/**
 * GoldFluid — WebGL2 GPU stable-fluids（Navier-Stokes）金墨模拟。
 *
 * 管线：平流（半拉格朗日）→ 涡度增强（curl/vorticity confinement）
 *      → 散度 → 压力 Jacobi 迭代 → 梯度减去 → 染料场显示。
 * 速度场 / 染料场均双缓冲 FBO（ping-pong），16F 半浮点纹理。
 * 画布以 0.5x 降采样渲染（默认），CSS 放大，保证 60fps。
 *
 * 配色只用 DESIGN_V7 token：底 #0B0B0B，金 #C0924E → #E8C98A（按速度/密度映射），
 * 高光极小面积 #F5E3BC。
 *
 * 生命周期：mountGoldFluid(canvas) → handle；destroy() 必须 loseContext。
 * prefers-reduced-motion：setReducedMotion(true) 冻结循环，仅渲染一帧静态金雾。
 */

export interface GoldFluidHandle {
  /** 注入一团金墨。x/y 为画布归一化坐标（0..1，原点左上，CSS 约定），dx/dy 为方向力度（uv 单位）。 */
  splat(x: number, y: number, dx: number, dy: number): void;
  /** reduced-motion：冻结模拟，仅保留一帧静态金雾；恢复 false 后继续。 */
  setReducedMotion(reduced: boolean): void;
  pause(): void;
  resume(): void;
  /** 释放全部 GPU 资源并 loseContext。 */
  destroy(): void;
}

export interface GoldFluidOptions {
  /** 染料/画布相对 CSS 尺寸的降采样比例，默认 0.5。 */
  scale?: number;
  /** 静置时自动注入缓慢涡流，默认 true。 */
  idle?: boolean;
  /** 监听 pointermove/touchmove 产生金墨，默认 true。 */
  pointer?: boolean;
}

/* ---------------------------------------------------------------- token 色 */
const INK = { r: 0x0B / 255, g: 0x0B / 255, b: 0x0B / 255 };       // #0B0B0B
const GOLD = { r: 0xC0 / 255, g: 0x92 / 255, b: 0x4E / 255 };      // #C0924E
const GOLD_BRIGHT = { r: 0xE8 / 255, g: 0xC9 / 255, b: 0x8A / 255 }; // #E8C98A
const GOLD_SHEEN = { r: 0xF5 / 255, g: 0xE3 / 255, b: 0xBC / 255 };  // #F5E3BC

const CONFIG = {
  SIM_RESOLUTION: 168,       // 速度/压力网格短边
  PRESSURE_ITERATIONS: 22,
  PRESSURE_DECAY: 0.8,
  CURL: 26,                  // 涡度增强强度（翻涌感）
  SPLAT_RADIUS: 0.18,
  SPLAT_FORCE: 5600,
  DENSITY_DISSIPATION: 0.972, // 每 1/60s 染料留存率（金墨悬停）
  VELOCITY_DISSIPATION: 0.992,
  MAX_DYE_SHORT_EDGE: 1024,   // 染料分辨率上限
};

/* ----------------------------------------------------------------- shaders */
const VERT = `#version 300 es
precision highp float;
layout(location = 0) in vec2 aPosition;
out vec2 vUv;
void main() {
  vUv = aPosition * 0.5 + 0.5;
  gl_Position = vec4(aPosition, 0.0, 1.0);
}`;

const SPLAT_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uTarget;
uniform float uAspect;
uniform vec3 uColor;
uniform vec2 uPoint;
uniform float uRadius;
void main() {
  vec2 p = vUv - uPoint;
  p.x *= uAspect;
  vec3 splat = exp(-dot(p, p) / uRadius) * uColor;
  vec3 base = texture(uTarget, vUv).xyz;
  fragColor = vec4(base + splat, 1.0);
}`;

const ADVECTION_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uVelocity;
uniform sampler2D uSource;
uniform vec2 uTexelSize;
uniform float uDt;
uniform float uDissipation;
void main() {
  vec2 coord = vUv - uDt * texture(uVelocity, vUv).xy * uTexelSize;
  vec4 result = texture(uSource, coord);
  fragColor = uDissipation * result;
}`;

const DIVERGENCE_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uVelocity;
uniform vec2 uTexelSize;
void main() {
  float L = texture(uVelocity, vUv - vec2(uTexelSize.x, 0.0)).x;
  float R = texture(uVelocity, vUv + vec2(uTexelSize.x, 0.0)).x;
  float B = texture(uVelocity, vUv - vec2(0.0, uTexelSize.y)).y;
  float T = texture(uVelocity, vUv + vec2(0.0, uTexelSize.y)).y;
  vec2 C = texture(uVelocity, vUv).xy;
  if (vUv.x - uTexelSize.x < 0.0) { L = -C.x; }
  if (vUv.x + uTexelSize.x > 1.0) { R = -C.x; }
  if (vUv.y - uTexelSize.y < 0.0) { B = -C.y; }
  if (vUv.y + uTexelSize.y > 1.0) { T = -C.y; }
  fragColor = vec4(0.5 * (R - L + T - B), 0.0, 0.0, 1.0);
}`;

const CURL_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uVelocity;
uniform vec2 uTexelSize;
void main() {
  float L = texture(uVelocity, vUv - vec2(uTexelSize.x, 0.0)).y;
  float R = texture(uVelocity, vUv + vec2(uTexelSize.x, 0.0)).y;
  float B = texture(uVelocity, vUv - vec2(0.0, uTexelSize.y)).x;
  float T = texture(uVelocity, vUv + vec2(0.0, uTexelSize.y)).x;
  fragColor = vec4(0.5 * (R - L - T + B), 0.0, 0.0, 1.0);
}`;

const VORTICITY_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uVelocity;
uniform sampler2D uCurl;
uniform vec2 uTexelSize;
uniform float uCurlStrength;
uniform float uDt;
void main() {
  float L = texture(uCurl, vUv - vec2(uTexelSize.x, 0.0)).x;
  float R = texture(uCurl, vUv + vec2(uTexelSize.x, 0.0)).x;
  float B = texture(uCurl, vUv - vec2(0.0, uTexelSize.y)).x;
  float T = texture(uCurl, vUv + vec2(0.0, uTexelSize.y)).x;
  float C = texture(uCurl, vUv).x;
  vec2 force = 0.5 * vec2(abs(T) - abs(B), abs(R) - abs(L));
  force /= length(force) + 0.0001;
  force *= uCurlStrength * C;
  force.y *= -1.0;
  vec2 velocity = texture(uVelocity, vUv).xy + force * uDt;
  velocity = clamp(velocity, vec2(-1000.0), vec2(1000.0));
  fragColor = vec4(velocity, 0.0, 1.0);
}`;

const PRESSURE_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uPressure;
uniform sampler2D uDivergence;
uniform vec2 uTexelSize;
void main() {
  float L = texture(uPressure, vUv - vec2(uTexelSize.x, 0.0)).x;
  float R = texture(uPressure, vUv + vec2(uTexelSize.x, 0.0)).x;
  float B = texture(uPressure, vUv - vec2(0.0, uTexelSize.y)).x;
  float T = texture(uPressure, vUv + vec2(0.0, uTexelSize.y)).x;
  float divergence = texture(uDivergence, vUv).x;
  fragColor = vec4((L + R + B + T - divergence) * 0.25, 0.0, 0.0, 1.0);
}`;

const GRADIENT_SUBTRACT_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uPressure;
uniform sampler2D uVelocity;
uniform vec2 uTexelSize;
void main() {
  float L = texture(uPressure, vUv - vec2(uTexelSize.x, 0.0)).x;
  float R = texture(uPressure, vUv + vec2(uTexelSize.x, 0.0)).x;
  float B = texture(uPressure, vUv - vec2(0.0, uTexelSize.y)).x;
  float T = texture(uPressure, vUv + vec2(0.0, uTexelSize.y)).x;
  vec2 velocity = texture(uVelocity, vUv).xy - vec2(R - L, T - B);
  fragColor = vec4(velocity, 0.0, 1.0);
}`;

const CLEAR_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uTexture;
uniform float uValue;
void main() {
  fragColor = uValue * texture(uTexture, vUv);
}`;

const DISPLAY_FRAG = `#version 300 es
precision highp float;
in vec2 vUv;
out vec4 fragColor;
uniform sampler2D uDye;
uniform sampler2D uVelocity;
uniform vec3 uInk;
uniform vec3 uGold;
uniform vec3 uGoldBright;
uniform vec3 uGoldSheen;
void main() {
  vec3 dye = texture(uDye, vUv).rgb;
  // 染料存的是 uGold * density，反解密度
  float density = dye.r / uGold.r;
  float speed = length(texture(uVelocity, vUv).xy);
  float speedGlow = clamp(speed * 0.0035, 0.0, 1.0);
  // 金阶梯：密度与速度把 #C0924E 推向 #E8C98A
  vec3 tint = mix(uGold, uGoldBright, clamp(density * 0.38 + speedGlow * 0.62, 0.0, 1.0));
  float d = 1.0 - exp(-density * 1.35);            // 柔和 tone-map，重叠处不过曝
  vec3 color = tint * d;
  // 极小面积金箔闪光：高速 + 高密叠层
  float sheen = clamp(density - 1.15, 0.0, 1.5) * speedGlow;
  color += uGoldSheen * sheen * 0.28;
  // 边缘 vignette 融入黑漆（功能遮罩，非装饰渐变）
  vec2 q = vUv - 0.5;
  float vig = smoothstep(0.95, 0.35, length(q * vec2(1.15, 1.35)));
  color *= mix(0.35, 1.0, vig);
  fragColor = vec4(uInk + color, 1.0);
}`;

/* ------------------------------------------------------------------ 小工具 */
interface FBO {
  texture: WebGLTexture;
  fbo: WebGLFramebuffer;
  width: number;
  height: number;
  texelSizeX: number;
  texelSizeY: number;
  attach(id: number): number;
}

interface DoubleFBO {
  width: number;
  height: number;
  texelSizeX: number;
  texelSizeY: number;
  read: FBO;
  write: FBO;
  swap(): void;
}

class Program {
  readonly program: WebGLProgram;
  private readonly uniforms = new Map<string, WebGLUniformLocation>();

  constructor(
    private readonly gl: WebGL2RenderingContext,
    vertexShader: WebGLShader,
    fragSource: string,
  ) {
    const frag = this.compile(gl.FRAGMENT_SHADER, fragSource);
    const program = gl.createProgram();
    if (!program) throw new Error('[GoldFluid] createProgram failed');
    gl.attachShader(program, vertexShader);
    gl.attachShader(program, frag);
    gl.linkProgram(program);
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
      throw new Error(`[GoldFluid] link failed: ${gl.getProgramInfoLog(program) ?? ''}`);
    }
    this.program = program;
    gl.deleteShader(frag);

    const count = gl.getProgramParameter(program, gl.ACTIVE_UNIFORMS) as number;
    for (let i = 0; i < count; i += 1) {
      const name = gl.getActiveUniform(program, i)?.name;
      if (!name) continue;
      const loc = gl.getUniformLocation(program, name);
      if (loc) this.uniforms.set(name, loc);
    }
  }

  private compile(type: number, source: string): WebGLShader {
    const gl = this.gl;
    const shader = gl.createShader(type);
    if (!shader) throw new Error('[GoldFluid] createShader failed');
    gl.shaderSource(shader, source);
    gl.compileShader(shader);
    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
      throw new Error(`[GoldFluid] compile failed: ${gl.getShaderInfoLog(shader) ?? ''}`);
    }
    return shader;
  }

  u(name: string): WebGLUniformLocation | null {
    return this.uniforms.get(name) ?? null;
  }

  bind(): void {
    this.gl.useProgram(this.program);
  }
}

/** 挂载入口：WebGL2 / 浮点渲染不可用（或 reduced-motion 由调用方处理）时返回 null。 */
export function mountGoldFluid(canvas: HTMLCanvasElement, options: GoldFluidOptions = {}): GoldFluidHandle | null {
  let gl: WebGL2RenderingContext | null = null;
  try {
    gl = canvas.getContext('webgl2', {
      alpha: false,
      depth: false,
      stencil: false,
      antialias: false,
      preserveDrawingBuffer: false,
      powerPreference: 'high-performance',
    });
    if (!gl) return null;
    if (!gl.getExtension('EXT_color_buffer_float')) return null;
    return new GoldFluidSim(gl, canvas, options);
  } catch (error) {
    console.warn('[Gilt Archive] GoldFluid unavailable; boot continues without fluid.', error);
    return null;
  }
}

class GoldFluidSim implements GoldFluidHandle {
  private raf = 0;
  private lastTime = 0;
  private running = false;
  private reduced = false;
  private destroyed = false;
  private resizeQueued = true;
  private lastPointerTime = -10_000;
  private pointerX = 0;
  private pointerY = 0;
  private hasPointer = false;
  private idleTime = 0;
  private readonly scale: number;
  private readonly idleEnabled: boolean;
  private readonly pointerEnabled: boolean;
  private rect: DOMRect | null = null;

  private vertexShader!: WebGLShader;
  private blitVao: WebGLVertexArrayObject | null = null;
  private blitBuffer: WebGLBuffer | null = null;
  private splatProgram!: Program;
  private advectionProgram!: Program;
  private divergenceProgram!: Program;
  private curlProgram!: Program;
  private vorticityProgram!: Program;
  private pressureProgram!: Program;
  private gradientProgram!: Program;
  private clearProgram!: Program;
  private displayProgram!: Program;

  private dye!: DoubleFBO;
  private velocity!: DoubleFBO;
  private divergence!: FBO;
  private curl!: FBO;
  private pressure!: DoubleFBO;

  private readonly onPointerMove = (event: PointerEvent): void => {
    if (this.reduced || this.destroyed || !this.running) return;
    if (!this.rect) this.rect = this.canvas.getBoundingClientRect();
    if (this.rect.width <= 0 || this.rect.height <= 0) return;
    const x = (event.clientX - this.rect.left) / this.rect.width;
    const y = 1 - (event.clientY - this.rect.top) / this.rect.height;
    if (x < -0.1 || x > 1.1 || y < -0.1 || y > 1.1) return;
    if (!this.hasPointer) {
      this.hasPointer = true;
      this.pointerX = x;
      this.pointerY = y;
    }
    const dx = (x - this.pointerX) * CONFIG.SPLAT_FORCE;
    const dy = (y - this.pointerY) * CONFIG.SPLAT_FORCE;
    this.pointerX = x;
    this.pointerY = y;
    this.lastPointerTime = performance.now();
    if (Math.abs(dx) + Math.abs(dy) > 0.01) this.splatInternal(x, y, dx, dy, 1);
  };

  private readonly onTouchMove = (event: TouchEvent): void => {
    const touch = event.touches[0];
    if (!touch) return;
    this.onPointerMove({ clientX: touch.clientX, clientY: touch.clientY } as PointerEvent);
  };

  private readonly onResize = (): void => {
    this.resizeQueued = true;
    this.rect = null;
  };

  constructor(
    private readonly gl: WebGL2RenderingContext,
    private readonly canvas: HTMLCanvasElement,
    options: GoldFluidOptions,
  ) {
    this.scale = options.scale ?? 0.5;
    this.idleEnabled = options.idle ?? true;
    this.pointerEnabled = options.pointer ?? true;
    this.initGL();
    if (this.pointerEnabled && 'PointerEvent' in window) {
      window.addEventListener('pointermove', this.onPointerMove, { passive: true });
    } else if (this.pointerEnabled) {
      window.addEventListener('touchmove', this.onTouchMove, { passive: true });
    }
    window.addEventListener('resize', this.onResize, { passive: true });
    this.resume();
    this.seedOpening();
  }

  /* ------------------------------------------------------------ GL 初始化 */
  private initGL(): void {
    const gl = this.gl;
    gl.disable(gl.BLEND);
    gl.disable(gl.DEPTH_TEST);

    this.vertexShader = this.compileShader(gl.VERTEX_SHADER, VERT);
    this.blitVao = gl.createVertexArray();
    gl.bindVertexArray(this.blitVao);
    this.blitBuffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, this.blitBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1, -1, 3, -1, -1, 3]), gl.STATIC_DRAW);
    gl.enableVertexAttribArray(0);
    gl.vertexAttribPointer(0, 2, gl.FLOAT, false, 0, 0);

    this.splatProgram = new Program(gl, this.vertexShader, SPLAT_FRAG);
    this.advectionProgram = new Program(gl, this.vertexShader, ADVECTION_FRAG);
    this.divergenceProgram = new Program(gl, this.vertexShader, DIVERGENCE_FRAG);
    this.curlProgram = new Program(gl, this.vertexShader, CURL_FRAG);
    this.vorticityProgram = new Program(gl, this.vertexShader, VORTICITY_FRAG);
    this.pressureProgram = new Program(gl, this.vertexShader, PRESSURE_FRAG);
    this.gradientProgram = new Program(gl, this.vertexShader, GRADIENT_SUBTRACT_FRAG);
    this.clearProgram = new Program(gl, this.vertexShader, CLEAR_FRAG);
    this.displayProgram = new Program(gl, this.vertexShader, DISPLAY_FRAG);

    gl.bindVertexArray(null);
    this.initFramebuffers();
  }

  private compileShader(type: number, source: string): WebGLShader {
    const gl = this.gl;
    const shader = gl.createShader(type);
    if (!shader) throw new Error('[GoldFluid] createShader failed');
    gl.shaderSource(shader, source);
    gl.compileShader(shader);
    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
      throw new Error(`[GoldFluid] vertex compile failed: ${gl.getShaderInfoLog(shader) ?? ''}`);
    }
    return shader;
  }

  private createFBO(width: number, height: number, internalFormat: number, format: number, filter: number): FBO {
    const gl = this.gl;
    gl.activeTexture(gl.TEXTURE0);
    const texture = gl.createTexture();
    if (!texture) throw new Error('[GoldFluid] createTexture failed');
    gl.bindTexture(gl.TEXTURE_2D, texture);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, filter);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, filter);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    gl.texImage2D(gl.TEXTURE_2D, 0, internalFormat, width, height, 0, format, gl.HALF_FLOAT, null);

    const fbo = gl.createFramebuffer();
    if (!fbo) throw new Error('[GoldFluid] createFramebuffer failed');
    gl.bindFramebuffer(gl.FRAMEBUFFER, fbo);
    gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, texture, 0);
    gl.viewport(0, 0, width, height);
    gl.clearColor(0, 0, 0, 1);
    gl.clear(gl.COLOR_BUFFER_BIT);

    return {
      texture,
      fbo,
      width,
      height,
      texelSizeX: 1 / width,
      texelSizeY: 1 / height,
      attach(id: number): number {
        gl.activeTexture(gl.TEXTURE0 + id);
        gl.bindTexture(gl.TEXTURE_2D, texture);
        return id;
      },
    };
  }

  private createDoubleFBO(width: number, height: number, internalFormat: number, format: number, filter: number): DoubleFBO {
    let fbo1 = this.createFBO(width, height, internalFormat, format, filter);
    let fbo2 = this.createFBO(width, height, internalFormat, format, filter);
    return {
      width,
      height,
      texelSizeX: fbo1.texelSizeX,
      texelSizeY: fbo1.texelSizeY,
      get read(): FBO { return fbo1; },
      get write(): FBO { return fbo2; },
      swap(): void {
        const temp = fbo1;
        fbo1 = fbo2;
        fbo2 = temp;
      },
    };
  }

  private getResolution(base: number): { width: number; height: number } {
    const gl = this.gl;
    let aspect = gl.drawingBufferWidth / Math.max(1, gl.drawingBufferHeight);
    if (aspect < 1) aspect = 1 / aspect;
    const min = Math.round(base);
    const max = Math.round(base * aspect);
    return gl.drawingBufferWidth > gl.drawingBufferHeight
      ? { width: max, height: min }
      : { width: min, height: max };
  }

  private initFramebuffers(): void {
    const gl = this.gl;
    // 0.5x 降采样：drawing buffer = CSS 尺寸 * scale，CSS 放大铺满
    const cssW = Math.max(2, this.canvas.clientWidth || window.innerWidth);
    const cssH = Math.max(2, this.canvas.clientHeight || window.innerHeight);
    const w = Math.round(cssW * this.scale);
    const h = Math.round(cssH * this.scale);
    const shortEdge = Math.min(w, h);
    if (shortEdge > CONFIG.MAX_DYE_SHORT_EDGE) {
      const k = CONFIG.MAX_DYE_SHORT_EDGE / shortEdge;
      this.canvas.width = Math.round(w * k);
      this.canvas.height = Math.round(h * k);
    } else {
      this.canvas.width = w;
      this.canvas.height = h;
    }

    this.deleteFramebuffers();
    const dyeRes = { width: gl.drawingBufferWidth, height: gl.drawingBufferHeight };
    const simRes = this.getResolution(CONFIG.SIM_RESOLUTION);

    this.dye = this.createDoubleFBO(dyeRes.width, dyeRes.height, gl.RGBA16F, gl.RGBA, gl.LINEAR);
    this.velocity = this.createDoubleFBO(simRes.width, simRes.height, gl.RG16F, gl.RG, gl.LINEAR);
    this.divergence = this.createFBO(simRes.width, simRes.height, gl.R16F, gl.RED, gl.NEAREST);
    this.curl = this.createFBO(simRes.width, simRes.height, gl.R16F, gl.RED, gl.NEAREST);
    this.pressure = this.createDoubleFBO(simRes.width, simRes.height, gl.R16F, gl.RED, gl.NEAREST);
  }

  private deleteFramebuffers(): void {
    const gl = this.gl;
    const killFBO = (f: FBO | undefined): void => {
      if (!f) return;
      gl.deleteTexture(f.texture);
      gl.deleteFramebuffer(f.fbo);
    };
    if (this.dye) { killFBO(this.dye.read); killFBO(this.dye.write); }
    if (this.velocity) { killFBO(this.velocity.read); killFBO(this.velocity.write); }
    if (this.pressure) { killFBO(this.pressure.read); killFBO(this.pressure.write); }
    killFBO(this.divergence);
    killFBO(this.curl);
  }

  private blit(target: FBO | null): void {
    const gl = this.gl;
    if (target) {
      gl.viewport(0, 0, target.width, target.height);
      gl.bindFramebuffer(gl.FRAMEBUFFER, target.fbo);
    } else {
      gl.viewport(0, 0, gl.drawingBufferWidth, gl.drawingBufferHeight);
      gl.bindFramebuffer(gl.FRAMEBUFFER, null);
    }
    gl.bindVertexArray(this.blitVao);
    gl.drawArrays(gl.TRIANGLES, 0, 3);
    gl.bindVertexArray(null);
  }

  /* ------------------------------------------------------------ 公共 API */
  splat(x: number, y: number, dx: number, dy: number): void {
    if (this.destroyed || this.reduced) return;
    // 公共契约：原点左上（CSS），内部转为 GL 的左下原点
    this.splatInternal(x, 1 - y, dx, -dy, 1.2);
  }

  setReducedMotion(reduced: boolean): void {
    if (this.destroyed || this.reduced === reduced) return;
    this.reduced = reduced;
    if (reduced) {
      this.stopLoop();
      this.renderStaticVeil();
    } else {
      this.resume();
    }
  }

  pause(): void {
    this.stopLoop();
  }

  resume(): void {
    if (this.destroyed || this.reduced || this.running) return;
    this.running = true;
    this.lastTime = performance.now();
    this.raf = requestAnimationFrame(this.frame);
  }

  destroy(): void {
    if (this.destroyed) return;
    this.destroyed = true;
    this.stopLoop();
    window.removeEventListener('pointermove', this.onPointerMove);
    window.removeEventListener('touchmove', this.onTouchMove);
    window.removeEventListener('resize', this.onResize);
    const gl = this.gl;
    this.deleteFramebuffers();
    gl.deleteBuffer(this.blitBuffer);
    gl.deleteVertexArray(this.blitVao);
    gl.deleteShader(this.vertexShader);
    for (const p of [
      this.splatProgram, this.advectionProgram, this.divergenceProgram,
      this.curlProgram, this.vorticityProgram, this.pressureProgram,
      this.gradientProgram, this.clearProgram, this.displayProgram,
    ]) {
      gl.deleteProgram(p.program);
    }
    this.canvas.width = 1;
    this.canvas.height = 1;
    gl.getExtension('WEBGL_lose_context')?.loseContext();
  }

  /* ------------------------------------------------------------ 内部驱动 */
  private stopLoop(): void {
    this.running = false;
    if (this.raf) cancelAnimationFrame(this.raf);
    this.raf = 0;
  }

  private readonly frame = (now: number): void => {
    if (!this.running || this.destroyed) return;
    this.raf = requestAnimationFrame(this.frame);
    if (document.hidden) {
      this.lastTime = now;
      return;
    }
    if (this.resizeQueued) {
      this.resizeQueued = false;
      this.initFramebuffers();
      this.seedOpening();
    }
    const dt = Math.min(Math.max((now - this.lastTime) / 1000, 0), 1 / 60);
    this.lastTime = now;
    this.updateIdle(dt, now);
    this.step(dt);
    this.render();
  };

  /** 静置时注入缓慢涡流：两条利萨如轨迹的金色移动子。 */
  private updateIdle(dt: number, now: number): void {
    if (!this.idleEnabled) return;
    if (now - this.lastPointerTime < 1200) return;
    this.idleTime += dt;
    const t = this.idleTime;
    // 双移动子相位错开，速度沿轨迹切向（前后帧公式严格一致）
    const movers = [
      { ax: 0.33, ay: 0.27, fx: 0.55, fy: 0.83, phx: 0, phy: 1.7 },
      { ax: 0.38, ay: 0.31, fx: 0.34, fy: 0.62, phx: 3.1, phy: 0.4 },
    ];
    for (const m of movers) {
      const px = 0.5 + m.ax * Math.sin(t * m.fx + m.phx);
      const py = 0.5 + m.ay * Math.sin(t * m.fy + m.phy);
      const nx = 0.5 + m.ax * Math.sin((t + dt) * m.fx + m.phx);
      const ny = 0.5 + m.ay * Math.sin((t + dt) * m.fy + m.phy);
      const dx = (nx - px) * CONFIG.SPLAT_FORCE * 0.55;
      const dy = (ny - py) * CONFIG.SPLAT_FORCE * 0.55;
      this.splatInternal(px, py, dx, dy, 0.42);
    }
  }

  private splatInternal(x: number, y: number, dx: number, dy: number, intensity: number): void {
    const gl = this.gl;
    const radius = this.correctRadius(CONFIG.SPLAT_RADIUS / 100);
    const aspect = this.canvas.width / Math.max(1, this.canvas.height);

    this.splatProgram.bind();
    gl.uniform1f(this.splatProgram.u('uAspect'), aspect);
    gl.uniform2f(this.splatProgram.u('uPoint'), x, y);
    gl.uniform1f(this.splatProgram.u('uRadius'), radius);

    gl.uniform1i(this.splatProgram.u('uTarget'), this.velocity.read.attach(0));
    gl.uniform3f(this.splatProgram.u('uColor'), dx, dy, 0);
    this.blit(this.velocity.write);
    this.velocity.swap();

    const dyeBoost = 0.32 * intensity;
    gl.uniform1i(this.splatProgram.u('uTarget'), this.dye.read.attach(0));
    gl.uniform3f(this.splatProgram.u('uColor'), GOLD.r * dyeBoost, GOLD.g * dyeBoost, GOLD.b * dyeBoost);
    this.blit(this.dye.write);
    this.dye.swap();
  }

  private correctRadius(radius: number): number {
    const aspect = this.canvas.width / Math.max(1, this.canvas.height);
    return aspect > 1 ? radius * aspect : radius;
  }

  private seedOpening(): void {
    // 开场金墨：数团错位的涡旋，让第一帧就有翻涌感
    for (let i = 0; i < 6; i += 1) {
      const angle = (i / 6) * Math.PI * 2;
      const x = 0.5 + 0.28 * Math.cos(angle);
      const y = 0.5 + 0.24 * Math.sin(angle);
      const dx = -Math.sin(angle) * CONFIG.SPLAT_FORCE * 0.16;
      const dy = Math.cos(angle) * CONFIG.SPLAT_FORCE * 0.16;
      this.splatInternal(x, y, dx, dy, 0.9);
    }
  }

  /** reduced-motion 静态降级：一团低强度金雾，渲染一次即冻结。 */
  private renderStaticVeil(): void {
    if (this.resizeQueued) {
      this.resizeQueued = false;
      this.initFramebuffers();
    }
    const marks: Array<[number, number, number]> = [
      [0.36, 0.44, 0.5], [0.62, 0.55, 0.4], [0.5, 0.38, 0.32], [0.44, 0.62, 0.28],
    ];
    for (const [x, y, s] of marks) this.splatInternal(x, y, 0, 0, s);
    this.step(1 / 60);
    this.render();
  }

  private step(dt: number): void {
    const gl = this.gl;
    gl.disable(gl.BLEND);

    this.curlProgram.bind();
    gl.uniform2f(this.curlProgram.u('uTexelSize'), this.velocity.texelSizeX, this.velocity.texelSizeY);
    gl.uniform1i(this.curlProgram.u('uVelocity'), this.velocity.read.attach(0));
    this.blit(this.curl);

    this.vorticityProgram.bind();
    gl.uniform2f(this.vorticityProgram.u('uTexelSize'), this.velocity.texelSizeX, this.velocity.texelSizeY);
    gl.uniform1i(this.vorticityProgram.u('uVelocity'), this.velocity.read.attach(0));
    gl.uniform1i(this.vorticityProgram.u('uCurl'), this.curl.attach(1));
    gl.uniform1f(this.vorticityProgram.u('uCurlStrength'), CONFIG.CURL);
    gl.uniform1f(this.vorticityProgram.u('uDt'), dt);
    this.blit(this.velocity.write);
    this.velocity.swap();

    this.divergenceProgram.bind();
    gl.uniform2f(this.divergenceProgram.u('uTexelSize'), this.velocity.texelSizeX, this.velocity.texelSizeY);
    gl.uniform1i(this.divergenceProgram.u('uVelocity'), this.velocity.read.attach(0));
    this.blit(this.divergence);

    this.clearProgram.bind();
    gl.uniform1i(this.clearProgram.u('uTexture'), this.pressure.read.attach(0));
    gl.uniform1f(this.clearProgram.u('uValue'), CONFIG.PRESSURE_DECAY);
    this.blit(this.pressure.write);
    this.pressure.swap();

    this.pressureProgram.bind();
    gl.uniform2f(this.pressureProgram.u('uTexelSize'), this.velocity.texelSizeX, this.velocity.texelSizeY);
    gl.uniform1i(this.pressureProgram.u('uDivergence'), this.divergence.attach(0));
    for (let i = 0; i < CONFIG.PRESSURE_ITERATIONS; i += 1) {
      gl.uniform1i(this.pressureProgram.u('uPressure'), this.pressure.read.attach(1));
      this.blit(this.pressure.write);
      this.pressure.swap();
    }

    this.gradientProgram.bind();
    gl.uniform2f(this.gradientProgram.u('uTexelSize'), this.velocity.texelSizeX, this.velocity.texelSizeY);
    gl.uniform1i(this.gradientProgram.u('uPressure'), this.pressure.read.attach(0));
    gl.uniform1i(this.gradientProgram.u('uVelocity'), this.velocity.read.attach(1));
    this.blit(this.velocity.write);
    this.velocity.swap();

    this.advectionProgram.bind();
    gl.uniform2f(this.advectionProgram.u('uTexelSize'), this.velocity.texelSizeX, this.velocity.texelSizeY);
    gl.uniform1f(this.advectionProgram.u('uDt'), dt);
    const velId = this.velocity.read.attach(0);
    gl.uniform1i(this.advectionProgram.u('uVelocity'), velId);
    gl.uniform1i(this.advectionProgram.u('uSource'), velId);
    gl.uniform1f(this.advectionProgram.u('uDissipation'), Math.pow(CONFIG.VELOCITY_DISSIPATION, dt * 60));
    this.blit(this.velocity.write);
    this.velocity.swap();

    gl.uniform1i(this.advectionProgram.u('uVelocity'), this.velocity.read.attach(0));
    gl.uniform1i(this.advectionProgram.u('uSource'), this.dye.read.attach(1));
    gl.uniform1f(this.advectionProgram.u('uDissipation'), Math.pow(CONFIG.DENSITY_DISSIPATION, dt * 60));
    this.blit(this.dye.write);
    this.dye.swap();
  }

  private render(): void {
    const gl = this.gl;
    this.displayProgram.bind();
    gl.uniform1i(this.displayProgram.u('uDye'), this.dye.read.attach(0));
    gl.uniform1i(this.displayProgram.u('uVelocity'), this.velocity.read.attach(1));
    gl.uniform3f(this.displayProgram.u('uInk'), INK.r, INK.g, INK.b);
    gl.uniform3f(this.displayProgram.u('uGold'), GOLD.r, GOLD.g, GOLD.b);
    gl.uniform3f(this.displayProgram.u('uGoldBright'), GOLD_BRIGHT.r, GOLD_BRIGHT.g, GOLD_BRIGHT.b);
    gl.uniform3f(this.displayProgram.u('uGoldSheen'), GOLD_SHEEN.r, GOLD_SHEEN.g, GOLD_SHEEN.b);
    this.blit(null);
  }
}
