import * as THREE from 'three';
import { RoomEnvironment } from 'three/examples/jsm/environments/RoomEnvironment.js';

/**
 * 「金缮 · GILT ARCHIVE」v7.1 — 可旋转 3D 金器（奖杯 × 印章混合器型）
 *
 * 程序化建模（零外部模型/贴图）：
 * - 双层方印底座：圆角矩形 ExtrudeGeometry（高细分 bevel），致敬篆刻印章。
 * - 收腰杯身：CatmullRom 平滑剖面 → LatheGeometry 240 径向细分旋成，
 *   剖面 151 点（含外翻杯口与内壁回程），单体约 7.2 万三角面，轮廓无棱。
 * - 翼形耳柄 ×2：Bezier 翼形剖面 ExtrudeGeometry，左右镜像，微外张。
 * - 杯口金箍：TorusGeometry 细环，与杯身同部件组。
 *   全器合计约 9 万+ 三角面（≥5 万目标），法线全平滑。
 *
 * PBR：MeshStandardMaterial metalness=1.0，roughness 由程序化 canvas
 * roughnessMap 驱动（0.18–0.32 细微起伏 + 拉丝方向性 + 细划痕），
 * PMREM + RoomEnvironment 环境反射，ACES 色调映射。
 *
 * 金缮裂纹：onBeforeCompile 注入自写 GLSL —— uv 域 Voronoi(F2−F1) 边缘
 * 取裂纹，值噪声区域遮罩让裂纹只成簇出现；亮金（--gold-sheen #F5E3BC）
 * 自发光呼吸脉动（周期 2.6s，相位沿裂纹走向流动），uGlow 随进度增强。
 *
 * 交互：pointer 拖拽旋转（惯性指数阻尼），静置 2s 恢复 0.05rad/s 自转；
 * 触摸手势不捕获（页面翻页状态机优先），滚轮完全不拦截。
 * setProgress(0..1)：部件沿结构外法线 explode 0–12% 器高（解体/聚合）。
 *
 * 性能：pixelRatio ≤1.75、小容器自适应降细分、IntersectionObserver 离屏暂停、
 * reduced-motion 冻结自转/惯性/脉动并按需渲染；destroy 释放全部 GPU 资源
 * 并 forceContextLoss。
 *
 * v8.0 电影化升级：
 * - pushThrough(duration?)：相机沿当前视轴推近，直至金器在垂直/水平两个方向
 *   均溢出画面（充满），时长钳制 1.2–1.6s，缓动 cubic-bezier(.2,.6,0,1)，
 *   供幕间转场调用；resetCamera(duration?) 缓回基准博物馆构图。两者均复用
 *   既有 tick 主循环，reduced-motion 下瞬时落位（简单切换）。
 * - 材质新增一层轻微 fresnel 暖金边缘光（onBeforeCompile 注入，随既有
 *   金缮 GLSL 一同编译，不引入后处理管线），掠射角勾出器型轮廓。
 */

export interface ArtifactController {
  setProgress: (progress: number) => void;
  setReducedMotion: (reduced: boolean) => void;
  /**
   * v8.0 转场推镜：相机沿当前视轴向金器推近，直至器型在垂直/水平两个方向
   * 均溢出画面（充满全屏，可作遮挡式转场的落点）。时长钳制 1.2–1.6s
   * （默认 1.4s），缓动 cubic-bezier(.2,.6,0,1)；reduced-motion 下瞬时落位。
   * 动画复用既有 tick 主循环；离屏暂停期间不推进，回屏后继续。
   */
  pushThrough: (duration?: number) => void;
  /**
   * v8.0 推镜逆过程：以同一电影缓动回到基准博物馆构图（pushThrough 前状态）。
   * 时长钳制 0.9–2.0s（默认 1.3s）。返回首幕时调用。
   */
  resetCamera: (duration?: number) => void;
  destroy: () => void;
}

