/* ------------------------------------------------------------ 金缮 GLSL */
const kintsugiPars = /* glsl */ `
  uniform float uArtifactTime;
  uniform float uArtifactPulse;
  uniform float uArtifactGlow;
  uniform vec2 uCrackScale;
  uniform vec3 uCrackColor;
  uniform float uRimIntensity;
  uniform vec3 uRimColor;

  vec2 artifactHash22(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453123);
  }

  float artifactNoise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    vec2 u = f * f * (3.0 - 2.0 * f);
    float a = artifactHash22(i).x;
    float b = artifactHash22(i + vec2(1.0, 0.0)).x;
    float c = artifactHash22(i + vec2(0.0, 1.0)).x;
    float d = artifactHash22(i + vec2(1.0, 1.0)).x;
    return mix(mix(a, b, u.x), mix(c, d, u.x), u.y);
  }

  /* Voronoi F2−F1 边缘距离 → 细裂纹；幂次收束出锔金细线。 */
  float artifactCrack(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float f1 = 8.0;
    float f2 = 8.0;
    for (int y = -1; y <= 1; y++)
    for (int x = -1; x <= 1; x++) {
      vec2 g = vec2(float(x), float(y));
      vec2 o = artifactHash22(i + g);
      vec2 r = g + o - f;
      float d = dot(r, r);
      if (d < f1) { f2 = f1; f1 = d; }
      else if (d < f2) { f2 = d; }
    }
    float edge = sqrt(f2) - sqrt(f1);
    float vein = 1.0 - smoothstep(0.015, 0.06, edge);
    return pow(vein, 1.35);
  }
`;

const kintsugiApply = /* glsl */ `
  {
    // r185 起 uv varying 按贴图独立命名；金材质恒挂 roughnessMap → vRoughnessMapUv 必存在。
    vec2 artifactUv = vRoughnessMapUv;
    vec2 crackUv = artifactUv * uCrackScale;
    float vein = artifactCrack(crackUv);
    float region = smoothstep(0.44, 0.72, artifactNoise(artifactUv * 3.1 + vec2(17.31, 7.77)));
    float seam = vein * region;
    /* 呼吸脉动：周期 2π/2.417 ≈ 2.6s，相位沿裂纹走向流动。 */
    float breath = mix(
      1.0,
      0.56 + 0.44 * sin(uArtifactTime * 2.417 + crackUv.x * 1.31 + crackUv.y * 1.97),
      uArtifactPulse
    );
    totalEmissiveRadiance += uCrackColor * seam * breath * uArtifactGlow;
    diffuseColor.rgb *= 1.0 - seam * 0.16;
  }
  {
    // v8.0 暖金 fresnel 边缘光（轻微）：掠射角提亮勾出器型轮廓，无后处理管线。
    // normal 已由 normal_fragment_begin 就绪；vViewPosition 指向相机。
    float artifactFresnel = pow(1.0 - saturate(dot(normalize(normal), normalize(vViewPosition))), 3.0);
    totalEmissiveRadiance += uRimColor * artifactFresnel * uRimIntensity;
  }
`;

type SharedUniforms = {
  uArtifactTime: { value: number };
  uArtifactPulse: { value: number };
  uArtifactGlow: { value: number };
  uRimIntensity: { value: number };
};

type ExplodePart = {
  node: THREE.Object3D;
  base: THREE.Vector3;
  direction: THREE.Vector3;
  factor: number;
};

/* ------------------------------------------------------------ 程序化工具 */

/** 确定性伪随机（roughnessMap 每帧/每次加载一致）。 */
function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/**
 * 程序化 roughnessMap：三倍频值噪声（纵向拉丝）+ 细划痕，
 * 灰度映射 roughness 0.18–0.32（map 与 roughness=1.0 相乘生效）。
 */
function createRoughnessTexture(): THREE.CanvasTexture {
  const size = 256;
  const rng = mulberry32(0xc0924e);
  const octaves = [8, 16, 32].map((cells) => {
    const grid = new Float32Array((cells + 1) * (cells + 1));
    for (let i = 0; i < grid.length; i += 1) grid[i] = rng();
    return { cells, grid };
  });
  const sample = (octave: { cells: number; grid: Float32Array }, x: number, y: number): number => {
    const { cells, grid } = octave;
    const xi = Math.min(cells - 1, Math.floor(x));
    const yi = Math.min(cells - 1, Math.floor(y));
    const xf = x - Math.floor(x);
    const yf = y - Math.floor(y);
    const sx = xf * xf * (3 - 2 * xf);
    const sy = yf * yf * (3 - 2 * yf);
    const at = (ix: number, iy: number): number => grid[iy * (cells + 1) + ix];
    const top = at(xi, yi) + (at(xi + 1, yi) - at(xi, yi)) * sx;
    const bottom = at(xi, yi + 1) + (at(xi + 1, yi + 1) - at(xi, yi + 1)) * sx;
    return top + (bottom - top) * sy;
  };

  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const context = canvas.getContext('2d');
  if (!context) throw new Error('2d context unavailable');
  const image = context.createImageData(size, size);
  for (let y = 0; y < size; y += 1) {
    for (let x = 0; x < size; x += 1) {
      const nx = x / size;
      const ny = y / size;
      // 纵向拉伸采样 → 拉丝金属的方向性微起伏。
      const n =
        0.5 * sample(octaves[0], nx * 8, ny * 24) +
        0.3 * sample(octaves[1], nx * 16, ny * 48) +
        0.2 * sample(octaves[2], nx * 32, ny * 96);
      const v = THREE.MathUtils.clamp((n - 0.26) * 1.9, 0, 1);
      const roughness = 0.18 + v * 0.14; // 0.18 – 0.32
      const byte = Math.round(roughness * 255);
      const index = (y * size + x) * 4;
      image.data[index] = byte;
      image.data[index + 1] = byte;
      image.data[index + 2] = byte;
      image.data[index + 3] = 255;
    }
  }
  context.putImageData(image, 0, 0);

  // 稀疏细划痕（近垂直 ±7°），博物馆器物的手工痕迹。
  context.lineWidth = 1;
  for (let i = 0; i < 42; i += 1) {
    const x = rng() * size;
    const y = rng() * size;
    const length = 24 + rng() * 88;
    const angle = Math.PI / 2 + (rng() - 0.5) * 0.24;
    const light = rng() > 0.5;
    context.strokeStyle = light ? 'rgba(255,255,255,0.10)' : 'rgba(0,0,0,0.12)';
    context.beginPath();
    context.moveTo(x, y);
    context.lineTo(x + Math.cos(angle) * length, y + Math.sin(angle) * length);
    context.stroke();
  }

  const texture = new THREE.CanvasTexture(canvas);
  texture.wrapS = THREE.RepeatWrapping;
  texture.wrapT = THREE.RepeatWrapping;
  return texture;
}

/** 底座暖金反光池（黑漆地面上的博物馆射灯光晕）。 */
function createFloorGlowTexture(): THREE.CanvasTexture {
  const size = 256;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const context = canvas.getContext('2d');
  if (!context) throw new Error('2d context unavailable');
  const gradient = context.createRadialGradient(size / 2, size / 2, 0, size / 2, size / 2, size / 2);
  gradient.addColorStop(0, 'rgba(232, 201, 138, 0.34)');
  gradient.addColorStop(0.42, 'rgba(192, 146, 78, 0.14)');
  gradient.addColorStop(1, 'rgba(192, 146, 78, 0)');
  context.fillStyle = gradient;
  context.fillRect(0, 0, size, size);
  return new THREE.CanvasTexture(canvas);
}

/** 圆角矩形剖面（印章底座用）。 */
function roundedRectShape(half: number, radius: number): THREE.Shape {
  const shape = new THREE.Shape();
  shape.moveTo(-half + radius, -half);
  shape.lineTo(half - radius, -half);
  shape.absarc(half - radius, -half + radius, radius, -Math.PI / 2, 0, false);
  shape.lineTo(half, half - radius);
  shape.absarc(half - radius, half - radius, radius, 0, Math.PI / 2, false);
  shape.lineTo(-half + radius, half);
  shape.absarc(-half + radius, half - radius, radius, Math.PI / 2, Math.PI, false);
  shape.lineTo(-half, -half + radius);
  shape.absarc(-half + radius, -half + radius, radius, Math.PI, Math.PI * 1.5, false);
  return shape;
}

/** 旋成体杯身：CatmullRom 平滑剖面 + 高径向细分 Lathe。 */
function buildCupGeometry(radialSegments: number): THREE.LatheGeometry {
  const control = CUP_PROFILE.map(([r, y]) => new THREE.Vector3(r, y, 0));
  const curve = new THREE.CatmullRomCurve3(control, false, 'catmullrom', 0.5);
  const points = curve
    .getPoints(150)
    .map((p) => new THREE.Vector2(Math.max(0.0001, p.x), p.y));
  return new THREE.LatheGeometry(points, radialSegments);
}

/** 翼形耳柄：Bezier 翼形剖面拉伸 + 高细分 bevel，厚度居中。 */
function buildHandleGeometry(): THREE.ExtrudeGeometry {
  const shape = new THREE.Shape();
  shape.moveTo(0, 0);
  shape.bezierCurveTo(0.3, 0.04, 0.66, 0.2, 0.86, 0.52);
  shape.bezierCurveTo(1.02, 0.8, 1.04, 1.08, 0.9, 1.3);
  shape.bezierCurveTo(0.86, 1.36, 0.78, 1.38, 0.72, 1.32);
  shape.bezierCurveTo(0.62, 1.08, 0.44, 0.92, 0.22, 0.8);
  shape.bezierCurveTo(0.08, 0.72, 0.01, 0.64, 0, 0.52);
  shape.lineTo(0, 0);
  const geometry = new THREE.ExtrudeGeometry(shape, {
    depth: 0.13,
    bevelEnabled: true,
    bevelThickness: 0.045,
    bevelSize: 0.045,
    bevelSegments: 8,
    curveSegments: 44,
    steps: 1,
  });
  geometry.translate(0, 0, -0.065); // 厚度居中
  return geometry;
}

/** 方印座（双层共用构造）：挤出后转为 Y 轴向上、底面落在 y=0。 */
function buildSealTierGeometry(half: number, radius: number, depth: number, bevel: number): THREE.ExtrudeGeometry {
  const geometry = new THREE.ExtrudeGeometry(roundedRectShape(half, radius), {
    depth,
    bevelEnabled: true,
    bevelThickness: bevel,
    bevelSize: bevel * 0.85,
    bevelSegments: 8,
    curveSegments: 32,
    steps: 1,
  });
  geometry.rotateX(-Math.PI / 2);
  geometry.translate(0, bevel, 0);
  return geometry;
}

