/**
 * cine-core / FocusRig — v8.0 焦点系统
 * -----------------------------------
 * 每幕定义一个焦平面：主体（当前 .node-visual 展签）清晰；
 * 背景（.scene__giant 巨字）轻模糊 blur 1.5–3px + 亮度降 8–15% +
 * 降对比（焦外区域降对比而非单纯高糊）；前景金缮裂缝略柔，
 * 形成「前柔 / 中清 / 背虚」的三层深度。
 *
 * 节点切换做 rack focus（300–600ms，cubic-bezier(.2,.6,0,1)）：
 * 旧主体失焦后退（blur↑ + scale .986），新主体由虚入清。
 * 动画用 WAAPI 落在 .node-plate-mask 上——该元素的 filter/transform
 * 不被 GSAP 接管（motion.ts 只动 figure 本体与 .node-art），零冲突。
 *
 * 背景失焦由 rig 上的 CSS 变量驱动（--cine-bg-blur 等），
 * style-cine.css 里的 filter transition 负责缓动；模糊全部短暂受控：
 * 移动端焦外模糊减半、rack 只留亮度/位移；reduced-motion 一律静止清晰。
 */

import type { CineEnvironment, CineSceneRig } from './CameraDirector';

interface FocalSpec {
  /** .scene__giant 失焦模糊 px（1.5–3）。 */
  bgBlur: number;
  /** 巨字亮度（.85–.92 → 降 8–15%）。 */
  bgDim: number;
  /** 巨字对比度：焦外降对比。 */
  bgContrast: number;
  /** 前景金缮柔化 px。 */
  fgBlur: number;
  /** 前景亮度。 */
  fgDim: number;
  /** rack focus 时长 ms（300–600，逐幕差异化）。 */
  rackMs: number;
  /** 焦平面叙事注释。 */
  note: string;
}

/* 焦平面逐幕定义：数据幕焦外最浅（理性、信息密度高），
   国家队服 / 终幕焦外最深（仪式感、收束）。 */
const FOCAL_SPECS: FocalSpec[] = [
  { bgBlur: 2.4, bgDim: 0.88, bgContrast: 0.93, fgBlur: 2.0, fgDim: 0.92, rackMs: 560, note: '序章深焦：巨字退成年代底色，展签是唯一清晰平面' },
  { bgBlur: 2.0, bgDim: 0.90, bgContrast: 0.94, fgBlur: 1.6, fgDim: 0.94, rackMs: 480, note: '制度卷宗：中速 rack，像翻阅卷宗时目光换行' },
  { bgBlur: 2.2, bgDim: 0.88, bgContrast: 0.93, fgBlur: 1.8, fgDim: 0.93, rackMs: 520, note: '冠军序列：rack 略慢，给卫冕与登顶留敬意' },
  { bgBlur: 1.8, bgDim: 0.90, bgContrast: 0.94, fgBlur: 1.5, fgDim: 0.94, rackMs: 440, note: '公共记忆：焦外放浅，记忆的颗粒感被保留' },
  { bgBlur: 2.6, bgDim: 0.86, bgContrast: 0.92, fgBlur: 2.2, fgDim: 0.92, rackMs: 600, note: '国家符号：全片最深焦外 + 最慢 rack，仪式感聚焦' },
  { bgBlur: 1.6, bgDim: 0.91, bgContrast: 0.95, fgBlur: 1.4, fgDim: 0.95, rackMs: 380, note: '产业结构：最浅焦外 + 最快 rack，服务数据阅读' },
  { bgBlur: 2.0, bgDim: 0.89, bgContrast: 0.94, fgBlur: 1.7, fgDim: 0.94, rackMs: 460, note: '赛事城市：中速 rack，如航拍换航点' },
  { bgBlur: 1.8, bgDim: 0.90, bgContrast: 0.94, fgBlur: 1.5, fgDim: 0.94, rackMs: 420, note: '职业链条：轻快节奏，跟随链条递进' },
  { bgBlur: 2.2, bgDim: 0.88, bgContrast: 0.93, fgBlur: 1.9, fgDim: 0.93, rackMs: 500, note: '全球回响：焦外加深，把单场赛事推向远景' },
  { bgBlur: 2.5, bgDim: 0.87, bgContrast: 0.92, fgBlur: 2.1, fgDim: 0.92, rackMs: 580, note: '终幕收束：深焦外慢 rack，视线落回唯一出口' },
];

const RACK_EASE = 'cubic-bezier(.2,.6,0,1)';
const RACK_OUT_EASE = 'cubic-bezier(.55,.06,.68,.19)';

export class FocusRig {
  private readonly rigs: CineSceneRig[];
  private env: CineEnvironment;
  private liveScene = -1;
  private readonly animations = new Set<Animation>();

  constructor(rigs: CineSceneRig[], env: CineEnvironment) {
    this.rigs = rigs;
    this.env = env;
  }

  private spec(scene: number): FocalSpec {
    return FOCAL_SPECS[scene] ?? FOCAL_SPECS[0];
  }

  private setVars(rig: CineSceneRig, spec: FocalSpec, armed: boolean): void {
    const mobile = this.env.mobile;
    const blurScale = armed ? (mobile ? 0.5 : 1) : 0;
    rig.rig.style.setProperty('--cine-bg-blur', `${(armed ? spec.bgBlur * blurScale : 0).toFixed(2)}px`);
    rig.rig.style.setProperty('--cine-bg-dim', armed ? spec.bgDim.toFixed(3) : '1');
    rig.rig.style.setProperty('--cine-bg-contrast', armed ? spec.bgContrast.toFixed(3) : '1');
    rig.rig.style.setProperty('--cine-fg-blur', `${(armed ? spec.fgBlur * blurScale : 0).toFixed(2)}px`);
    rig.rig.style.setProperty('--cine-fg-dim', armed ? spec.fgDim.toFixed(3) : '1');
  }

  /** 幕激活：挂上该幕焦平面（背景失焦经 CSS transition 缓入）。 */
  setActiveScene(scene: number): void {
    const previous = this.rigs[this.liveScene];
    if (previous && this.liveScene !== scene) this.setVars(previous, this.spec(this.liveScene), false);
    this.liveScene = scene;
    const rig = this.rigs[scene];
    if (!rig) return;
    if (this.env.reducedMotion) this.setVars(rig, this.spec(scene), false);
    else this.setVars(rig, this.spec(scene), true);
  }

  private maskOf(scene: number, nodeKey: string): HTMLElement | null {
    const rig = this.rigs[scene];
    if (!rig) return null;
    const figure = rig.scene.querySelector<HTMLElement>(`[data-node-visual="${nodeKey}"]`);
    return figure?.querySelector<HTMLElement>('.node-plate-mask') ?? null;
  }

  private track(animation: Animation): void {
    this.animations.add(animation);
    const release = (): void => {
      this.animations.delete(animation);
      // 收尾取消，把元素还原给底层样式（终态即中性态，无残留）。
      animation.cancel();
    };
    animation.addEventListener('finish', release, { once: true });
    animation.addEventListener('cancel', () => this.animations.delete(animation), { once: true });
  }

  /**
   * Rack focus：旧主体失焦后退，新主体由虚入清。
   * 只在同幕节点切换时调用；跨幕由镜头落幅接管焦点的重建。
   */
  rackFocus(scene: number, incomingKey: string, outgoingKey?: string): void {
    if (this.env.reducedMotion) return;
    const spec = this.spec(scene);
    const mobile = this.env.mobile;
    const rackMs = spec.rackMs;
    // 移动端降级：模糊半径压到 2.5px 以内，保留亮度与微位移。
    const peakBlur = mobile ? 2.5 : 5;

    if (outgoingKey && outgoingKey !== incomingKey) {
      const outgoing = this.maskOf(scene, outgoingKey);
      if (outgoing) {
        const animation = outgoing.animate(
          [
            { filter: 'blur(0px) brightness(1)', transform: 'scale(1)' },
            { filter: `blur(${mobile ? 2 : 4}px) brightness(.9)`, transform: 'scale(.986)' },
          ],
          { duration: Math.round(rackMs * 0.65), easing: RACK_OUT_EASE, fill: 'both' },
        );
        this.track(animation);
      }
    }

    const incoming = this.maskOf(scene, incomingKey);
    if (!incoming) return;
    const animation = incoming.animate(
      [
        { filter: `blur(${peakBlur}px) brightness(.92)`, transform: 'scale(1.012)' },
        { filter: 'blur(0px) brightness(1)', transform: 'scale(1)' },
      ],
      { duration: rackMs, easing: RACK_EASE, fill: 'both' },
    );
    this.track(animation);
  }

  /** reduced-motion：撤掉全部焦外模糊与进行中的 rack，恢复静止清晰。 */
  setReducedMotion(reduced: boolean): void {
    this.env = { ...this.env, reducedMotion: reduced };
    if (reduced) {
      this.animations.forEach((animation) => animation.cancel());
      this.animations.clear();
      this.rigs.forEach((rig) => this.setVars(rig, this.spec(rig.sceneIndex), false));
      return;
    }
    if (this.liveScene >= 0) this.setActiveScene(this.liveScene);
  }

  destroy(): void {
    this.animations.forEach((animation) => animation.cancel());
    this.animations.clear();
    this.rigs.forEach((rig) => this.setVars(rig, this.spec(rig.sceneIndex), false));
    this.liveScene = -1;
  }
}

export { FOCAL_SPECS };
export type { FocalSpec };
