/** v8.0：每幕金尘景深目标值（0=均匀；数据密集幕近景增强/远景退后）。 */
const SCENE_FOCUS_DEPTH: readonly number[] = [0, .2, .3, .4, .5, .8, .55, .4, .7, .15];

const required = <T extends Element>(selector: string, root: ParentNode = document): T => {
  const element = root.querySelector<T>(selector);
  if (!element) throw new Error(`Missing required element: ${selector}`);
  return element;
};

const all = <T extends Element>(selector: string, root: ParentNode = document): T[] =>
  Array.from(root.querySelectorAll<T>(selector));

type MotionRef = { current: MotionExperience };

/* ---------------------------------------------------------------------------
 * reduced-motion 总线：媒体查询 + 顶栏开关双源，运行时变更即时广播。
 * ------------------------------------------------------------------------ */
const motionPreference = {
  media: window.matchMedia('(prefers-reduced-motion: reduce)'),
  reduced: false,
  listeners: new Set<(reduced: boolean) => void>(),
  init(): void {
    this.reduced = this.media.matches;
    document.documentElement.classList.toggle('reduced-motion', this.reduced);
    this.media.addEventListener('change', (event) => this.set(event.matches));
  },
  set(next: boolean): void {
    if (this.reduced === next) return;
    this.reduced = next;
    document.documentElement.classList.toggle('reduced-motion', next);
    this.listeners.forEach((listener) => listener(next));
  },
  subscribe(listener: (reduced: boolean) => void): void {
    this.listeners.add(listener);
    listener(this.reduced);
  },
};

/* ---------------------------------------------------------------------------
 * 金缮裂缝：激活幕的裂缝 symbol 以 dashoffset 生长（仅可见幕的实例被看见）。
 * ------------------------------------------------------------------------ */
const drawKintsugi = (sceneIndex: number): void => {
  const scene = document.querySelector<HTMLElement>(`[data-scene="${sceneIndex}"]`);
  const svg = scene?.querySelector<SVGSVGElement>('svg.kintsugi');
  const href = svg?.querySelector('use')?.getAttribute('href');
  if (!svg || !href) return;
  const paths = all<SVGPathElement>(`${href} path`);
  const rects = all<SVGRectElement>(`${href} rect`);
  if (motionPreference.reduced) {
    gsap.set(paths, { strokeDashoffset: 0 });
    gsap.set(rects, { opacity: 1 });
    gsap.set(svg, { opacity: .55 });
    return;
  }
  gsap.fromTo(svg, { opacity: 0 }, { opacity: .55, duration: .7, ease: 'power2.out', delay: .45, overwrite: true });
  gsap.fromTo(paths, { strokeDashoffset: 100 }, { strokeDashoffset: 0, duration: 1.15, stagger: .16, ease: 'power2.inOut', delay: .5, overwrite: true });
  gsap.fromTo(rects, { opacity: 0 }, { opacity: 1, duration: .4, stagger: .12, delay: 1.35, overwrite: true });
};

/* ---------------------------------------------------------------------------
 * 光标（6px 金点 + 28px 阻尼金环）与三层指针视差（展签 ±14 / 巨字 ∓8 / 文本 ±4）。
 * 共用一个 gsap ticker；reduced-motion 下全部停用。
 * ------------------------------------------------------------------------ */
type QuickSetter = (value: string | number, start?: string | number) => void;
type LayerSetter = { x: QuickSetter; y: QuickSetter };

function setupPointerChoreography(): void {
  if (!window.matchMedia('(hover: hover) and (pointer: fine)').matches) return;
  const glow = required<HTMLElement>('#pointerGlow');
  const dot = required<HTMLElement>('.pointer-glow__dot', glow);
  const ring = required<HTMLElement>('.pointer-glow__ring', glow);
  const experience = required<HTMLElement>('#experience');
  const setDotX = gsap.quickSetter(dot, 'x', 'px');
  const setDotY = gsap.quickSetter(dot, 'y', 'px');
  const setRingX = gsap.quickSetter(ring, 'x', 'px');
  const setRingY = gsap.quickSetter(ring, 'y', 'px');
  const pointer = { x: window.innerWidth / 2, y: window.innerHeight / 2 };
  const ringPosition = { x: pointer.x, y: pointer.y };
  const parallax = { x: 0, y: 0 };
  let layerKey = '';
  let plates: LayerSetter[] = [];
  let giant: LayerSetter | null = null;

  const clearLayers = (): void => {
    plates.forEach((layer) => { layer.x(0); layer.y(0); });
    giant?.x(0);
    giant?.y(0);
    plates = [];
    giant = null;
    layerKey = '';
  };

  const qs = (element: HTMLElement, prop: 'x' | 'y'): QuickSetter =>
    gsap.quickSetter(element, prop, 'px') as unknown as QuickSetter;

  const collectLayers = (): void => {
    const scene = document.querySelector<HTMLElement>('.scene.is-active');
    if (!scene) return;
    plates = all<HTMLElement>('.node-visual.is-active .node-plate-parallax', scene)
      .map((element) => ({ x: qs(element, 'x'), y: qs(element, 'y') }));
    const giantElement = scene.querySelector<HTMLElement>('.scene__giant span');
    giant = giantElement ? { x: qs(giantElement, 'x'), y: qs(giantElement, 'y') } : null;
    // v8.0：正文层零视差（镜头语言规范——阅读区必须稳定），不再收集 text 层。
  };

  window.addEventListener('pointermove', (event) => {
    pointer.x = event.clientX;
    pointer.y = event.clientY;
    if (!motionPreference.reduced && Number(gsap.getProperty(glow, 'opacity')) < .9) gsap.set(glow, { autoAlpha: 1 });
  }, { passive: true });
  document.documentElement.addEventListener('pointerleave', () => gsap.to(glow, { autoAlpha: 0, duration: .25 }));

  gsap.ticker.add(() => {
    if (motionPreference.reduced) {
      if (layerKey) clearLayers();
      if (Number(gsap.getProperty(glow, 'opacity')) > 0) gsap.set(glow, { autoAlpha: 0 });
      return;
    }
    ringPosition.x += (pointer.x - ringPosition.x) * .12;
    ringPosition.y += (pointer.y - ringPosition.y) * .12;
    setDotX(pointer.x);
    setDotY(pointer.y);
    setRingX(ringPosition.x);
    setRingY(ringPosition.y);

    parallax.x += (pointer.x / window.innerWidth - .5 - parallax.x) * .06;
    parallax.y += (pointer.y / window.innerHeight - .5 - parallax.y) * .06;

    const key = `${experience.dataset.scene}:${experience.dataset.node}`;
    if (key !== layerKey) {
      layerKey = key;
      collectLayers();
    }
    plates.forEach((layer) => { layer.x(parallax.x * 14); layer.y(parallax.y * 8.5); });
    if (giant) { giant.x(parallax.x * -8); giant.y(parallax.y * -5); }
  });
}

function setupMagnetics(): void {
  if (!window.matchMedia('(hover: hover) and (pointer: fine)').matches) return;
  all<HTMLElement>('.magnetic').forEach((element) => {
    const targets = all<HTMLElement>('span, i', element);
    element.addEventListener('pointermove', (event) => {
      if (motionPreference.reduced) return;
      const rect = element.getBoundingClientRect();
      const x = event.clientX - rect.left - rect.width / 2;
      const y = event.clientY - rect.top - rect.height / 2;
      gsap.to(targets, { x: x * .14, y: y * .16, duration: .16, ease: 'power2.out', overwrite: true });
    });
    element.addEventListener('pointerleave', () => {
      gsap.to(targets, { x: 0, y: 0, duration: .42, ease: 'power3.out', overwrite: true });
    });
  });
}

/* ---------------------------------------------------------------------------
 * 抽屉（目录/资料）：焦点陷阱 + 初始焦点 + 背景 inert + 关闭时归还焦点。
 * ------------------------------------------------------------------------ */
type DrawerController = { close: () => void };

const setBackgroundInert = (inert: boolean): void => {
  ['#experience', '#topbar', '.rail'].forEach((selector) => {
    const element = document.querySelector(selector);
    if (!element) return;
    if (inert) element.setAttribute('inert', '');
    else element.removeAttribute('inert');
  });
};

const trapTabKey = (panel: HTMLElement, event: KeyboardEvent): void => {
  if (event.key !== 'Tab') return;
  const items = all<HTMLElement>('button, a[href], input, [tabindex]:not([tabindex="-1"])', panel)
    .filter((element) => element.offsetParent !== null);
  if (!items.length) return;
  const first = items[0];
  const last = items[items.length - 1];
  if (event.shiftKey && document.activeElement === first) {
    event.preventDefault();
    last.focus();
  } else if (!event.shiftKey && document.activeElement === last) {
    event.preventDefault();
    first.focus();
  }
};

function setupMenu(motionRef: MotionRef): DrawerController {
  const menu = required<HTMLElement>('#menuPanel');
  const panel = required<HTMLElement>('.menu__panel', menu);
  const backdrop = required<HTMLElement>('.menu__backdrop', menu);
  const toggle = required<HTMLButtonElement>('#menuToggle');
  let open = false;
  let previousFocus: HTMLElement | null = null;
  gsap.set(panel, { xPercent: 100, x: 0 });
  panel.addEventListener('keydown', (event) => { if (open) trapTabKey(panel, event); });

  const setOpen = (next: boolean): void => {
    if (open === next) return;
    open = next;
    toggle.setAttribute('aria-expanded', String(open));
    menu.setAttribute('aria-hidden', String(!open));
    document.body.classList.toggle('menu-open', open);
    if (open) {
      previousFocus = document.activeElement instanceof HTMLElement ? document.activeElement : null;
      setBackgroundInert(true);
      gsap.set(menu, { visibility: 'visible', pointerEvents: 'auto' });
      gsap.timeline()
        .to(backdrop, { autoAlpha: 1, duration: .28, ease: 'power2.out' })
        .to(panel, { xPercent: 0, duration: .46, ease: 'power4.out' }, 0)
        .fromTo('.menu__links button', { x: 32, autoAlpha: 0 }, { x: 0, autoAlpha: 1, duration: .32, stagger: .026, ease: 'power3.out' }, .12);
      panel.querySelector<HTMLElement>('.menu__links button')?.focus({ preventScroll: true });
    } else {
      setBackgroundInert(false);
      gsap.timeline({ onComplete: () => gsap.set(menu, { visibility: 'hidden', pointerEvents: 'none' }) })
        .to('.menu__links button', { x: 22, autoAlpha: 0, duration: .15, stagger: .012, ease: 'power2.in' })
        .to(panel, { xPercent: 100, duration: .36, ease: 'power3.inOut' }, .04)
        .to(backdrop, { autoAlpha: 0, duration: .24 }, .05);
      previousFocus?.focus({ preventScroll: true });
      previousFocus = null;
    }
  };

  toggle.addEventListener('click', () => setOpen(!open));
  all<HTMLElement>('[data-close-menu]', menu).forEach((element) => element.addEventListener('click', () => setOpen(false)));
  all<HTMLButtonElement>('[data-go]').forEach((button) => {
    button.addEventListener('click', () => {
      setOpen(false);
      motionRef.current.goTo(Number(button.dataset.go));
    });
  });
  window.addEventListener('keydown', (event) => { if (event.key === 'Escape') setOpen(false); });
  return { close: () => setOpen(false) };
}

function setupSources(menu: DrawerController): DrawerController {
  const sources = required<HTMLElement>('#sourcePanel');
  const panel = required<HTMLElement>('.sources__panel', sources);
  const backdrop = required<HTMLElement>('.sources__backdrop', sources);
  let open = false;
  let previousFocus: HTMLElement | null = null;
  gsap.set(panel, { xPercent: 100 });
  panel.addEventListener('keydown', (event) => { if (open) trapTabKey(panel, event); });

  const setOpen = (next: boolean): void => {
    if (open === next) return;
    open = next;
    if (open) menu.close();
    previousFocus = open && document.activeElement instanceof HTMLElement ? document.activeElement : previousFocus;
    sources.setAttribute('aria-hidden', String(!open));
    document.body.classList.toggle('sources-open', open);
    if (open) {
      setBackgroundInert(true);
      gsap.set(sources, { visibility: 'visible', pointerEvents: 'auto' });
      gsap.timeline()
        .to(backdrop, { autoAlpha: 1, duration: .28 })
        .to(panel, { xPercent: 0, duration: .48, ease: 'power4.out' }, 0)
        .fromTo('.sources__list li', { autoAlpha: 0, x: 24 }, { autoAlpha: 1, x: 0, duration: .3, stagger: .035, ease: 'power3.out' }, .14);
      panel.querySelector<HTMLElement>('button')?.focus({ preventScroll: true });
    } else {
      setBackgroundInert(false);
      gsap.timeline({ onComplete: () => gsap.set(sources, { visibility: 'hidden', pointerEvents: 'none' }) })
        .to(panel, { xPercent: 100, duration: .39, ease: 'power3.inOut' })
        .to(backdrop, { autoAlpha: 0, duration: .22 }, .04);
      previousFocus?.focus({ preventScroll: true });
      previousFocus = null;
    }
  };

  all<HTMLElement>('[data-open-sources]').forEach((element) => element.addEventListener('click', () => setOpen(true)));
  all<HTMLElement>('[data-close-sources]', sources).forEach((element) => element.addEventListener('click', () => setOpen(false)));
  window.addEventListener('keydown', (event) => { if (event.key === 'Escape') setOpen(false); });
  return { close: () => setOpen(false) };
}

function setupMotionToggle(motionRef: MotionRef): void {
  const toggle = required<HTMLButtonElement>('#motionToggle');
  toggle.addEventListener('click', () => motionPreference.set(!motionPreference.reduced));
  motionPreference.subscribe((reduced) => {
    toggle.setAttribute('aria-pressed', String(reduced));
    toggle.title = reduced ? '开启完整动态效果' : '降低动态效果';
    motionRef.current.setReducedMotion(reduced);
  });
}

/* v8.0 玻璃光照微交互：高光跟随指针（CSS 变量经 @property 注册，自带过渡阻尼）。 */
function initGlassSpecular(): void {
  if (!window.matchMedia('(hover: hover) and (pointer: fine)').matches) return;
  const GLASS_SELECTOR = '.node-tabs, .source-chip, .node-material-swatch, .era-control, .menu__panel, .sources__panel';
  document.addEventListener('pointermove', (event) => {
    if (motionPreference.reduced) return;
    const el = (event.target as Element | null)?.closest?.(GLASS_SELECTOR) as HTMLElement | null;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    if (rect.width < 2 || rect.height < 2) return;
    el.style.setProperty('--glass-mx', `${(((event.clientX - rect.left) / rect.width) * 100).toFixed(1)}%`);
    el.style.setProperty('--glass-my', `${(((event.clientY - rect.top) / rect.height) * 100).toFixed(1)}%`);
  }, { passive: true });
  document.addEventListener('pointerout', (event) => {
    const el = (event.target as Element | null)?.closest?.(GLASS_SELECTOR) as HTMLElement | null;
    if (!el) return;
    el.style.setProperty('--glass-mx', '50%');
    el.style.setProperty('--glass-my', '-30%');
  }, { passive: true });
}

/* ---------------------------------------------------------------------------
 * 左侧 rail：40 刻度（依 SCENE_NODE_KEYS 生成）+ 圆弧进度环 + 编目号。
 * ------------------------------------------------------------------------ */
type RailRefs = {
  ticks: HTMLButtonElement[];
  ring: HTMLElement;
  arc: SVGCircleElement;
  catalog: HTMLElement;
};

const RING_LENGTH = 97.39; // 2π × 15.5

function buildRail(motionRef: MotionRef): RailRefs {
  const container = required<HTMLElement>('#railTicks');
  const ring = required<HTMLElement>('#railRing');
  const arc = required<SVGCircleElement>('#railRingArc');
  const catalog = required<HTMLElement>('#railCatalog');
  const ticks: HTMLButtonElement[] = [];
  let flat = 0;
  SCENE_NODE_KEYS.forEach((keys, sceneIndex) => {
    keys.forEach((key) => {
      const target = flat;
      const tick = document.createElement('button');
      tick.type = 'button';
      tick.className = 'rail__tick';
      tick.dataset.flat = String(target);
      tick.dataset.chapter = String(sceneIndex);
      tick.setAttribute('aria-label', `第 ${target + 1} 节点 · ${key.toUpperCase()}（${CHAPTERS[sceneIndex].name}）`);
      tick.setAttribute('aria-current', 'false');
      tick.innerHTML = '<i></i>';
      tick.addEventListener('click', () => motionRef.current.goToFlat(target));
      container.append(tick);
      ticks.push(tick);
      flat += 1;
    });
  });
  return { ticks, ring, arc, catalog };
}

/* ---------------------------------------------------------------------------
 * 章节/节点 UI：顶栏、rail、巨型年代字、aria-live 通报、相邻图像素预取。
 * ------------------------------------------------------------------------ */
type UiHandlers = {
  handleChapter: (index: number, phase: ScenePhase) => void;
  handleNode: (scene: number, key: string, localIndex: number, flatIndex: number, reason: NodeChangeReason) => void;
  currentChapter: () => number;
};

function setupChapterUI(rail: RailRefs): UiHandlers {
  const activeAct = required<HTMLElement>('#activeAct');
  const activeName = required<HTMLElement>('#activeName');
  const topbar = required<HTMLElement>('#topbar');
  const flowCue = required<HTMLElement>('#flowCue');
  const flowState = required<HTMLElement>('#flowState');
  const liveRegion = required<HTMLElement>('#liveRegion');
  const menuButtons = all<HTMLButtonElement>('.menu__links [data-go]');
  let phase: ScenePhase = 'primary';
  let chapter = 0;
  let nodeKey = '2003';
  let flatIndex = 0;

  const renderFlow = (): void => {
    flowCue.textContent = `NODE / ${String(flatIndex + 1).padStart(2, '0')}—${String(TOTAL_NODES).padStart(2, '0')}`;
    flowState.textContent = `${phase === 'detail' ? 'READY' : 'OPENING'} · ${nodeKey.toUpperCase()}`;
  };

  const updateGiant = (sceneIndex: number, key: string, flat: number): void => {
    const giant = document.querySelector<HTMLElement>(`[data-scene="${sceneIndex}"] [data-giant]`);
    if (!giant) return;
    const label = /^\d{4}$/.test(key) ? key : String(flat + 1).padStart(2, '0');
    if (giant.textContent === label) return;
    giant.textContent = label;
    if (!motionPreference.reduced) {
      gsap.fromTo(giant, { opacity: 0 }, { opacity: .58, duration: .55, ease: 'power2.out', overwrite: true });
    }
  };

  /** 非相邻节点保持 lazy；当前节点 ±1 与相邻幕首节点升级为 eager。 */
  const promoteNodeImages = (sceneIndex: number, localIndex: number): void => {
    const scenes = all<HTMLElement>('[data-scene]');
    const figures: HTMLElement[] = [];
    const active = scenes[sceneIndex];
    if (active) {
      const keys = active.dataset.nodeKeys?.split(',') ?? [];
      all<HTMLElement>('[data-node-visual]', active).forEach((figure) => {
        const index = keys.indexOf(figure.dataset.nodeVisual ?? '');
        if (index >= 0 && Math.abs(index - localIndex) <= 1) figures.push(figure);
      });
    }
    [sceneIndex - 1, sceneIndex + 1].forEach((adjacent) => {
      const scene = scenes[adjacent];
      const firstKey = scene?.dataset.nodeKeys?.split(',')[0];
      const first = scene?.querySelector<HTMLElement>(`[data-node-visual="${firstKey}"]`);
      if (first) figures.push(first);
    });
    figures.forEach((figure) => {
      all<HTMLImageElement>('img[loading="lazy"]', figure).forEach((image) => { image.loading = 'eager'; });
    });
  };

  return {
    currentChapter: () => chapter,
    handleChapter: (index, nextPhase) => {
      chapter = index;
      phase = nextPhase;
      const chapterData = CHAPTERS[index];
      gsap.to([activeAct, activeName], {
        autoAlpha: 0,
        y: -4,
        duration: .1,
        onComplete: () => {
          activeAct.textContent = chapterData.act;
          activeName.textContent = `${chapterData.name} · ${PHASE_LABELS[nextPhase]}`;
          gsap.fromTo([activeAct, activeName], { y: 4 }, { autoAlpha: 1, y: 0, duration: .18, stagger: .025 });
        },
      });
      topbar.classList.toggle('is-compact', index > 0);
      menuButtons.forEach((button, buttonIndex) => button.classList.toggle('is-active', buttonIndex === index));
      rail.ticks.forEach((tick) => tick.classList.toggle('is-chapter', Number(tick.dataset.chapter) === index));
      if (!document.body.classList.contains('is-loading')) drawKintsugi(index);
      renderFlow();
    },
    handleNode: (scene, key, localIndex, flat, reason) => {
      nodeKey = key;
      flatIndex = flat;
      rail.catalog.textContent = String(flat + 1).padStart(2, '0');
      rail.ticks.forEach((tick, tickIndex) => tick.setAttribute('aria-current', String(tickIndex === flat)));
      const tick = rail.ticks[flat];
      if (tick) rail.ring.style.top = `${tick.offsetTop + tick.offsetHeight / 2 - 13}px`;
      rail.arc.style.strokeDashoffset = String(RING_LENGTH * (1 - flat / (TOTAL_NODES - 1)));
      updateGiant(scene, key, flat);
      if (reason !== 'qa') {
        const chapterData = CHAPTERS[scene];
        liveRegion.textContent = `${chapterData.act} ${chapterData.name}，第 ${flat + 1} / ${TOTAL_NODES} 节点：${key.toUpperCase()}`;
      }
      promoteNodeImages(scene, localIndex);
      renderFlow();
    },
  };
}

