/* ---------------------------------------------------------------------------
 * Boot：黑底 → 金缮印章描线（1.2s）→ 计数 000–100 → 幕布揭开。
 * B3：3.5s 兜底计时在初始化即武装（init 内），不再等待 window.load。
 * ------------------------------------------------------------------------ */
async function prepareBootTypography(): Promise<void> {
  if (!document.fonts || typeof FontFace === 'undefined') {
    document.documentElement.classList.add('boot-font-fallback');
    return;
  }
  const fontUrl = new URL('assets/fonts/boot-cormorant-500.woff2', document.baseURI).href;
  const bootFace = new FontFace('Boot Cormorant', `url("${fontUrl}") format("woff2")`, { style: 'normal', weight: '500' });
  const loaded = bootFace.load().then((face) => { document.fonts.add(face); return true; }).catch(() => false);
  const timedOut = new Promise<boolean>((resolve) => window.setTimeout(() => resolve(false), 1600));
  if (!await Promise.race([loaded, timedOut])) document.documentElement.classList.add('boot-font-fallback');
}

function playBootSequence(onReady: () => void): { kill: () => void } {
  return playGoldBoot({
    onReady,
    onPhase: (phase: BootPhase) => {
      document.documentElement.dataset.bootPhase = phase;
    },
  });
}

function createAmbientController(canvas: HTMLCanvasElement): AmbientController {
  const fallback: AmbientController = {
    setProgress: () => undefined,
    setReducedMotion: () => undefined,
    destroy: () => undefined,
  };

  let scene: AmbientController = fallback;
  try {
    const context = canvas.getContext('webgl2', { alpha: true, antialias: true })
      ?? canvas.getContext('webgl', { alpha: true, antialias: true });
    if (!context) {
      canvas.hidden = true;
    } else {
      scene = new AmbientScene(canvas);
    }
  } catch (error) {
    canvas.hidden = true;
    console.warn('[Gilt Archive] WebGL unavailable; continuing with DOM atmosphere.', error);
  }

  // 3D 金器：独立容器与渲染器，内部自带 no-op 兜底。
  const artifact = mountGoldArtifact(required<HTMLElement>('#artifactStage'));

  return {
    setProgress: (progress: number) => { scene.setProgress(progress); artifact.setProgress(progress); },
    setReducedMotion: (reduced: boolean) => { scene.setReducedMotion(reduced); artifact.setReducedMotion(reduced); },
    // v7.2：转场-金尘聚散脉冲（类型化主路径；motion.ts 探测优先、DOM 事件桥兜底）
    pulse: (intensity?: number) => { scene.pulse?.(intensity); },
    // v8.0：首幕金器推镜 / 回位 / 金尘景深
    pushThrough: (duration?: number) => { artifact.pushThrough(duration); },
    resetCamera: (duration?: number) => { artifact.resetCamera(duration); },
    setFocusDepth: (t: number) => { scene.setFocusDepth?.(t); },
    destroy: () => { scene.destroy(); artifact.destroy(); },
  };
}

type QaWindow = Window & typeof globalThis & {
  __motionExperience?: MotionExperience;
  __qaReady?: boolean;
};

function init(): void {
  // Mount before MotionExperience prepares scene state, so node 01 is visible on first paint.
  mountNodeArtV67();
  mountSceneViz();
  let ambient = createAmbientController(required<HTMLCanvasElement>('#webgl'));
  const motionRef: MotionRef = { current: null as unknown as MotionExperience };
  motionRef.current = new MotionExperience(ambient);
  motionPreference.init();

  // v8.0：镜头导演 / 动态文字 / 宏景层；v8.1：BGM 黑胶开关（init 绑定顶栏 #soundToggle）。
  let cine: CineController = initCine({ reducedMotion: motionPreference.reduced });
  initKinetic();
  soundDesign.init();
  mountSceneVistas();
  motionPreference.subscribe((reduced) => cine.setReducedMotion(reduced));

  setupPointerChoreography();
  setupMagnetics();
  initGlassSpecular();
  const menu = setupMenu(motionRef);
  setupSources(menu);
  setupMotionToggle(motionRef);
  const applyNodeContent = setupInteractions(motionRef);
  const rail = buildRail(motionRef);
  const ui = setupChapterUI(rail);

  const params = new URLSearchParams(window.location.search);
  const qaWindow = window as QaWindow;
  let currentFlat = 0;

  const wireMotion = (instance: MotionExperience): void => {
    instance.onActiveChapter(ui.handleChapter);
    instance.onActiveNode((scene, key, localIndex, flat, reason) => {
      currentFlat = flat;
      ui.handleNode(scene, key, localIndex, flat, reason);
    });
    instance.onActiveNode((scene, key, localIndex, _flat, reason) => {
      applyNodeContent(scene, key, localIndex);
      syncSceneViz(scene, key, localIndex, reason);
      // 3D 金器仅驻守首幕；其余幕让位于展签与可视化。
      required<HTMLElement>('#artifactStage').classList.toggle('is-hidden', scene !== 0);
    });
    // v8.0：镜头导演跟随节点切换（含 rack focus / 视差接棒 / 幕内进度换算）。
    instance.onActiveNode((scene, key, localIndex, flat, _reason) => {
      cine.setActiveNode(scene, key, localIndex, flat);
    });
    // v8.0：金尘景深分级——数据密集幕焦外退后，首末幕回归均匀。
    instance.onActiveNode((scene, _key, _localIndex, _flat, _reason) => {
      ambient.setFocusDepth?.(SCENE_FOCUS_DEPTH[scene] ?? 0);
    });
    // v8.0：动态文字——必须在 applyNodeContent 之后注册，读到切换后的新文案。
    instance.onActiveNode((scene, _key, localIndex) => kineticOnNodeChange(scene, localIndex));
    instance.setReducedMotion(motionPreference.reduced);
    qaWindow.__motionExperience = instance;
  };

  /* B3：boot 兜底计时在初始化即武装——慢网不再面对静止 000%。 */
  let bootFinished = false;
  let bootHandle: { kill: () => void } | null = null;
  const finishBoot = (): void => {
    if (bootFinished) return;
    bootFinished = true;
    window.clearTimeout(bootGuard);
    document.body.classList.remove('is-loading');
    document.querySelector('#boot')?.remove();
    window.dispatchEvent(new Event('resize'));
    motionRef.current.start();
    drawKintsugi(ui.currentChapter());
  };
  const bootGuard = window.setTimeout(() => {
    if (bootFinished) return;
    bootHandle?.kill();
    gsap.set('.heritage-canvas--01', { y: 0, scale: 1, autoAlpha: 1, filter: 'blur(0px)' });
    gsap.set('.hero-aperture-v66', { autoAlpha: .5, rotation: -16 });
    const boot = document.querySelector('#boot');
    if (boot) gsap.to(boot, { autoAlpha: 0, duration: .2, onComplete: finishBoot });
    else finishBoot();
  }, 3500);

  wireMotion(motionRef.current);
  motionRef.current.refresh();

  if (params.has('qa')) {
    window.clearTimeout(bootGuard);
    bootFinished = true;
    document.body.classList.remove('is-loading');
    document.querySelector('#boot')?.remove();
    motionRef.current.start();
    const qaNode = Number(params.get('qaNode'));
    if (Number.isFinite(qaNode) && qaNode >= 0) motionRef.current.goToFlat(qaNode, true);
    requestAnimationFrame(() => { qaWindow.__qaReady = true; });
  } else {
    void prepareBootTypography();
    bootHandle = playBootSequence(finishBoot);
  }

  /* B2：仅在真正进入 bfcache（persisted）时销毁；返回时在 pageshow 重建。 */
  let destroyedForBFCache = false;
  window.addEventListener('pagehide', (event) => {
    if (!event.persisted) return;
    destroySceneViz();
    // v8.0：cine 一并销毁（摘掉 gsap.ticker 与 window 事件、还原 rig DOM），
    // 与 cine/index.ts 的 pagehide 契约一致；pageshow 里 initCine 负责重建。
    cine.destroy();
    motionRef.current.destroy();
    ambient.destroy();
    destroyedForBFCache = true;
  });
  window.addEventListener('pageshow', (event) => {
    if (!event.persisted || !destroyedForBFCache) return;
    destroyedForBFCache = false;
    // canvas 换新，避免复用已 forceContextLoss 的绘图表面。
    const staleCanvas = required<HTMLCanvasElement>('#webgl');
    const freshCanvas = staleCanvas.cloneNode(false) as HTMLCanvasElement;
    staleCanvas.replaceWith(freshCanvas);
    ambient = createAmbientController(freshCanvas);
    motionRef.current = new MotionExperience(ambient);
    wireMotion(motionRef.current);
    motionRef.current.start();
    motionRef.current.goToFlat(currentFlat, true);
    // v8.0：镜头 rig 与宏景层随 DOM 重建（initCine 内置旧实例自毁）。
    cine = initCine({ reducedMotion: motionPreference.reduced });
    mountSceneVistas();
  });
}

init();
