/* ============================================================================
 * audio/SoundDesign.ts — v8.1 背景音乐（BGM）播放器（HTMLAudioElement，单音频文件）
 *
 * v8.1 变更：删除 v8.0 全部 WebAudio 程序化合成音（whoosh/impact/chime/ambient），
 * 改为单一循环背景音乐「boy solo - 共生」。音量脚本（稍微加强，随后弱下去）：
 *   启用 → 0 → 0.55 约 1.2s 快速升起（easeOutCubic）
 *        → 0.55 保持约 2.5s
 *        → 约 4.5s 平滑降到 0.18 驻留（easeInOutQuad），循环播放；
 *   关闭 → 从当前音量约 0.8s 反向淡出后 pause。
 *
 * 行为契约：
 *   - localStorage('gilt-sound') 记忆开关，默认关；
 *   - 记忆为开时 load 后自动 play()，若被自动播放策略拒绝，则挂一次性
 *     pointerdown/keydown 监听，首次手势时恢复播放；
 *   - visibilitychange：页面隐藏时暂停并标记，回见且开关为开时恢复驻留音量播放；
 *   - 开关按钮为 index.html 顶栏「目录」右侧的黑胶按钮（#soundToggle），
 *     init 时绑定；播放中加 .is-playing（CSS 驱动旋转），aria-pressed 同步；
 *   - destroy() 供 bfcache / HMR 场景调用：卸载监听、取消音量 rAF、暂停音频。
 *
 * 接入（main.ts）：
 *   import { soundDesign } from './audio';
 *   soundDesign.init();          // 绑定黑胶按钮、读取记忆、按需自动开播
 *   soundDesign.setEnabled(true); // 等价于点击黑胶
 * ========================================================================== */

const STORAGE_KEY = 'gilt-sound';
/** 相对路径：index.html 与 assets/ 同级（dev 与 dist 均成立）。 */
const BGM_SRC = 'assets/audio/bgm-gongsheng.mp3';

const VOLUME_PEAK = 0.55; // 升起峰值（稍微加强）
const VOLUME_DWELL = 0.18; // 驻留音量（随后弱下去）
const RISE_MS = 1200;
const HOLD_MS = 2500;
const FALL_MS = 4500;
const FADEOUT_MS = 800;

const easeOutCubic = (t: number): number => 1 - Math.pow(1 - t, 3);
const easeInOutQuad = (t: number): number => (t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2);

const readStoredEnabled = (): boolean => {
  try {
    return window.localStorage.getItem(STORAGE_KEY) === 'on';
  } catch {
    return false; // 隐私模式 / 禁用存储：回落默认关闭
  }
};

export class SoundDesign {
  private audio: HTMLAudioElement | null = null;
  private enabled = false;
  private initialized = false;
  private rafId = 0;
  private systemPaused = false;
  private recoveryArmed = false;
  private toggleButton: HTMLButtonElement | null = null;

  /* ------------------------------------------------------------------ API */

  /** 幂等。绑定顶栏黑胶按钮、读取持久化状态；记忆为开时尝试自动开播。 */
  init(): void {
    if (this.initialized) return;
    this.initialized = true;
    this.enabled = readStoredEnabled(); // 无记录 → false（默认关闭）
    this.bindToggle();
    document.addEventListener('visibilitychange', this.handleVisibility);
    this.syncToggle();
    if (this.enabled) this.startBgm(); // play() 被拒时内部挂一次性手势恢复
  }

  /** 总开关：持久化到 localStorage('gilt-sound')，同步黑胶状态，启停 BGM。 */
  setEnabled(next: boolean): void {
    this.enabled = Boolean(next);
    this.persistEnabled();
    this.syncToggle();
    if (this.enabled) this.startBgm();
    else this.stopBgm();
  }

  isEnabled(): boolean {
    return this.enabled;
  }

  /** 卸载监听、取消音量插值、暂停音频（按钮保留在 DOM 中，复位其状态）。 */
  destroy(): void {
    document.removeEventListener('visibilitychange', this.handleVisibility);
    this.disarmAutoplayRecovery();
    if (this.toggleButton) this.toggleButton.removeEventListener('click', this.handleToggleClick);
    this.cancelVolumeRaf();
    if (this.audio) {
      this.audio.pause();
      this.audio.removeAttribute('src');
      this.audio.load();
      this.audio = null;
    }
    this.enabled = false;
    this.systemPaused = false;
    this.initialized = false;
    this.toggleButton = null;
  }

  /* ------------------------------------------------------------- 黑胶按钮 */

  private readonly handleToggleClick = (): void => {
    this.setEnabled(!this.enabled);
  };

  private bindToggle(): void {
    const button = document.querySelector<HTMLButtonElement>('#soundToggle');
    if (!button) {
      console.warn('[Gilt BGM] #soundToggle not found; BGM switch unavailable.');
      return;
    }
    button.addEventListener('click', this.handleToggleClick);
    this.toggleButton = button;
  }

  private syncToggle(): void {
    if (!this.toggleButton) return;
    this.toggleButton.classList.toggle('is-playing', this.enabled);
    this.toggleButton.setAttribute('aria-pressed', String(this.enabled));
    this.toggleButton.title = this.enabled ? '关闭背景音乐' : '播放背景音乐';
  }

  private persistEnabled(): void {
    try {
      window.localStorage.setItem(STORAGE_KEY, this.enabled ? 'on' : 'off');
    } catch {
      /* 写入失败（隐私模式等）：静默，不影响当次状态 */
    }
  }

  /* ------------------------------------------------------------- 播放控制 */

  /** 懒创建音频元素：loop、preload="none"，仅在首次启用时设置 src。 */
  private ensureAudio(): HTMLAudioElement {
    if (!this.audio) {
      const audio = new Audio();
      audio.loop = true;
      audio.preload = 'none';
      audio.src = BGM_SRC;
      this.audio = audio;
      // QA 钩子（与 __motionExperience 同类）：音量脚本验收用，不影响运行时行为。
      (window as Window & { __giltBgm?: HTMLAudioElement }).__giltBgm = audio;
    }
    return this.audio;
  }

  /** 启用：音量从 0 起步播放，随后跑「升起→保持→驻留」音量脚本。 */
  private startBgm(): void {
    const audio = this.ensureAudio();
    this.systemPaused = false;
    this.disarmAutoplayRecovery();
    this.cancelVolumeRaf();
    audio.volume = 0;
    const attempt = audio.play();
    if (attempt && typeof attempt.then === 'function') {
      attempt
        .then(() => this.runVolumeEnvelope())
        .catch(() => this.armAutoplayRecovery()); // 自动播放策略：等首次手势
    } else {
      this.runVolumeEnvelope();
    }
  }

  /** 关闭：从当前音量反向淡出后 pause。 */
  private stopBgm(): void {
    this.disarmAutoplayRecovery();
    this.cancelVolumeRaf();
    const audio = this.audio;
    if (!audio || audio.paused) return;
    const from = audio.volume;
    const t0 = performance.now();
    const tick = (now: number): void => {
      const p = Math.min(1, Math.max(0, (now - t0) / FADEOUT_MS));
      audio.volume = Math.min(1, Math.max(0, from * (1 - easeInOutQuad(p))));
      if (p < 1) this.rafId = requestAnimationFrame(tick);
      else {
        audio.pause();
        this.rafId = 0;
      }
    };
    this.rafId = requestAnimationFrame(tick);
  }

  /** 音量脚本：0→0.55（1.2s）→ 保持（2.5s）→ 0.18 驻留（4.5s）。 */
  private runVolumeEnvelope(): void {
    const audio = this.audio;
    if (!audio || !this.enabled) return;
    const t0 = performance.now();
    const tick = (now: number): void => {
      if (!this.enabled || !this.audio) return;
      // rAF 时间戳可能早于 t0（帧起点早于当前任务），夹紧避免负音量抛错。
      const elapsed = Math.max(0, now - t0);
      let volume: number;
      if (elapsed < RISE_MS) {
        volume = VOLUME_PEAK * easeOutCubic(elapsed / RISE_MS);
      } else if (elapsed < RISE_MS + HOLD_MS) {
        volume = VOLUME_PEAK;
      } else if (elapsed < RISE_MS + HOLD_MS + FALL_MS) {
        const p = (elapsed - RISE_MS - HOLD_MS) / FALL_MS;
        volume = VOLUME_PEAK + (VOLUME_DWELL - VOLUME_PEAK) * easeInOutQuad(p);
      } else {
        audio.volume = VOLUME_DWELL;
        this.rafId = 0;
        return;
      }
      audio.volume = Math.min(1, Math.max(0, volume));
      this.rafId = requestAnimationFrame(tick);
    };
    this.rafId = requestAnimationFrame(tick);
  }

  private cancelVolumeRaf(): void {
    if (!this.rafId) return;
    cancelAnimationFrame(this.rafId);
    this.rafId = 0;
  }

  /* -------------------------------------------------- 自动播放策略与可见性 */

  /** play() 被拒后：挂一次性 pointerdown/keydown，首次手势恢复播放。 */
  private armAutoplayRecovery(): void {
    if (this.recoveryArmed || !this.enabled) return;
    this.recoveryArmed = true;
    window.addEventListener('pointerdown', this.handleRecoveryGesture, { capture: true, once: true });
    window.addEventListener('keydown', this.handleRecoveryGesture, { capture: true, once: true });
  }

  private disarmAutoplayRecovery(): void {
    if (!this.recoveryArmed) return;
    this.recoveryArmed = false;
    window.removeEventListener('pointerdown', this.handleRecoveryGesture, { capture: true });
    window.removeEventListener('keydown', this.handleRecoveryGesture, { capture: true });
  }

  private readonly handleRecoveryGesture = (): void => {
    this.recoveryArmed = false;
    window.removeEventListener('keydown', this.handleRecoveryGesture, { capture: true });
    window.removeEventListener('pointerdown', this.handleRecoveryGesture, { capture: true });
    if (this.enabled) this.startBgm();
  };

  /** 隐藏暂停并标记；回见且开关为开时以驻留音量恢复。 */
  private readonly handleVisibility = (): void => {
    if (document.hidden) {
      if (this.enabled && this.audio && !this.audio.paused) {
        this.systemPaused = true;
        this.cancelVolumeRaf();
        this.audio.pause();
      }
      return;
    }
    if (!this.systemPaused) return;
    this.systemPaused = false;
    if (!this.enabled || !this.audio) return;
    const audio = this.audio;
    audio.volume = VOLUME_DWELL;
    const attempt = audio.play();
    if (attempt && typeof attempt.catch === 'function') {
      attempt.catch(() => this.armAutoplayRecovery());
    }
  };
}

/** 单例：main.ts 直接 import 使用；类类型同时导出便于注释/测试注入。 */
export const soundDesign = new SoundDesign();
