import * as THREE from 'three';

/**
 * v7.1 金尘粒子场 · curl-noise 流场驱动（DESIGN_V7 §4.6 升级）
 *
 * - 顶点着色器内实现 3D simplex 噪声 + 有限差分求旋度（curl noise），
 *   粒子位置是 (basePosition, uTime) 的纯时间函数，GPU 内即时积分，无需 FBO。
 * - 粒子数按硬件分级：high 52000 / mid 26000 / low 8000（回退档）。
 *   运行期滚动帧时监测，持续掉帧自动逐级降档（low 档仍慢则关闭发线层）。
 * - 金色按速度/深度在 #8C6A3F → #E8C98A 插值，加法混合；
 *   点尺寸 1.2–2.8px（乘像素比前），随深度衰减。
 * - 邻近发线「强化」：拓扑仍在 CPU 一次性求解，但线段两端顶点在着色器内
 *   重放与点精灵完全相同的流场位移函数，因此发线实时跟随流场形变；
 *   alpha 随两端点当前距离衰减，远于阈值自然断线 —— 无需屏幕空间后处理。
 * - setProgress(0..1)：驱动湍流强度（噪声采样步幅/位移幅度）与聚散
 *   （开场聚拢 → 中段展开 → 末段向中心回流）。
 * - setFocusDepth(0..1)：v8.0 景深分级——近景颗粒稍大稍亮、远景更小更暗，
 *   焦平面随 t 向近景推移（rack-focus），主循环内阻尼跟随，t=0 时与 v7 一致。
 * - pulse(intensity?)：v7.2 转场联动聚散脉冲——金尘先向心收拢、湍流骤起，
 *   再随 smoothstep 包络释放；也可经 window 事件 'gilt:ambient-pulse' 触发
 *   （main.ts 适配层未转发 pulse 时的桥），reduced-motion 下天然无视觉变化。
 * - 整体绕 Y 缓转 0.04 rad/s + pointer 视差（内部监听 pointermove）。
 * - reduced-motion：冻结噪声时间项，静态星尘，按需渲染。
 * - destroy：dispose 全部 GPU 资源并 forceContextLoss。
 */

// ---------- 性能分级 ----------

type TierName = 'low' | 'mid' | 'high';

interface TierSpec {
  readonly count: number;
  readonly linkSources: number; // 参与发线拓扑的粒子子集规模
  readonly advectSteps: 1 | 2;  // 着色器内二阶平流步数
}

const TIERS: Record<TierName, TierSpec> = {
  low: { count: 8000, linkSources: 1200, advectSteps: 1 },
  mid: { count: 26000, linkSources: 2200, advectSteps: 2 },
  high: { count: 52000, linkSources: 3200, advectSteps: 2 },
};

const TIER_ORDER: readonly TierName[] = ['low', 'mid', 'high'];

const LINK_MAX_DISTANCE = 9;
const LINKS_PER_PARTICLE = 3;
const ROTATION_SPEED = 0.04; // rad/s，绕 Y 轴
// v7.2 转场聚散脉冲：时长（秒）与 DOM 事件桥名（motion.ts 侧字面量保持一致）
const PULSE_DURATION = 1.15;
const PULSE_EVENT = 'gilt:ambient-pulse';
// v8.0 景深分级：焦平面基准深度（aDepth 域）与随 t 向近景的推移量（rack-focus）
const FOCUS_PLANE_BASE = 0.62;
const FOCUS_PLANE_DRIFT = 0.16;
const GOLD_DIM = new THREE.Color('#8C6A3F');
const GOLD_BRIGHT = new THREE.Color('#E8C98A');
const LINE_COLOR = new THREE.Color('#C0924E');

// 帧时监测：预热后按窗口统计平均帧时，超阈值自动降档。
const PERF_WARMUP_FRAMES = 150;
const PERF_WINDOW_FRAMES = 90;
const PERF_DEGRADE_MS = 28 / 1000;

// ---------- GLSL：simplex 噪声 + 旋度 + 流场位移（点/线共享） ----------

const NOISE_GLSL = /* glsl */ `
  // Simplex 3D noise — Ashima Arts / Ian McEwan (MIT)
  vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
  vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
  vec4 permute(vec4 x) { return mod289(((x * 34.0) + 1.0) * x); }
  vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

  float snoise(vec3 v) {
    const vec2 C = vec2(1.0 / 6.0, 1.0 / 3.0);
    const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);

    vec3 i  = floor(v + dot(v, C.yyy));
    vec3 x0 = v - i + dot(i, C.xxx);

    vec3 g = step(x0.yzx, x0.xyz);
    vec3 l = 1.0 - g;
    vec3 i1 = min(g.xyz, l.zxy);
    vec3 i2 = max(g.xyz, l.zxy);

    vec3 x1 = x0 - i1 + C.xxx;
    vec3 x2 = x0 - i2 + C.yyy;
    vec3 x3 = x0 - D.yyy;

    i = mod289(i);
    vec4 p = permute(permute(permute(
              i.z + vec4(0.0, i1.z, i2.z, 1.0))
            + i.y + vec4(0.0, i1.y, i2.y, 1.0))
            + i.x + vec4(0.0, i1.x, i2.x, 1.0));

    float n_ = 0.142857142857;
    vec3 ns = n_ * D.wyz - D.xzx;

    vec4 j = p - 49.0 * floor(p * ns.z * ns.z);

    vec4 x_ = floor(j * ns.z);
    vec4 y_ = floor(j - 7.0 * x_);

    vec4 x = x_ * ns.x + ns.yyyy;
    vec4 y = y_ * ns.x + ns.yyyy;
    vec4 h = 1.0 - abs(x) - abs(y);

    vec4 b0 = vec4(x.xy, y.xy);
    vec4 b1 = vec4(x.zw, y.zw);

    vec4 s0 = floor(b0) * 2.0 + 1.0;
    vec4 s1 = floor(b1) * 2.0 + 1.0;
    vec4 sh = -step(h, vec4(0.0));

    vec4 a0 = b0.xzyw + s0.xzyw * sh.xxyy;
    vec4 a1 = b1.xzyw + s1.xzyw * sh.zzww;

    vec3 p0 = vec3(a0.xy, h.x);
    vec3 p1 = vec3(a0.zw, h.y);
    vec3 p2 = vec3(a1.xy, h.z);
    vec3 p3 = vec3(a1.zw, h.w);

    vec4 norm = taylorInvSqrt(vec4(dot(p0, p0), dot(p1, p1), dot(p2, p2), dot(p3, p3)));
    p0 *= norm.x;
    p1 *= norm.y;
    p2 *= norm.z;
    p3 *= norm.w;

    vec4 m = max(0.6 - vec4(dot(x0, x0), dot(x1, x1), dot(x2, x2), dot(x3, x3)), 0.0);
    m = m * m;
    return 42.0 * dot(m * m, vec4(dot(p0, x0), dot(p1, x1), dot(p2, x2), dot(p3, x3)));
  }

  // 三个去相关的标量噪声组成向量势场
  vec3 noiseVector(vec3 p) {
    return vec3(
      snoise(p),
      snoise(p + vec3(31.416, -47.853, 12.793)),
      snoise(p + vec3(-233.145, 113.093, -185.621))
    );
  }

  // 有限差分求旋度：无散度流场，粒子沿流线漂移
  vec3 curlNoise(vec3 p) {
    const float E = 0.12;
    vec3 n0 = noiseVector(p);
    vec3 dx = (noiseVector(p + vec3(E, 0.0, 0.0)) - n0) / E;
    vec3 dy = (noiseVector(p + vec3(0.0, E, 0.0)) - n0) / E;
    vec3 dz = (noiseVector(p + vec3(0.0, 0.0, E)) - n0) / E;
    return vec3(dy.z - dz.y, dz.x - dx.z, dx.y - dy.x);
  }

  float hash13(vec3 p) {
    p = fract(p * 0.1031);
    p += dot(p, p.zyx + 31.32);
    return fract((p.x + p.y) * p.z);
  }

  uniform float uTime;
  uniform float uTurbulence; // 0..1 湍流强度（setProgress 驱动）
  uniform float uSpread;     // 0..1 聚散（径向缩放，setProgress 驱动）
  uniform float uAmplitude;  // 流场位移幅度（世界单位）
  uniform vec3 uWind;        // 噪声场整体平流方向/速度
  uniform float uNoiseScale;

  // 点精灵与发线端点共享的唯一位移函数：纯 (base, uTime) 决定论。
  vec3 flowPosition(vec3 base, out float speed, out float seed) {
    float h = hash13(base);
    float t = uTime;
    vec3 sampleP = base * uNoiseScale + uWind * t;
    vec3 v = curlNoise(sampleP);
#if ADVECT_STEPS > 1
    // 二阶平流：沿当前速度方向再采样一次，流线更卷曲
    v = mix(v, curlNoise(sampleP + v * (1.6 + uTurbulence * 2.4)), 0.5);
#endif
    speed = clamp(length(v), 0.0, 2.0);
    float amp = uAmplitude * (0.55 + 0.9 * h);
    vec3 pos = base * uSpread + v * amp;
    // 低频呼吸项：平静期仍保持微弱生命力
    pos.y += sin(t * 0.22 + h * 6.2831) * (0.5 + uTurbulence * 1.1);
    seed = h;
    return pos;
  }
`;

const pointsVertexShader = /* glsl */ `
  ${NOISE_GLSL}

  uniform float uPixelRatio;
  uniform float uGlobalAlpha;
  uniform vec3 uGoldDim;
  uniform vec3 uGoldBright;
  uniform float uFocusT;     // v8.0：0..1 景深分级强度（setFocusDepth 驱动）
  uniform float uFocusPlane; // v8.0：焦平面深度（aDepth 域 0..1）

  attribute float aSize;
  attribute float aPhase;
  attribute float aDepth;

  varying float vAlpha;
  varying vec3 vColor;

  void main() {
    float speed;
    float seed;
    vec3 pos = flowPosition(position, speed, seed);
    vec4 mvPosition = modelViewMatrix * vec4(pos, 1.0);
    gl_Position = projectionMatrix * mvPosition;

    float perspective = 150.0 / max(1.0, -mvPosition.z);
    // v8.0 景深分级：近景颗粒稍大稍亮、远景更小更暗；uFocusT=0 时两因子恒 1，
    // 与 v7 视觉完全一致（向后兼容）。
    float focusDelta = aDepth - uFocusPlane;
    float focusNear = smoothstep(0.02, 0.5, focusDelta);
    float focusFar = smoothstep(0.02, 0.6, -focusDelta);
    float focusSize = 1.0 + uFocusT * (0.38 * focusNear - 0.5 * focusFar);
    float focusAlpha = 1.0 + uFocusT * (0.3 * focusNear - 0.58 * focusFar);
    gl_PointSize = clamp(aSize * uPixelRatio * perspective * focusSize, 1.0, 7.0);

    float speedNorm = clamp(speed * 0.5, 0.0, 1.0);
    float twinkle = 0.62 + 0.38 * sin(uTime * (0.4 + aPhase * 0.8) + seed * 6.2831);
    float depthFade = mix(0.45, 1.0, aDepth);
    float distanceFade = smoothstep(-175.0, -30.0, mvPosition.z);

    vAlpha = twinkle * depthFade * (0.42 + 0.58 * speedNorm) * uGlobalAlpha * distanceFade * focusAlpha;
    vColor = mix(uGoldDim, uGoldBright, clamp(aDepth * 0.4 + speedNorm * 0.6, 0.0, 1.0));
  }
`;

const pointsFragmentShader = /* glsl */ `
  varying float vAlpha;
  varying vec3 vColor;

  void main() {
    vec2 uv = gl_PointCoord - 0.5;
    float d = length(uv);
    float disc = 1.0 - smoothstep(0.16, 0.5, d);
    float core = 1.0 - smoothstep(0.0, 0.13, d);
    gl_FragColor = vec4(vColor + core * 0.2, disc * vAlpha);
  }
`;

const linesVertexShader = /* glsl */ `
  ${NOISE_GLSL}

  uniform float uLineOpacity;
  uniform float uLinkMax;

  attribute vec3 aPartner;
  attribute float aBaseAlpha;

  varying float vAlpha;

  void main() {
    float speedSelf;
    float seedSelf;
    vec3 pos = flowPosition(position, speedSelf, seedSelf);
    float speedMate;
    float seedMate;
    vec3 mate = flowPosition(aPartner, speedMate, seedMate);

    // 端点当前距离实时衰减：流场拉开即断线，靠近即重连
    float d = distance(pos, mate);
    float fade = 1.0 - smoothstep(uLinkMax * 0.35, uLinkMax, d);
    float speedGlow = clamp((speedSelf + speedMate) * 0.25, 0.0, 1.0);
    vAlpha = aBaseAlpha * fade * uLineOpacity * (0.5 + 0.5 * speedGlow);

    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
  }
`;

const linesFragmentShader = /* glsl */ `
  uniform vec3 uColor;
  varying float vAlpha;

  void main() {
    gl_FragColor = vec4(uColor, vAlpha);
  }
`;

// ---------- 工具 ----------

function detectTier(): TierName {
  const dpr = window.devicePixelRatio || 1;
  const cores = navigator.hardwareConcurrency ?? 4;
  const memory = (navigator as Navigator & { deviceMemory?: number }).deviceMemory ?? 8;
  const minSide = Math.min(window.innerWidth, window.innerHeight);
  const mobile = minSide < 720 || /Mobi|Android|iPhone|iPad/i.test(navigator.userAgent);
  if (mobile || cores <= 4 || memory <= 4) return 'low';
  if (cores >= 10 && memory >= 8 && dpr <= 2.5 && minSide >= 900) return 'high';
  return 'mid';
}

type ScatterResult = {
  positions: Float32Array;
  sizes: Float32Array;
  phases: Float32Array;
  depths: Float32Array;
};

type LinkTopology = { positions: Float32Array; partners: Float32Array; alphas: Float32Array; count: number };

export class AmbientScene {
  private readonly renderer: THREE.WebGLRenderer;
  private readonly scene = new THREE.Scene();
  private readonly camera = new THREE.PerspectiveCamera(42, 1, 0.1, 280);
  private readonly group = new THREE.Group();

  private tier: TierName;
  private pointsMaterial!: THREE.ShaderMaterial;
  private linesMaterial!: THREE.ShaderMaterial;
  private particleField!: THREE.Points;
  private linkMesh!: THREE.LineSegments;

  private rafId = 0;
  private simTime = 0;
  private lastFrameAt = 0;
  private progress = 0;
  private progressSmooth = 0;
  private reducedMotion = false;
  private needsRender = true;
  private destroyed = false;

  // v7.2 转场聚散脉冲（simTime 锚点 + 增益；pulseStartAt < 0 = 未激活）
  private pulseStartAt = -1;
  private pulseGain = 0;

  // v8.0 景深分级（setFocusDepth 目标值 + 阻尼跟随平滑值）
  private focusDepth = 0;
  private focusDepthSmooth = 0;

  // pointer 视差（内部自管理，不改动对外接口）
  private pointerX = 0;
  private pointerY = 0;
  private pointerTargetX = 0;
  private pointerTargetY = 0;

  // 运行期性能自动降档
  private framesSinceReset = 0;
  private perfAccum = 0;
  private perfSamples = 0;

  constructor(canvas: HTMLCanvasElement) {
    this.renderer = new THREE.WebGLRenderer({
      canvas,
      alpha: true,
      antialias: false,
      powerPreference: 'high-performance',
    });
    this.renderer.setClearColor(0x0b0b0b, 0);
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.camera.position.set(0, 2, 58);
    this.camera.lookAt(0, 0, -18);

    this.group.rotation.x = 0.07;
    this.scene.add(this.group);

    this.tier = detectTier();
    this.buildField(TIERS[this.tier]);

    window.addEventListener('resize', this.resize, { passive: true });
    window.addEventListener('pointermove', this.onPointerMove, { passive: true });
    window.addEventListener(PULSE_EVENT, this.onPulseEvent);
    this.resize();
    this.lastFrameAt = performance.now();
    this.render();
  }

  // ---------- 场景构建（按档位重建，支持运行期降档） ----------

  private buildField(spec: TierSpec): void {
    // 释放上一档资源
    if (this.particleField) {
      this.group.remove(this.particleField);
      this.particleField.geometry.dispose();
      this.pointsMaterial.dispose();
    }
    if (this.linkMesh) {
      this.group.remove(this.linkMesh);
      this.linkMesh.geometry.dispose();
      this.linesMaterial.dispose();
    }

    const { positions, sizes, phases, depths } = this.scatterParticles(spec.count);

    const pointsGeometry = new THREE.BufferGeometry();
    pointsGeometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    pointsGeometry.setAttribute('aSize', new THREE.BufferAttribute(sizes, 1));
    pointsGeometry.setAttribute('aPhase', new THREE.BufferAttribute(phases, 1));
    pointsGeometry.setAttribute('aDepth', new THREE.BufferAttribute(depths, 1));

    this.pointsMaterial = new THREE.ShaderMaterial({
      vertexShader: pointsVertexShader,
      fragmentShader: pointsFragmentShader,
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
      defines: { ADVECT_STEPS: spec.advectSteps },
      uniforms: {
        uTime: { value: this.simTime },
        uPixelRatio: { value: Math.min(window.devicePixelRatio, 2) },
        uTurbulence: { value: 0.3 },
        uSpread: { value: 0.5 },
        uAmplitude: { value: 5.0 },
        uWind: { value: new THREE.Vector3(0.021, 0.013, 0.017) },
        uNoiseScale: { value: 0.028 },
        uGlobalAlpha: { value: this.globalAlphaFor(spec.count) },
        uGoldDim: { value: GOLD_DIM },
        uGoldBright: { value: GOLD_BRIGHT },
        uFocusT: { value: 0 },
        uFocusPlane: { value: FOCUS_PLANE_BASE },
      },
    });
    this.particleField = new THREE.Points(pointsGeometry, this.pointsMaterial);
    this.particleField.frustumCulled = false;

    const topology = this.solveLinks(positions, spec.count, spec.linkSources);
    const linesGeometry = new THREE.BufferGeometry();
    linesGeometry.setAttribute('position', new THREE.BufferAttribute(topology.positions, 3));
    linesGeometry.setAttribute('aPartner', new THREE.BufferAttribute(topology.partners, 3));
    linesGeometry.setAttribute('aBaseAlpha', new THREE.BufferAttribute(topology.alphas, 1));
    this.linesMaterial = new THREE.ShaderMaterial({
      vertexShader: linesVertexShader,
      fragmentShader: linesFragmentShader,
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
      defines: { ADVECT_STEPS: spec.advectSteps },
      uniforms: {
        uTime: { value: this.simTime },
        uTurbulence: { value: 0.3 },
        uSpread: { value: 0.5 },
        uAmplitude: { value: 5.0 },
        uWind: { value: new THREE.Vector3(0.021, 0.013, 0.017) },
        uNoiseScale: { value: 0.028 },
        uLineOpacity: { value: 0.1 },
        uLinkMax: { value: LINK_MAX_DISTANCE * 2.2 },
        uColor: { value: LINE_COLOR },
      },
    });
    this.linkMesh = new THREE.LineSegments(linesGeometry, this.linesMaterial);
    this.linkMesh.frustumCulled = false;
    this.linkMesh.visible = topology.count > 0;

    this.group.add(this.particleField);
    this.group.add(this.linkMesh);

    // 以当前平滑进度立即同步一次视觉状态
    this.applyProgress(1);
    this.needsRender = true;
  }

  /** 粒子越多单点越淡，保持加法混合下的总亮度与留白比例一致。 */
  private globalAlphaFor(count: number): number {
    return THREE.MathUtils.clamp(16 / Math.sqrt(count), 0.07, 0.35);
  }

  /** 低密度椭球壳分布：大量留白，粒子贴深度分层。 */
  private scatterParticles(count: number): ScatterResult {
    const positions = new Float32Array(count * 3);
    const sizes = new Float32Array(count);
    const phases = new Float32Array(count);
    const depths = new Float32Array(count);
    for (let index = 0; index < count; index += 1) {
      const theta = Math.random() * Math.PI * 2;
      const radius = 14 + Math.pow(Math.random(), 0.6) * 46;
      const x = Math.cos(theta) * radius * (0.9 + Math.random() * 0.4);
      const y = Math.sin(theta) * radius * 0.52 * (0.8 + Math.random() * 0.4);
      const z = -85 + Math.random() * 110;
      positions[index * 3] = x;
      positions[index * 3 + 1] = y;
      positions[index * 3 + 2] = z;
      sizes[index] = 1.2 + Math.random() * 1.6; // 1.2 – 2.8 px（乘像素比前）
      phases[index] = Math.random();
      depths[index] = THREE.MathUtils.clamp((z + 85) / 110, 0, 1);
    }
    return { positions, sizes, phases, depths };
  }

  /**
   * 空间哈希一次求解发线拓扑（仅在子集上）：距离阈值内每粒子最多 3 条，
   * aBaseAlpha = 1 - d/dmax。运行时端点距离由着色器实时重算衰减。
   */
  private solveLinks(positions: Float32Array, count: number, linkSources: number): LinkTopology {
    const stride = Math.max(1, Math.floor(count / linkSources));
    const sources: number[] = [];
    for (let index = 0; index < count && sources.length < linkSources; index += stride) {
      sources.push(index);
    }

    const cellSize = LINK_MAX_DISTANCE;
    const cellKey = (x: number, y: number, z: number): string =>
      `${Math.floor(x / cellSize)},${Math.floor(y / cellSize)},${Math.floor(z / cellSize)}`;

    const grid = new Map<string, number[]>();
    for (const index of sources) {
      const key = cellKey(positions[index * 3], positions[index * 3 + 1], positions[index * 3 + 2]);
      const bucket = grid.get(key);
      if (bucket) bucket.push(index);
      else grid.set(key, [index]);
    }

    const degree = new Uint8Array(count);
    const seen = new Set<number>();
    const segmentPositions: number[] = [];
    const segmentPartners: number[] = [];
    const segmentAlphas: number[] = [];
    const maxDistSq = LINK_MAX_DISTANCE * LINK_MAX_DISTANCE;

    for (const index of sources) {
      if (degree[index] >= LINKS_PER_PARTICLE) continue;
      const px = positions[index * 3];
      const py = positions[index * 3 + 1];
      const pz = positions[index * 3 + 2];
      const cx = Math.floor(px / cellSize);
      const cy = Math.floor(py / cellSize);
      const cz = Math.floor(pz / cellSize);
      const candidates: { other: number; distSq: number }[] = [];

      for (let dx = -1; dx <= 1; dx += 1) {
        for (let dy = -1; dy <= 1; dy += 1) {
          for (let dz = -1; dz <= 1; dz += 1) {
            const bucket = grid.get(`${cx + dx},${cy + dy},${cz + dz}`);
            if (!bucket) continue;
            for (const other of bucket) {
              if (other === index || degree[other] >= LINKS_PER_PARTICLE) continue;
              const ox = positions[other * 3] - px;
              const oy = positions[other * 3 + 1] - py;
              const oz = positions[other * 3 + 2] - pz;
              const distSq = ox * ox + oy * oy + oz * oz;
              if (distSq < maxDistSq) candidates.push({ other, distSq });
            }
          }
        }
      }

      candidates.sort((a, b) => a.distSq - b.distSq);
      for (const { other, distSq } of candidates) {
        if (degree[index] >= LINKS_PER_PARTICLE || degree[other] >= LINKS_PER_PARTICLE) break;
        const pairKey = index < other ? index * count + other : other * count + index;
        if (seen.has(pairKey)) continue;
        seen.add(pairKey);
        const alpha = 1 - Math.sqrt(distSq) / LINK_MAX_DISTANCE;
        const ax = positions[other * 3];
        const ay = positions[other * 3 + 1];
        const az = positions[other * 3 + 2];
        // 顶点 A：自身位置 + 伙伴基准位置；顶点 B：镜像
        segmentPositions.push(px, py, pz, ax, ay, az);
        segmentPartners.push(ax, ay, az, px, py, pz);
        segmentAlphas.push(alpha, alpha);
        degree[index] += 1;
        degree[other] += 1;
      }
    }

    return {
      positions: new Float32Array(segmentPositions),
      partners: new Float32Array(segmentPartners),
      alphas: new Float32Array(segmentAlphas),
      count: segmentPositions.length / 6,
    };
  }

  // ---------- 进度驱动：湍流 + 聚散 ----------

  /** 开场聚拢 → 中段展开 → 末段向中心回流；湍流中段峰值。 */
  private applyProgress(blend: number): void {
    this.progressSmooth += (this.progress - this.progressSmooth) * blend;
    const p = this.progressSmooth;
    const swell = Math.sin(p * Math.PI); // 0 → 1 → 0

    // v8.0 景深分级：与 progress 同一阻尼节奏跟随，焦平面随 t 向近景推移。
    this.focusDepthSmooth += (this.focusDepth - this.focusDepthSmooth) * blend;
    this.pointsMaterial.uniforms.uFocusT.value = this.focusDepthSmooth;
    this.pointsMaterial.uniforms.uFocusPlane.value =
      FOCUS_PLANE_BASE + FOCUS_PLANE_DRIFT * this.focusDepthSmooth;

    // v7.2 转场脉冲包络：前 36% 向心收拢（gather 0→1），后 64% 释放回 0，
    // smoothstep 成形；叠加 = spread 下压 + 湍流/发线骤起。reduced-motion 下
    // simTime 冻结，包络恒为 0，不产生视觉变化。
    let envelope = 0;
    if (this.pulseStartAt >= 0) {
      const t = (this.simTime - this.pulseStartAt) / PULSE_DURATION;
      if (t >= 1) {
        this.pulseStartAt = -1;
        this.pulseGain = 0;
      } else {
        const phase = t < .36 ? t / .36 : 1 - (t - .36) / .64;
        envelope = phase * phase * (3 - 2 * phase) * this.pulseGain;
      }
    }

    const spread = Math.max(.3, 0.5 + 0.5 * swell - .18 * envelope); // 聚拢 0.5 → 展开 1.0 → 回流 0.5
    const turbulence = Math.min(1.5, 0.3 + 0.7 * swell + .45 * envelope);
    const amplitude = 4.2 + 9.0 * turbulence;
    const lineOpacity = Math.min(.42, 0.08 + 0.2 * swell + .1 * envelope);

    for (const material of [this.pointsMaterial, this.linesMaterial]) {
      material.uniforms.uSpread.value = spread;
      material.uniforms.uTurbulence.value = turbulence;
      material.uniforms.uAmplitude.value = amplitude;
    }
    this.linesMaterial.uniforms.uLineOpacity.value = lineOpacity;
  }

  // ---------- 事件与主循环 ----------

  private readonly onPointerMove = (event: PointerEvent): void => {
    this.pointerTargetX = (event.clientX / window.innerWidth) * 2 - 1;
    this.pointerTargetY = (event.clientY / window.innerHeight) * 2 - 1;
  };

  /** v7.2：DOM 事件桥——main.ts 适配层未转发 pulse 时由 motion.ts 派发。 */
  private readonly onPulseEvent = (event: Event): void => {
    const detail = event instanceof CustomEvent ? event.detail : null;
    this.pulse(typeof detail === 'number' && Number.isFinite(detail) ? detail : 1);
  };

  private readonly resize = (): void => {
    const width = window.innerWidth;
    const height = window.innerHeight;
    const pixelRatio = Math.min(window.devicePixelRatio, 2);
    this.camera.aspect = width / height;
    this.camera.updateProjectionMatrix();
    this.renderer.setPixelRatio(pixelRatio);
    this.renderer.setSize(width, height, false);
    this.pointsMaterial.uniforms.uPixelRatio.value = pixelRatio;
    this.needsRender = true;
  };

  /** 运行期帧时监测：持续掉帧逐级降档，low 档仍慢则关闭发线层。 */
  private monitorPerformance(delta: number): void {
    this.framesSinceReset += 1;
    if (this.framesSinceReset <= PERF_WARMUP_FRAMES) return;
    this.perfAccum += delta;
    this.perfSamples += 1;
    if (this.perfSamples < PERF_WINDOW_FRAMES) return;
    const avg = this.perfAccum / this.perfSamples;
    this.perfAccum = 0;
    this.perfSamples = 0;
    if (avg <= PERF_DEGRADE_MS) return;

    const currentIndex = TIER_ORDER.indexOf(this.tier);
    if (currentIndex > 0) {
      this.tier = TIER_ORDER[currentIndex - 1];
      this.framesSinceReset = 0;
      this.buildField(TIERS[this.tier]);
    } else if (this.linkMesh.visible) {
      // 已是最低档：关闭发线层进一步减负
      this.linkMesh.visible = false;
    }
  }

  private readonly render = (): void => {
    if (this.destroyed) return;
    this.rafId = requestAnimationFrame(this.render);

    const now = performance.now();
    const delta = Math.min(0.1, (now - this.lastFrameAt) / 1000);
    this.lastFrameAt = now;

    if (this.reducedMotion) {
      // 冻结噪声时间项：静态星尘，仅在进度/尺寸变化时重绘。
      if (!this.needsRender) return;
      this.needsRender = false;
      this.renderer.render(this.scene, this.camera);
      return;
    }

    this.simTime += delta;
    this.monitorPerformance(delta);
    this.applyProgress(0.06);

    // pointer 视差（缓动跟随）
    this.pointerX += (this.pointerTargetX - this.pointerX) * 0.045;
    this.pointerY += (this.pointerTargetY - this.pointerY) * 0.045;
    this.camera.position.x = this.pointerX * 3.2;
    this.camera.position.y = 2 - this.pointerY * 2.0;
    this.camera.lookAt(0, 0, -18);

    this.group.rotation.y = this.simTime * ROTATION_SPEED;
    this.pointsMaterial.uniforms.uTime.value = this.simTime;
    this.linesMaterial.uniforms.uTime.value = this.simTime;

    this.renderer.render(this.scene, this.camera);
  };

  // ---------- 对外接口（既有签名不变；pulse 为 v7.2 增量 API） ----------

  /**
   * v7.2 转场联动：聚散脉冲。金尘先向心收拢、湍流骤起，再随包络释放。
   * intensity ∈ [0, 1.5]：1 = 切页全强度，≈.4 = 幕内节点轻脉冲。
   * 纯增量方法，不改动任何既有行为；reduced-motion 下包络恒 0，天然无变化。
   */
  pulse(intensity = 1): void {
    if (this.destroyed) return;
    this.pulseStartAt = this.simTime;
    this.pulseGain = THREE.MathUtils.clamp(intensity, 0, 1.5);
    this.needsRender = true;
  }

  /**
   * v8.0 景深分级（rack-focus 气质）：t ∈ [0, 1]。
   * t = 0 为 v7 既有均匀观感；t → 1 近景金尘稍大稍亮（尺寸 +38% / alpha +30%）、
   * 远景更小更暗（尺寸 −50% / alpha −58%），焦平面随 t 向近景缓慢推移。
   * 主循环内与 progress 同一阻尼节奏平滑跟随；reduced-motion 下瞬时落位。
   * 纯增量方法，t = 0 时着色器两因子恒 1，视觉与 v7 完全一致。
   */
  setFocusDepth(t: number): void {
    if (this.destroyed) return;
    this.focusDepth = THREE.MathUtils.clamp(t, 0, 1);
    if (this.reducedMotion) {
      // 静态模式下次要参数一次性生效。
      this.focusDepthSmooth = this.focusDepth;
      this.applyProgress(1);
    }
    this.needsRender = true;
  }

  setProgress(progress: number): void {
    this.progress = THREE.MathUtils.clamp(progress, 0, 1);
    if (this.reducedMotion) {
      // 静态模式下进度变化立即一次性生效。
      this.progressSmooth = this.progress;
      this.applyProgress(1);
    }
    this.needsRender = true;
  }

  setReducedMotion(reduced: boolean): void {
    this.reducedMotion = reduced;
    this.lastFrameAt = performance.now();
    if (reduced) {
      // 冻结噪声时间项于当前相位，呈现静态星尘。
      this.pointsMaterial.uniforms.uTime.value = this.simTime;
      this.linesMaterial.uniforms.uTime.value = this.simTime;
    }
    this.needsRender = true;
  }

  destroy(): void {
    this.destroyed = true;
    cancelAnimationFrame(this.rafId);
    window.removeEventListener('resize', this.resize);
    window.removeEventListener('pointermove', this.onPointerMove);
    window.removeEventListener(PULSE_EVENT, this.onPulseEvent);
    this.particleField.geometry.dispose();
    this.pointsMaterial.dispose();
    this.linkMesh.geometry.dispose();
    this.linesMaterial.dispose();
    this.renderer.dispose();
    this.renderer.forceContextLoss();
  }
}
