import { CHAPTERS } from './motion';

/**
 * Forty-node art registry.
 *
 * The reference boards live in `assets/generated/reference-v6.7/` and are never
 * shipped. Runtime uses only the isolated plate + material detail listed here.
 * Replace files with the same names to update art without touching the motion
 * state machine or substantive page copy.
 *
 * v7.0: each figure carries a parallax / wipe-mask / ken-burns wrapper chain
 * plus a bilingual catalogue caption (DESIGN_V7 §3). Plates beyond the first
 * nodes load lazily; the material detail is never mounted on coarse pointers.
 */
export type NodeArtRecord = {
  number: number;
  scene: number;
  key: string;
  direction: string;
  composition: 'right-wide' | 'right-tall' | 'center-wide' | 'center-tall' | 'left-wide' | 'left-tall';
};

