const safeKey = (key: string): string => key.toLowerCase().replace(/[^a-z0-9]+/g, '-');

export function mountNodeArtV67(root: ParentNode = document): void {
  if (root.querySelector('[data-node-art-version="6.7"]')) return;
  const coarsePointer = window.matchMedia('(pointer: coarse)').matches;

  NODE_ART_V67.forEach((record) => {
    const canvas = root.querySelector<HTMLElement>(`.heritage-canvas--${String(record.scene + 1).padStart(2, '0')}`);
    if (!canvas) throw new Error(`Missing heritage canvas for node ${record.number}`);
    const id = String(record.number).padStart(2, '0');
    const plateId = String(record.number).padStart(3, '0');
    const stem = `n${id}-${safeKey(record.key)}`;
    const loading = record.number <= 3 ? 'eager' : 'lazy';
    const chapterName = CHAPTERS[record.scene]?.name ?? '';
    const keyLabel = record.key.toUpperCase();
    const figure = document.createElement('figure');
    figure.className = `node-visual node-visual--v67 node-composition--${record.composition}`;
    figure.dataset.nodeVisual = record.key;
    figure.dataset.nodeNumber = id;
    figure.dataset.nodeArtVersion = '6.7';
    figure.dataset.direction = record.direction;
    figure.setAttribute('aria-hidden', 'true');
    figure.innerHTML = `
      <span class="node-plate-parallax">
        <span class="node-plate-mask">
          <span class="node-plate-kb">
            <img class="node-art node-art--plate" src="./assets/art/v7/nodes/${stem}-plate.webp" alt="" width="1320" height="900" decoding="async" loading="${loading}" draggable="false" />
          </span>
        </span>
        <span class="node-caption">
          <span class="node-caption__frame" aria-hidden="true"><i></i><i></i><i></i><i></i></span>
          <span class="node-caption__en">PLATE ${plateId} / ${keyLabel}</span>
          <span class="node-caption__zh">${chapterName} · ${keyLabel}</span>
        </span>
      </span>
      ${coarsePointer ? '' : `<span class="node-material-swatch" aria-hidden="true">
        <img class="node-art node-art--detail" src="./assets/art/v7/nodes/${stem}-detail.webp" alt="" width="560" height="380" decoding="async" loading="lazy" draggable="false" />
        <i>DETAIL / ${id}</i>
      </span>`}`;
    canvas.append(figure);
  });

  if (root.querySelectorAll('[data-node-art-version="6.7"]').length !== 40) {
    throw new Error('v6.7 node-art registry must mount exactly 40 visual states.');
  }
}
