/**
 * bootChoreo — 「金缮 GILT ARCHIVE」v7.1 Boot 编排。
 *
 * 叙事：黑漆上 GPU 金墨翻涌 → 金缮印章 SVG 描线（stroke-dashoffset）
 *      → 000-100 逐字 odometer 翻滚（每位独立滚轮列，Cormorant 巨字）
 *      → 金墨向中心收束爆开 → 幕布揭开。
 *
 * 总时长 ≈ 3.6s（正常）/ ≈ 1.3s（reduced-motion 静态降级），点击/按键可跳过（4x 快进）。
 * 不修改既有 #boot 静态结构：canvas 缺失时自动创建并前置插入；
 * odometer 滚轮列注入既有 #bootCount 内（id 契约保留）。
 *
 * 接入：playGoldBoot({ onReady, onPhase }) → { kill }，签名与 main.ts 原
 * playBootSequence 完全兼容（onReady 回调 + kill 句柄），onPhase 为新增可选回调。
 */

import gsap from 'gsap';
import { mountGoldFluid, type GoldFluidHandle } from '../webgl/GoldFluid';

export type BootPhase = 'fluid' | 'seal' | 'count' | 'burst' | 'done';

export interface GoldBootOptions {
  /** 编排结束（含兜底快进）后调用，语义等同原 playBootSequence 的 onReady。 */
  onReady: () => void;
  /** 阶段回调：fluid → seal → count → burst → done，供主控衔接 #boot 移除等动作。 */
  onPhase?: (phase: BootPhase) => void;
  /** 缺省读 matchMedia('(prefers-reduced-motion: reduce)')。 */
  reducedMotion?: boolean;
}

export interface GoldBootHandle {
  kill: () => void;
}

interface OdometerReels {
  hundreds: HTMLElement;
  tens: HTMLElement;
  ones: HTMLElement;
  /** 单格像素高（reel 中一个 digit span 的 offsetHeight）。 */
  step: number;
  /** 各位最终位移（格数，非像素）。 */
  finalSteps: { hundreds: number; tens: number; ones: number };
}

const REEL_ONES_DIGITS = Array.from({ length: 4 }, () => '0123456789'.split('')).flat(); // 40 格，转 3 圈
const REEL_TENS_DIGITS = Array.from({ length: 2 }, () => '0123456789'.split('')).flat(); // 20 格，转 1 圈
const REEL_HUNDREDS_DIGITS = ['0', '1'];

function buildOdometer(host: HTMLElement): OdometerReels {
  host.textContent = '';
  host.classList.add('boot__odometer');
  host.setAttribute('aria-label', '100');

  const makeReel = (digits: string[]): HTMLElement => {
    const digit = document.createElement('span');
    digit.className = 'boot__digit';
    digit.setAttribute('aria-hidden', 'true');
    const reel = document.createElement('span');
    reel.className = 'boot__digit-reel';
    for (const d of digits) {
      const cell = document.createElement('span');
      cell.textContent = d;
      reel.appendChild(cell);
    }
    digit.appendChild(reel);
    host.appendChild(digit);
    return reel;
  };

  const hundreds = makeReel(REEL_HUNDREDS_DIGITS);
  const tens = makeReel(REEL_TENS_DIGITS);
  const ones = makeReel(REEL_ONES_DIGITS);
  const firstCell = ones.firstElementChild as HTMLElement | null;
  const step = firstCell ? firstCell.offsetHeight || 1 : 1;
  // 最终显示 100：百位 → 第 2 格（1），十位 → 第 11 格（第二圈 0），个位 → 第 31 格（第四圈 0）
  return { hundreds, tens, ones, step, finalSteps: { hundreds: 1, tens: 10, ones: 30 } };
}

function setReelToFinal(reels: OdometerReels): void {
  gsap.set(reels.hundreds, { y: -reels.finalSteps.hundreds * reels.step });
  gsap.set(reels.tens, { y: -reels.finalSteps.tens * reels.step });
  gsap.set(reels.ones, { y: -reels.finalSteps.ones * reels.step });
}

export function playGoldBoot(options: GoldBootOptions): GoldBootHandle {
  const onReady = options.onReady;
  const emitPhase = (phase: BootPhase): void => {
    try {
      options.onPhase?.(phase);
    } catch (error) {
      console.warn('[Gilt Archive] boot onPhase callback failed.', error);
    }
  };

  const boot = document.querySelector<HTMLElement>('#boot');
  if (!boot) {
    emitPhase('done');
    onReady();
    return { kill: () => undefined };
  }

  const reduced = options.reducedMotion
    ?? window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  boot.classList.add('boot--gold');
  if (reduced) boot.classList.add('boot--reduced');

  /* 流体画布：缺失则自动创建并置于最底层（主控也可在 index.html 中显式插入）。 */
  let canvas = boot.querySelector<HTMLCanvasElement>('#bootFluid');
  if (!canvas) {
    canvas = document.createElement('canvas');
    canvas.id = 'bootFluid';
    canvas.className = 'boot__fluid';
    canvas.setAttribute('aria-hidden', 'true');
    boot.prepend(canvas);
  }

  const fluid: GoldFluidHandle | null = reduced ? null : mountGoldFluid(canvas, { scale: 0.5, idle: true, pointer: true });
  if (!fluid) canvas.style.display = 'none';

  const count = boot.querySelector<HTMLElement>('#bootCount');
  const bar = boot.querySelector<HTMLElement>('#bootBar');
  const readout = boot.querySelector<HTMLElement>('.boot__readout');
  const caption = boot.querySelector<HTMLElement>('.boot__caption');
  const seal = boot.querySelector<HTMLElement>('.boot__seal');
  const sealParts = Array.from(
    boot.querySelectorAll<SVGRectElement | SVGPathElement>('.boot__seal-svg rect, .boot__seal-svg path'),
  );

  const reels = count ? buildOdometer(count) : null;

  let finished = false;
  let killed = false;
  const destroyFluid = (): void => {
    try {
      fluid?.destroy();
    } catch (error) {
      console.warn('[Gilt Archive] GoldFluid destroy failed.', error);
    }
  };

  const timeline = gsap.timeline({ paused: false });

  const finish = (): void => {
    if (finished || killed) return;
    finished = true;
    removeSkipListeners();
    emitPhase('done');
    destroyFluid();
    onReady();
  };

  /* 收束爆开：金墨向中心收拢，最后一团中心爆墨，幕布同时揭开。 */
  const driveConvergence = (): void => {
    if (!fluid) return;
    boot.classList.add('is-bursting');
    const state = { p: 0 };
    gsap.to(state, {
      p: 1,
      duration: 0.5,
      ease: 'power3.in',
      onUpdate: () => {
        const p = state.p;
        for (let k = 0; k < 4; k += 1) {
          const angle = k * (Math.PI / 2) + p * 2.6;
          const r = 0.4 * (1 - p * 0.85);
          const x = 0.5 + r * Math.cos(angle);
          const y = 0.5 + r * Math.sin(angle) * 0.82;
          fluid.splat(x, y, -Math.cos(angle) * 3.2 * (1 - p + 0.25), Math.sin(angle) * 3.2 * (1 - p + 0.25));
        }
      },
      onComplete: () => {
        // 中心爆开：一圈高速外扩金墨
        for (let k = 0; k < 8; k += 1) {
          const angle = (k / 8) * Math.PI * 2;
          fluid.splat(0.5, 0.5, Math.cos(angle) * 4.4, -Math.sin(angle) * 4.4);
        }
        window.setTimeout(() => boot.classList.remove('is-bursting'), 260);
      },
    });
  };

  const onSkip = (): void => {
    if (finished || killed) return;
    removeSkipListeners();
    timeline.timeScale(4);
  };
  const onSkipKey = (event: KeyboardEvent): void => {
    if (event.key === 'Tab') return; // 不劫持焦点导航
    onSkip();
  };
  const removeSkipListeners = (): void => {
    window.removeEventListener('pointerdown', onSkip);
    window.removeEventListener('keydown', onSkipKey);
  };
  window.addEventListener('pointerdown', onSkip, { passive: true });
  window.addEventListener('keydown', onSkipKey);

  if (reduced) {
    /* -------- reduced-motion 静态降级：无流体，印章+计数静态呈现，短驻留后淡出 -------- */
    emitPhase('seal');
    gsap.set(sealParts, { strokeDashoffset: 0 });
    gsap.set(caption, { autoAlpha: 1, y: 0 });
    if (reels) setReelToFinal(reels);
    gsap.set(readout, { autoAlpha: 1, y: 0 });
    if (bar) gsap.set(bar, { scaleX: 1 });
    emitPhase('count');
    timeline
      .to({}, { duration: 0.9 }) // 静态驻留
      .add(() => emitPhase('burst'))
      .to(boot, { autoAlpha: 0, duration: 0.35, ease: 'power1.out' })
      .add(finish);
  } else {
    /* -------- 完整编排：≈ 3.6s -------- */
    timeline
      .add(() => emitPhase('fluid'), 0)
      .add(() => emitPhase('seal'), 0.12)
      // 印章描线（保留原 1.2s 骨架）
      .to(sealParts, { strokeDashoffset: 0, duration: 1.2, stagger: 0.08, ease: 'power2.inOut' }, 0.12)
      .fromTo(caption, { autoAlpha: 0, y: 8 }, { autoAlpha: 1, y: 0, duration: 0.4, ease: 'power2.out' }, 0.35)
      .fromTo(readout, { autoAlpha: 0, y: 10 }, { autoAlpha: 1, y: 0, duration: 0.35, ease: 'power2.out' }, 0.62)
      .add(() => emitPhase('count'), 0.8);

    if (reels) {
      timeline
        .to(reels.ones, { y: -reels.finalSteps.ones * reels.step, duration: 1.5, ease: 'power2.inOut' }, 0.8)
        .to(reels.tens, { y: -reels.finalSteps.tens * reels.step, duration: 1.5, ease: 'power2.inOut' }, 0.9)
        .to(reels.hundreds, { y: -reels.finalSteps.hundreds * reels.step, duration: 1.35, ease: 'power2.inOut' }, 1.0);
    }
    if (bar) timeline.to(bar, { scaleX: 1, duration: 1.5, ease: 'power2.inOut' }, 0.8);

    timeline
      // 退场：印章/眉题上浮，巨字模糊放大
      .to([caption, seal].filter(Boolean), { autoAlpha: 0, y: -10, duration: 0.28, ease: 'power2.in' }, 2.55)
      .to(readout, { scale: 1.14, autoAlpha: 0, filter: 'blur(12px)', duration: 0.3, ease: 'power2.in' }, 2.6)
      // 金墨收束爆开 + 幕布揭开
      .add(() => {
        emitPhase('burst');
        driveConvergence();
      }, 2.72)
      .to(boot, { clipPath: 'inset(0 0 100% 0)', duration: 0.68, ease: 'power4.inOut' }, 2.9)
      .add(finish, 3.6);
  }

  return {
    kill: () => {
      if (killed) return;
      killed = true;
      removeSkipListeners();
      timeline.kill();
      destroyFluid();
      boot.classList.remove('boot--gold', 'boot--reduced', 'is-bursting');
    },
  };
}
