/**
 * cine-core — v8.0 镜头导演系统入口
 * --------------------------------
 * initCine(deps) 装配三个子系统：
 *   CameraDirector  镜头计划 / 入场落幅 / 速度模糊（--cine-* 变量）
 *   FocusRig        焦平面 / rack focus（--cine-bg-* / --cine-fg-* 变量 + WAAPI）
 *   ParallaxField   双源阻尼视差（--pf-* 变量，前/中/后三档）
 *
 * 三者共用同一个 gsap.ticker 回调（RAF 统一，挂在全站既有全局循环上），
 * transform/opacity/filter 全部落在运行时新建的 .cine-rig 包装层上，
 * 不触碰 main.ts / motion.ts 管理的任何元素属性。
 *
 * 接线（由主代理完成，二选一或并存）：
 *   1) 直接调用返回的 controller：
 *        const cine = initCine({ reducedMotion: motionPreference.reduced });
 *        motion.onActiveNode((scene, key, localIndex, flat) =>
 *          cine.setActiveNode(scene, key, localIndex, flat));
 *        motionPreference.subscribe((r) => cine.setReducedMotion(r));
 *        // pagehide 里：cine.destroy()
 *   2) 或广播 CustomEvent（motion.ts 当前未广播，属可选前向兼容）：
 *        window.dispatchEvent(new CustomEvent('gilt:scene-progress',
 *          { detail: { scene, t } }));
 *        window.dispatchEvent(new CustomEvent('gilt:active-node',
 *          { detail: { scene, nodeKey, localIndex, flatIndex } }));
 */

import gsap from 'gsap';
import { SCENE_NODE_KEYS } from '../motion';
import '../style-cine.css';
import {
  CameraDirector,
  buildSceneRigs,
  unwrapSceneRigs,
  type CineEnvironment,
  type CineSceneRig,
} from './CameraDirector';
import { FocusRig } from './FocusRig';
import { ParallaxField } from './ParallaxField';

/* ------------------------------------------------------------------ 契约 */

export const CINE_SCENE_PROGRESS_EVENT = 'gilt:scene-progress';
export const CINE_ACTIVE_NODE_EVENT = 'gilt:active-node';

export interface CineSceneProgressDetail {
  /** 幕序号 0-9。 */
  scene: number;
  /** 幕内进度 0..1。 */
  t: number;
}

export interface CineActiveNodeDetail {
  scene: number;
  nodeKey: string;
  localIndex: number;
  flatIndex: number;
}

export interface CineDeps {
  /** 场景容器，默认 #experience。 */
  experience?: HTMLElement;
  /** 十幕元素；默认按 data-scene 排序查询 '.scene[data-scene]'。 */
  scenes?: HTMLElement[];
  /** 初始 reduced-motion；缺省读 html.reduced-motion 类与系统媒体查询。 */
  reducedMotion?: boolean;
  /** 强制移动端降级；缺省 matchMedia('(max-width: 760px)')。 */
  mobile?: boolean;
  /** 每幕节点数（节点→幕内进度换算）；缺省取自 motion.SCENE_NODE_KEYS。 */
  sceneNodeCounts?: number[];
}

export interface CineController {
  /**
   * 连续幕内进度（镜头计划的直接驱动）。
   * scene: 0-9；t: 0..1。只对当前直播幕生效，其余幕调用被忽略。
   */
  setSceneProgress(scene: number, t: number): void;
  /**
   * 节点切换（离散驱动，主代理在 motion.onActiveNode 内转发）：
   * 自动换算幕内进度 t = localIndex / (幕内节点数 - 1)，
   * 同幕切换触发 FocusRig rack focus，跨幕切换触发镜头落幅 + 焦平面重建。
   */
  setActiveNode(scene: number, nodeKey: string, localIndex: number, flatIndex: number): void;
  /** reduced-motion 切换：全部运动静止 / 恢复。 */
  setReducedMotion(reduced: boolean): void;
  /** 还原 DOM、摘掉 ticker 与监听器（bfcache pagehide 时调用）。 */
  destroy(): void;
}

/* ------------------------------------------------------------------ 装配 */

let activeController: CineController | null = null;

export function initCine(deps: CineDeps = {}): CineController {
  // 重复初始化（如 bfcache 重建）先拆旧实例，保证 DOM 只有一套 rig。
  activeController?.destroy();

  const experience = deps.experience ?? document.querySelector<HTMLElement>('#experience') ?? document.body;
  const scenes = deps.scenes
    ?? Array.from(document.querySelectorAll<HTMLElement>('.scene[data-scene]'))
      .sort((a, b) => Number(a.dataset.scene) - Number(b.dataset.scene));
  const counts = deps.sceneNodeCounts ?? SCENE_NODE_KEYS.map((keys) => keys.length);
  const totalNodes = counts.reduce((sum, count) => sum + count, 0);

  const env: CineEnvironment = {
    mobile: deps.mobile ?? window.matchMedia('(max-width: 760px)').matches,
    reducedMotion: deps.reducedMotion
      ?? (document.documentElement.classList.contains('reduced-motion')
        || window.matchMedia('(prefers-reduced-motion: reduce)').matches),
    // QA 截图链路：镜头落幅瞬时完成，保证截图是稳态画面。
    qaMode: new URLSearchParams(window.location.search).has('qa'),
  };

  const rigs: CineSceneRig[] = buildSceneRigs(scenes);
  const camera = new CameraDirector(rigs, env);
  const focus = new FocusRig(rigs, env);
  const parallax = new ParallaxField(rigs, env);

  let liveScene = -1;
  let lastNodeKey: string | undefined;

  const markLive = (scene: number): void => {
    rigs.forEach((rig) => rig.rig.classList.toggle('is-cine-live', rig.sceneIndex === scene));
  };

  const activateScene = (scene: number, t: number): void => {
    camera.setActiveScene(scene, t);
    focus.setActiveScene(scene);
    parallax.setActiveScene(scene);
    markLive(scene);
    liveScene = scene;
  };

  const clampScene = (scene: number): number =>
    Math.min(rigs.length - 1, Math.max(0, Math.round(scene)));

  const controller: CineController = {
    setSceneProgress(scene, t) {
      if (!Number.isFinite(scene) || !Number.isFinite(t)) return;
      camera.setSceneProgress(clampScene(scene), Math.min(1, Math.max(0, t)));
    },

    setActiveNode(scene, nodeKey, localIndex, flatIndex) {
      const target = clampScene(scene);
      const count = counts[target] ?? 1;
      const t = count > 1
        ? Math.min(1, Math.max(0, localIndex / (count - 1)))
        : 0;
      parallax.setScrollProgress(totalNodes > 1 ? flatIndex / (totalNodes - 1) : 0);
      if (target !== liveScene) {
        // 跨幕：镜头落幅接管焦点重建，新幕主体由虚入清收尾。
        activateScene(target, t);
        focus.rackFocus(target, nodeKey);
      } else {
        camera.setSceneProgress(target, t);
        if (lastNodeKey !== undefined && lastNodeKey !== nodeKey) {
          focus.rackFocus(target, nodeKey, lastNodeKey);
        }
      }
      lastNodeKey = nodeKey;
    },

    setReducedMotion(reduced) {
      camera.setReducedMotion(reduced);
      focus.setReducedMotion(reduced);
      parallax.setReducedMotion(reduced);
    },

    destroy() {
      window.removeEventListener(CINE_SCENE_PROGRESS_EVENT, handleProgressEvent);
      window.removeEventListener(CINE_ACTIVE_NODE_EVENT, handleNodeEvent);
      gsap.ticker.remove(tick);
      camera.destroy();
      focus.destroy();
      parallax.destroy();
      rigs.forEach((rig) => rig.rig.classList.remove('is-cine-live'));
      unwrapSceneRigs(rigs);
      liveScene = -1;
      if (activeController === controller) activeController = null;
    },
  };

  /* 统一 RAF：单回调驱动三个子系统，挂在全站既有的 gsap.ticker 上。 */
  const tick = (_time: number, deltaTime: number): void => {
    const dt = Math.min(Math.max(deltaTime / 1000, 0), 0.1);
    if (dt <= 0) return;
    camera.update(dt);
    parallax.update(dt);
  };
  gsap.ticker.add(tick);

  /* 可选事件桥：motion.ts 目前不广播这两个事件，保留前向兼容。 */
  const handleProgressEvent = (event: Event): void => {
    const detail = (event as CustomEvent<CineSceneProgressDetail>).detail;
    if (!detail) return;
    controller.setSceneProgress(detail.scene, detail.t);
  };
  const handleNodeEvent = (event: Event): void => {
    const detail = (event as CustomEvent<CineActiveNodeDetail>).detail;
    if (!detail) return;
    controller.setActiveNode(detail.scene, detail.nodeKey, detail.localIndex, detail.flatIndex);
  };
  window.addEventListener(CINE_SCENE_PROGRESS_EVENT, handleProgressEvent);
  window.addEventListener(CINE_ACTIVE_NODE_EVENT, handleNodeEvent);

  /* 初始幕：与 motion 的当前幕对齐（缺省首幕），入场落幅自此开始。 */
  const initial = clampScene(Number(experience.dataset.scene ?? 0) || 0);
  activateScene(initial, 0);

  activeController = controller;
  return controller;
}

export type { CineEnvironment, CineSceneRig } from './CameraDirector';
export { SHOT_PLANS } from './CameraDirector';
export { FOCAL_SPECS } from './FocusRig';
export { TIER_SPEED } from './ParallaxField';
