/**
 * cine-core / CameraDirector — v8.0 镜头导演
 * ----------------------------------------
 * 为十幕各定义一条镜头计划（推近 / 拉远 / 横移 / 升降 + 视觉中心），
 * 通过 CSS 变量 --cine-scale / --cine-x / --cine-y / --cine-blur 驱动
 * 每幕的 .cine-rig 包裹层（只包媒体层：巨字 / 金缮 / heritage-canvas，
 * 正文 .scene__inner 一律不包）。
 *
 * 运动学：不挂 GSAP tween，改为在共享 gsap.ticker 内做指数阻尼
 * （current += (target - current) * (1 - e^(-dt/τ))），天然形成
 * cubic-bezier(.2,.6,0,1) 式的缓出镜头语言；入场落幅 2.5s（移动端）
 * ~ 3.6s（桌面端），开场主体自 1.2x 缓速回落到 1.0。
 *
 * 进度源：motion.ts 当前不广播 'gilt:scene-progress'，本模块只暴露
 * setSceneProgress(scene, t) / setActiveScene(scene, t)，由 index.ts
 * 统一接线（主代理在 motion.onActiveNode 里转发，或未来广播事件）。
 */

/* ------------------------------------------------------------------ 类型 */

export interface CineEnvironment {
  /** 移动端降级：所有镜头幅度减半、禁用速度模糊。 */
  mobile: boolean;
  /** reduced-motion：镜头全部静止（neutral 姿态，不再逐帧写入）。 */
  reducedMotion: boolean;
  /** QA 截图模式：入场落幅瞬时完成，避免截到半程姿态。 */
  qaMode: boolean;
}

/** 一幕的运行时包裹结构（由 buildSceneRigs 动态创建）。 */
export interface CineSceneRig {
  sceneIndex: number;
  scene: HTMLElement;
  rig: HTMLElement;
  /** 背景层（远景）：.scene__giant 巨字。 */
  bg: HTMLElement;
  /** 中景层：.heritage-canvas（.scene__media / .scene-art-code）。 */
  mid: HTMLElement;
  /** 前景层：svg.kintsugi 金缮裂缝。 */
  fg: HTMLElement;
  giant: HTMLElement | null;
  kintsugi: SVGSVGElement | null;
  media: HTMLElement | null;
}

export interface CameraPose {
  scale: number;
  /** 视口宽百分比（vw），写入 --cine-x。 */
  x: number;
  /** 视口高百分比（vh），写入 --cine-y。 */
  y: number;
  /** px，写入 --cine-blur；计划内恒为 0，运行时由镜头速度短时注入。 */
  blur: number;
}

interface ShotKeyframe extends CameraPose {
  /** 幕内进度 0..1。 */
  at: number;
}

export interface ShotPlan {
  scene: number;
  /** 叙事意图（建立场景 / 引导注意 / 提升强度 / 交接下一幕）。 */
  intent: string;
  /** 视觉中心（transform-origin，%）。相邻幕共享或近共享同一中心以形成连续。 */
  center: [number, number];
  /** 入场起始倍率：首幕 1.2（全站开场回落），其余幕 1.12（克制的落幅）。 */
  entryScale: number;
  keys: ShotKeyframe[];
}

