/* ------------------------------------------------------------------ DOM 构建
   每幕把三个装饰/媒体层（巨字 / 金缮 / heritage-canvas）移入新建的
   .cine-rig > .cine-depth 包装。原元素的选择器、内联 GSAP 动画、
   CSS 定位全部不变——它们相对的新父盒与原 .scene 盒完全同构
   （absolute inset:0）。正文 .scene__inner 不参与包裹。 */

const createLayer = (className: string): HTMLElement => {
  const element = document.createElement('div');
  element.className = className;
  element.setAttribute('aria-hidden', 'true');
  return element;
};

export function buildSceneRigs(scenes: HTMLElement[]): CineSceneRig[] {
  const rigs: CineSceneRig[] = [];
  scenes.forEach((scene, sceneIndex) => {
    const giant = scene.querySelector<HTMLElement>(':scope > .scene__giant');
    const kintsugi = scene.querySelector<SVGSVGElement>(':scope > svg.kintsugi');
    const media = scene.querySelector<HTMLElement>(':scope > .scene__media');

    const rig = createLayer('cine-rig');
    rig.dataset.cineRig = String(sceneIndex);
    const bg = createLayer('cine-depth cine-depth--bg');
    const fg = createLayer('cine-depth cine-depth--fg');
    const mid = createLayer('cine-depth cine-depth--mid');

    // 插在 .scene__inner 之前：DOM 顺序与 z-index 双重保证正文永远在上。
    const anchor = scene.querySelector<HTMLElement>(':scope > .scene__inner');
    scene.insertBefore(rig, anchor ?? null);
    if (giant) bg.append(giant);
    if (kintsugi) fg.append(kintsugi);
    if (media) mid.append(media);
    rig.append(bg, fg, mid);

    rigs.push({ sceneIndex, scene, rig, bg, mid, fg, giant, kintsugi, media });
  });
  return rigs;
}

/** destroy 还原：把三层按原顺序移回 .scene 并移除包装。 */
export function unwrapSceneRigs(rigs: CineSceneRig[]): void {
  rigs.forEach(({ scene, rig, giant, kintsugi, media }) => {
    if (giant) scene.insertBefore(giant, rig);
    if (kintsugi) scene.insertBefore(kintsugi, rig);
    if (media) scene.insertBefore(media, rig);
    rig.remove();
  });
}

/* ------------------------------------------------------------------ 导演 */

const NEUTRAL_POSE: CameraPose = { scale: 1, x: 0, y: 0, blur: 0 };

/** 指数阻尼：帧率无关。 */
const damp = (current: number, target: number, tau: number, dt: number): number => {
  const k = 1 - Math.exp(-dt / Math.max(tau, 1e-3));
  return current + (target - current) * k;
};

const lerp = (a: number, b: number, t: number): number => a + (b - a) * t;

export class CameraDirector {
  private readonly rigs: CineSceneRig[];
  private env: CineEnvironment;
  private liveScene = -1;
  private current: CameraPose = { ...NEUTRAL_POSE };
  private target: CameraPose = { ...NEUTRAL_POSE };
  private blur = 0;
  private progressT = 0;
  private settleLeft = 0;
  private settled = true;
  private neutralApplied = false;

  constructor(rigs: CineSceneRig[], env: CineEnvironment) {
    this.rigs = rigs;
    this.env = env;
  }

  /** 当前直播幕的镜头计划（越界回退到首幕）。 */
  private plan(scene: number): ShotPlan {
    return SHOT_PLANS[scene] ?? SHOT_PLANS[0];
  }

  /** 计划姿态 → 运行姿态：移动端幅度减半（倍率的超出部分减半）。 */
  private applyAmplitude(pose: CameraPose): CameraPose {
    if (!this.env.mobile) return pose;
    return {
      scale: 1 + (pose.scale - 1) * 0.5,
      x: pose.x * 0.5,
      y: pose.y * 0.5,
      blur: pose.blur * 0.5,
    };
  }

  private poseAt(plan: ShotPlan, t: number): CameraPose {
    const clamped = Math.min(1, Math.max(0, t));
    const keys = plan.keys;
    const sample = (key: ShotKeyframe): CameraPose =>
      this.applyAmplitude({ scale: key.scale, x: key.x, y: key.y, blur: 0 });
    if (clamped <= keys[0].at) return sample(keys[0]);
    for (let index = 1; index < keys.length; index += 1) {
      const b = keys[index];
      if (clamped > b.at) continue;
      const a = keys[index - 1];
      const local = b.at === a.at ? 1 : (clamped - a.at) / (b.at - a.at);
      return this.applyAmplitude({
        scale: lerp(a.scale, b.scale, local),
        x: lerp(a.x, b.x, local),
        y: lerp(a.y, b.y, local),
        blur: 0,
      });
    }
    return sample(keys[keys.length - 1]);
  }

  /** 把姿态写入直播幕 rig 的 CSS 变量（仅超阈值时写，避免样式抖动）。 */
  private write(pose: CameraPose, blur: number): void {
    const rig = this.rigs[this.liveScene]?.rig;
    if (!rig) return;
    rig.style.setProperty('--cine-scale', pose.scale.toFixed(4));
    rig.style.setProperty('--cine-x', `${pose.x.toFixed(3)}vw`);
    rig.style.setProperty('--cine-y', `${pose.y.toFixed(3)}vh`);
    rig.style.setProperty('--cine-blur', `${blur.toFixed(2)}px`);
  }

  private resetRig(rig: CineSceneRig | undefined): void {
    if (!rig) return;
    rig.rig.style.setProperty('--cine-scale', '1');
    rig.rig.style.setProperty('--cine-x', '0vw');
    rig.rig.style.setProperty('--cine-y', '0vh');
    rig.rig.style.setProperty('--cine-blur', '0px');
  }

  /**
   * 幕激活：从入场姿态（entryScale，首幕 1.2x）落幅到计划姿态，
   * 入场平移继承上一幕的出口 x/y 的一半（运动匹配，转场遮盖残余差）。
   */
  setActiveScene(scene: number, t = 0): void {
    if (scene === this.liveScene) return;
    this.resetRig(this.rigs[this.liveScene]);
    this.liveScene = scene;
    const plan = this.plan(scene);
    const rig = this.rigs[scene];
    if (!rig) return;
    rig.rig.style.setProperty('--cine-origin', `${plan.center[0]}% ${plan.center[1]}%`);
    this.progressT = Math.min(1, Math.max(0, t));
    this.target = this.poseAt(plan, this.progressT);
    const entry = this.applyAmplitude({
      scale: plan.entryScale,
      x: lerp(this.current.x, this.target.x, 0.5),
      y: lerp(this.current.y, this.target.y, 0.5),
      blur: 0,
    });
    this.current = this.env.qaMode || this.env.reducedMotion ? { ...this.target } : entry;
    this.settleLeft = this.env.qaMode ? 0 : this.env.mobile ? 2.5 : 3.6;
    this.settled = false;
    this.neutralApplied = false;
    if (this.env.reducedMotion) {
      this.applyNeutral();
      return;
    }
    this.write(this.current, this.blur);
  }

  /** 幕内进度 0..1（连续源或节点换算的离散目标）。 */
  setSceneProgress(scene: number, t: number): void {
    if (scene !== this.liveScene) return;
    this.progressT = Math.min(1, Math.max(0, t));
    this.target = this.poseAt(this.plan(scene), this.progressT);
    this.settled = false;
    this.neutralApplied = false;
  }

  /** reduced-motion：全部静止为 neutral 姿态。 */
  setReducedMotion(reduced: boolean): void {
    this.env = { ...this.env, reducedMotion: reduced };
    if (reduced) this.applyNeutral();
    else this.settled = false;
  }

  private applyNeutral(): void {
    this.current = { ...NEUTRAL_POSE };
    this.target = { ...NEUTRAL_POSE };
    this.blur = 0;
    this.rigs.forEach((rig) => this.resetRig(rig));
    this.settled = true;
    this.neutralApplied = true;
  }

  /** 共享 ticker 驱动（index.ts 挂 gsap.ticker）。dt 单位秒。 */
  update(dt: number): void {
    if (this.env.reducedMotion) {
      if (!this.neutralApplied) this.applyNeutral();
      return;
    }
    if (this.liveScene < 0 || this.settled) return;

    const settle = this.settleLeft > 0;
    if (settle) this.settleLeft = Math.max(0, this.settleLeft - dt);
    // 落幅期 τ≈settle/4（≈98% 收敛），常规期桌面 .8s / 移动 .55s。
    const tau = settle
      ? (this.env.mobile ? 2.5 : 3.6) / 4
      : this.env.mobile ? 0.55 : 0.8;

    const prev = this.current;
    this.current = {
      scale: damp(prev.scale, this.target.scale, tau, dt),
      x: damp(prev.x, this.target.x, tau, dt),
      y: damp(prev.y, this.target.y, tau, dt),
      blur: 0,
    };

    // 速度模糊：镜头运动中注入短促受控的 blur，停稳即归零。
    if (!this.env.mobile && dt > 0) {
      const speed = (Math.abs(this.current.scale - prev.scale) * 6
        + (Math.abs(this.current.x - prev.x) + Math.abs(this.current.y - prev.y)) * 0.5) / dt;
      const blurTarget = Math.min(1.2, Math.max(0, speed));
      this.blur = damp(this.blur, blurTarget, 0.12, dt);
      if (this.blur < 0.04 && blurTarget === 0) this.blur = 0;
    } else {
      this.blur = 0;
    }

    // 收敛判定：完全停稳后锁死为目标值，正文阅读期间镜头绝对静止。
    const done = this.settleLeft === 0
      && Math.abs(this.current.scale - this.target.scale) < 4e-4
      && Math.abs(this.current.x - this.target.x) < 0.01
      && Math.abs(this.current.y - this.target.y) < 0.01;
    if (done) {
      this.current = { ...this.target };
      this.blur = 0;
      this.settled = true;
    }
    this.write(this.current, this.blur);
  }

  destroy(): void {
    this.rigs.forEach((rig) => this.resetRig(rig));
    this.liveScene = -1;
  }
}

export { SHOT_PLANS };
