import gsap from 'gsap';
import { CustomEase } from 'gsap/CustomEase';
import type { NodeChangeReason } from './motion';

/**
 * v7.2 十幕定制数据可视化（全部手工 inline SVG / DOM，无图表库）。
 * v7.2：s01 弧线上缘呼吸间距加宽；sparkline 点位内收防溢出；
 *       出海大数启用千分位；版式变体扩至 7 种新增（band / orbit / scatter）。
 *
 * 交接：
 * - mountSceneViz() 在 init() 中紧随 mountNodeArtV67() 调用，幂等。
 * - syncSceneViz(scene, key, localIndex, reason) 在 applyNodeContent 之后调用：
 *   更新 scene dataset.composition（版式变体切换）并重绘当前幕可视化。
 * - destroySceneViz() 在 pagehide(persisted) 销毁路径调用，杀掉全部 GSAP 时间线。
 * - reduced-motion：读取 documentElement.reduced-motion（main.ts 总线写入），
 *   直接写终态，不做任何绘制/计数动画。
 * - 数据口径与 main.ts 十个事实 Record 完全一致（仅复制数值，不改文案）。
 */

gsap.registerPlugin(CustomEase);
if (!gsap.parseEase('vizMuseum')) CustomEase.create('vizMuseum', '0.18, 0.02, 0.16, 1');
if (!gsap.parseEase('vizWipe')) CustomEase.create('vizWipe', '0.72, 0, 0.22, 1');

const SVG_NS = 'http://www.w3.org/2000/svg';

type Attrs = Record<string, string | number>;

const svgEl = <K extends keyof SVGElementTagNameMap>(tag: K, attrs: Attrs = {}): SVGElementTagNameMap[K] => {
  const el = document.createElementNS(SVG_NS, tag);
  Object.entries(attrs).forEach(([name, value]) => el.setAttribute(name, String(value)));
  return el;
};

const htmlEl = <K extends keyof HTMLElementTagNameMap>(tag: K, className = '', text = ''): HTMLElementTagNameMap[K] => {
  const el = document.createElement(tag);
  if (className) el.className = className;
  if (text) el.textContent = text;
  return el;
};

const pt = (n: number): string => String(Math.round(n * 10) / 10);

const polar = (cx: number, cy: number, r: number, deg: number): [number, number] => {
  const rad = (deg * Math.PI) / 180;
  return [cx + r * Math.cos(rad), cy - r * Math.sin(rad)];
};

const isReduced = (): boolean =>
  document.documentElement.classList.contains('reduced-motion')
  || window.matchMedia('(prefers-reduced-motion: reduce)').matches;

/** 容器骨架：新 id + .scene-viz 类 + 双语 micro 标签行。 */
const vizShell = (id: string, modifier: string, en: string, zh: string): HTMLElement => {
  const root = htmlEl('div', `scene-viz ${modifier}`);
  root.id = id;
  root.dataset.sceneViz = '';
  root.setAttribute('aria-hidden', 'true');
  const label = htmlEl('p', 'scene-viz__label');
  label.append(htmlEl('span', 'scene-viz__label-en', en));
  const zhSpan = htmlEl('span', 'scene-viz__label-zh', zh);
  zhSpan.dataset.labelZh = '';
  label.append(zhSpan);
  root.append(label);
  return root;
};

const setLabelZh = (root: HTMLElement, text: string): void => {
  const el = root.querySelector<HTMLElement>('[data-label-zh]');
  if (el) el.textContent = text;
};

/** count-up：animate=false 时直接写终态。 */
const countUp = (
  el: Element | null,
  target: number,
  format: (n: number) => string,
  tl: gsap.core.Timeline,
  animate: boolean,
  at = 0,
  duration = 1,
): void => {
  if (!el) return;
  if (!animate) { el.textContent = format(target); return; }
  const state = { v: 0 };
  el.textContent = format(0);
  tl.to(state, {
    v: target,
    duration,
    ease: 'power2.out',
    onUpdate: () => { el.textContent = format(state.v); },
  }, at);
};

/** dashoffset 生长：元素需带 pathLength=100 + CSS stroke-dasharray:100。 */
const drawIn = (
  targets: gsap.TweenTarget,
  tl: gsap.core.Timeline,
  at: number,
  animate: boolean,
  duration = 1,
  stagger = 0.09,
): void => {
  if (!animate) { gsap.set(targets, { strokeDashoffset: 0 }); return; }
  tl.fromTo(targets, { strokeDashoffset: 100 }, { strokeDashoffset: 0, duration, stagger, ease: 'vizMuseum' }, at);
};

type VizUpdate = (
  root: HTMLElement,
  key: string,
  localIndex: number,
  tl: gsap.core.Timeline,
  animate: boolean,
  entering: boolean,
) => void;

type SceneViz = { build: () => HTMLElement; update: VizUpdate };

/* ============================================================ 01 年代弧线 */
const ERA_YEARS = ['2003', '2008', '2016', '2023', '2026'] as const;
const ERA_ARC_D = 'M30 150 A140 140 0 0 1 310 150';

const buildEraArc = (): HTMLElement => {
  const root = vizShell('vizEraArc', 'scene-viz--era', 'ERA ARC', '年代弧线');
  // v7.2：viewBox 上缘 -18 → -27，2016 顶刻度与上方展签编目行留出 ~8-12px 呼吸间距。
  const svg = svgEl('svg', { viewBox: '-16 -27 372 201' });
  svg.append(svgEl('path', { d: ERA_ARC_D, pathLength: 100, class: 'viz-track', 'data-draw': '', 'data-arc-track': '' }));
  svg.append(svgEl('path', { d: ERA_ARC_D, pathLength: 100, class: 'viz-era__progress', 'data-progress': '' }));
  ERA_YEARS.forEach((year, index) => {
    const angle = 180 - index * 45;
    const [tx, ty] = polar(170, 150, 140, angle);
    const [lx, ly] = polar(170, 150, 163, angle);
    const tick = svgEl('g', { class: 'viz-era__tick', 'data-tick': index });
    tick.append(svgEl('circle', { cx: pt(tx), cy: pt(ty), r: 3, class: 'viz-era__dot' }));
    const label = svgEl('text', { x: pt(lx), y: pt(ly + 3.5), class: 'viz-era__year', 'text-anchor': 'middle' });
    label.textContent = year;
    tick.append(label);
    svg.append(tick);
  });
  root.append(svg);
  return root;
};

const updateEraArc: VizUpdate = (root, _key, localIndex, tl, animate, entering) => {
  const progress = root.querySelector<SVGPathElement>('[data-progress]');
  const ticks = Array.from(root.querySelectorAll<SVGGElement>('[data-tick]'));
  const target = 100 - (localIndex / (ERA_YEARS.length - 1)) * 100;
  if (progress) {
    if (animate) tl.fromTo(progress, { strokeDashoffset: 100 }, { strokeDashoffset: target, duration: 1.1, ease: 'vizMuseum' }, entering ? .3 : 0);
    else gsap.set(progress, { strokeDashoffset: target });
  }
  ticks.forEach((tick, index) => {
    tick.classList.toggle('is-active', index === localIndex);
    tick.classList.toggle('is-past', index < localIndex);
  });
  if (!animate) return;
  if (entering) {
    const track = root.querySelector('[data-arc-track]');
    if (track) tl.fromTo(track, { strokeDashoffset: 100 }, { strokeDashoffset: 0, duration: 1, ease: 'vizMuseum' }, 0);
    const labels = ticks.map((tick) => tick.querySelector('text')).filter((el): el is SVGTextElement => Boolean(el));
    tl.fromTo(labels, { autoAlpha: 0 }, { autoAlpha: 1, duration: .5, stagger: .07, ease: 'power2.out' }, .25);
  }
  const dot = ticks[localIndex]?.querySelector('circle');
  if (dot) tl.fromTo(dot, { attr: { r: 3 } }, { attr: { r: 4.8 }, duration: .55, ease: 'vizWipe' }, .38);
};

