/**
 * 40 节点版式分配（scene dataset.composition 切换）。
 * 6 种既有展签构图 + 7 种新增（monument / diagonal / stack / halo，
 * v7.2 再增 band 横向时间带 / orbit 径向刻度环 / scatter 散点星座），
 * 全序列无一处相邻重复（含跨幕衔接），满足「不超过 3 连续同构图」。
 * 注意：新变体只落在 scene__primary 居左的节点上（对照 style-v7.css
 * 左侧构图节点右移清单逐一核对），不与右移文本块相撞。
 */
const COMPOSITIONS: readonly (readonly string[])[] = [
  ['right-wide', 'diagonal', 'right-tall', 'band', 'stack'],
  ['right-tall', 'stack', 'center-wide', 'orbit', 'right-tall'],
  ['right-wide', 'halo', 'right-tall', 'left-wide', 'scatter'],
  ['center-wide', 'orbit', 'diagonal'],
  ['band', 'stack'],
  ['right-wide', 'halo', 'scatter', 'monument'],
  ['right-wide', 'left-tall', 'orbit', 'diagonal'],
  ['left-wide', 'scatter', 'right-wide', 'monument'],
  ['halo', 'center-wide', 'orbit', 'left-wide'],
  ['right-wide', 'left-wide', 'band', 'monument'],
];

type MountedViz = { root: HTMLElement; tl: gsap.core.Timeline | null };

const mounted = new Map<number, MountedViz>();
let lastScene = -1;
let bootObserver: MutationObserver | null = null;
let bootArgs: { scene: number; key: string; localIndex: number; reason: NodeChangeReason } | null = null;

const armBootSync = (scene: number, key: string, localIndex: number, reason: NodeChangeReason): void => {
  bootArgs = { scene, key, localIndex, reason };
  if (bootObserver) return;
  bootObserver = new MutationObserver(() => {
    if (document.body.classList.contains('is-loading')) return;
    bootObserver?.disconnect();
    bootObserver = null;
    const args = bootArgs;
    bootArgs = null;
    if (args) syncSceneViz(args.scene, args.key, args.localIndex, args.reason);
  });
  bootObserver.observe(document.body, { attributes: true, attributeFilter: ['class'] });
};

export function mountSceneViz(root: ParentNode = document): void {
  if (root.querySelector('[data-scene-viz]')) return;
  const scenes = Array.from(root.querySelectorAll<HTMLElement>('[data-scene]'));
  SCENE_VIZ.forEach((viz, sceneIndex) => {
    const scene = scenes[sceneIndex];
    const detail = scene?.querySelector<HTMLElement>('[data-detail]');
    if (!scene || !detail) throw new Error(`Scene ${sceneIndex} is missing [data-detail] for viz mount.`);
    const element = viz.build();
    // 序章：弧线置于年代滑杆之后（prepend 会把滑杆挤进展签编目区）。
    const eraControl = sceneIndex === 0 ? detail.querySelector('.era-control') : null;
    if (eraControl) eraControl.after(element);
    else detail.prepend(element);
    mounted.set(sceneIndex, { root: element, tl: null });
    scene.dataset.composition = COMPOSITIONS[sceneIndex]?.[0] ?? '';
  });
}

export function syncSceneViz(scene: number, key: string, localIndex: number, reason: NodeChangeReason = 'wheel'): void {
  const sceneEl = document.querySelector<HTMLElement>(`[data-scene="${scene}"]`);
  const composition = COMPOSITIONS[scene]?.[localIndex];
  if (sceneEl && composition) sceneEl.dataset.composition = composition;
  const entry = mounted.get(scene);
  const viz = SCENE_VIZ[scene];
  if (!entry || !sceneEl || !viz) return;
  if (document.body.classList.contains('is-loading')) {
    armBootSync(scene, key, localIndex, reason);
    return;
  }
  // 已脱离 boot：作废等待中的 boot 重放，避免二次 sync 杀掉入场绘制。
  bootObserver?.disconnect();
  bootObserver = null;
  bootArgs = null;
  entry.tl?.kill();
  const reduced = isReduced();
  const entering = lastScene !== scene;
  lastScene = scene;
  const inDetail = sceneEl.dataset.phase === 'detail';
  const delay = reduced ? 0 : entering ? (inDetail ? .15 : .55) : .05;
  const tl = gsap.timeline({ delay });
  entry.tl = tl;
  viz.update(entry.root, key, localIndex, tl, !reduced, entering);
}

export function destroySceneViz(): void {
  mounted.forEach((entry) => {
    entry.tl?.kill();
    entry.tl = null;
  });
  bootObserver?.disconnect();
  bootObserver = null;
  bootArgs = null;
  lastScene = -1;
}
