/* ------------------------------------------------------------------ crack
   v7.2：裂纹缝形按幕定制。锯齿密度 / 摆幅 / 倾角 / 毛边 / 种子随幕变化，
   运行时以 mulberry32 播种生成左右互为镜像的 clip-path，写入 .tf-crack 层
   （resetTransitionFx 的 clearProps:'all' 会在转场结束后自动清回 CSS 默认）。
   每幕种子固定 → 同一幕每次转场得到同一条可辨识的裂缝。 */
type CrackSpec = {
  teeth: number;      // 锯齿密度（缝形拐点数，越大越细密）
  amplitude: number;  // 齿尖摆幅（相对缝轴，vw 百分比）
  angle: number;      // 裂缝主轴倾角（度，正=上端右倾）
  center: number;     // 裂缝中线基准 x（%）
  roughness: number;  // 次级毛边抖动幅度
  seed: number;       // 每幕独立随机种子
};

const CRACK_SPECS: CrackSpec[] = [
  { teeth: 12, amplitude: 2.6, angle: 0, center: 50, roughness: .5, seed: 0x1F3A2 },   // ① 基准直裂
  { teeth: 8, amplitude: 3.2, angle: -5, center: 49, roughness: .7, seed: 0x2B7D1 },   // ② 宽齿左倾
  { teeth: 14, amplitude: 2.2, angle: 2.5, center: 51, roughness: .45, seed: 0x3C91E },// ③ 密齿微斜（当前 crack 幕）
  { teeth: 10, amplitude: 3.4, angle: 5, center: 48.5, roughness: .8, seed: 0x4A557 }, // ④ 大摆右斜
  { teeth: 16, amplitude: 1.6, angle: -2, center: 50.5, roughness: .35, seed: 0x5E21A },// ⑤ 细密锔钉纹
  { teeth: 9, amplitude: 2.8, angle: 7, center: 52, roughness: .6, seed: 0x66B33 },    // ⑥ 疏齿陡斜
  { teeth: 11, amplitude: 2.4, angle: -7, center: 48, roughness: .55, seed: 0x7747C }, // ⑦ 中齿左斜
  { teeth: 13, amplitude: 2, angle: 1, center: 49.5, roughness: .5, seed: 0x88D9F },   // ⑧ 密直微糙
  { teeth: 7, amplitude: 3.6, angle: -3.5, center: 51.5, roughness: .9, seed: 0x9921B },// ⑨ 疏阔大裂
  { teeth: 15, amplitude: 1.8, angle: 4, center: 50, roughness: .4, seed: 0xA1C4D },   // ⑩ 细齿右倾
];

type CrackSeam = { left: string; right: string; seamX: number; seamTilt: number };

/** 确定性 PRNG（mulberry32）：种子随幕变化，缝形随幕可辨识地不同。 */
const mulberry32 = (seed: number): (() => number) => {
  let state = seed >>> 0;
  return () => {
    state = (state + 0x6D2B79F5) >>> 0;
    let t = state;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
};

/** 沿倾斜主轴播种锯齿折线，左右两块墨板共用同一缝形点列（互为镜像咬合）。 */
const buildCrackSeam = (spec: CrackSpec): CrackSeam => {
  const rand = mulberry32(spec.seed);
  const tilt = (spec.angle * Math.PI) / 180;
  const axisX = (t: number): number => spec.center + Math.tan(tilt) * (t - .5) * 100;
  const up: string[] = [];
  for (let index = 0; index <= spec.teeth; index += 1) {
    const t = index / spec.teeth;
    const alternate = index % 2 === 0 ? 1 : -1;
    const flip = rand() < .18 ? -1 : 1; // 少量同向连齿，打破机械等距感
    const magnitude = spec.amplitude * (.42 + rand() * .58);
    const rough = spec.roughness * (rand() - .5);
    const x = gsap.utils.clamp(34, 66, axisX(t) + alternate * flip * magnitude + rough);
    up.push(`${x.toFixed(1)}% ${(t * 100).toFixed(1)}%`);
  }
  const down = [...up].reverse();
  return {
    left: `polygon(0% 0%, ${up.join(', ')}, 0% 100%)`,
    right: `polygon(${up[0]}, 100% 0%, 100% 100%, ${down.join(', ')})`,
    seamX: spec.center,
    seamTilt: spec.angle,
  };
};

/* ------------------------------------------------------------------ v8.0
   镜头语言体系 —— 运动匹配 / 图形匹配 / 遮挡转场。
   CAMERA_VECTORS 按目标幕定义镜头向量：出场沿向量出离、入场从向量来向
   接入（同向同势，out/in 拼成一次连续镜头运动而非两段独立动画）；
   open 段只走到余势点，余势由非阻塞长尾缓速回落（开场主体最高 1.2x
   → 1.0，cineCam 渐近 = 阻尼感；移动端收敛 pan/推势，长尾封顶 2.5s）。
   GRAPHIC_MATCHES 登记幕间形状延续；巨号年代字在所有幕间做同位置形变
   （基座匹配）。共享元素层挂载在 #transitionFx 内两个运行时根：
   .tf-match-root（低，金框位于扫描场之下）与 .tf-match-root--high
   （高，位于全部遮盖之上、z-210 编目巨号之下）。 */
type CameraVector = {
  panX: number;      // 内容行进方向（vw 百分位），正 = 向右
  panY: number;      // vh 百分位，正 = 向下
  scaleFrom: number; // 入场起始倍率（>1 = 推近中接入；<1 = 拉远回落）
  scaleOut: number;  // 出场出离倍率（推势延续，不反向）
  rotate: number;    // 镜头漂移角（度）
  settle: number;    // 长尾回落时长（桌面端秒；移动端封顶 2.5s）
};

