const setDirectionalVar = (vars: MotionVars, axis: MotionAxis, value: number): MotionVars => {
  vars[axis] = value;
  return vars;
};

const profileArtFrom = (profile: MotionProfile, direction: -1 | 1): MotionVars => ({
  [profile.artAxis]: direction * profile.artShift,
  rotation: direction * profile.artRotate,
  skewX: direction * profile.artSkew,
  scale: profile.artScale,
  transformOrigin: direction > 0 ? '42% 54%' : '58% 46%',
});

const profileArtOut = (profile: MotionProfile, direction: -1 | 1): MotionVars => ({
  [profile.artAxis]: -direction * profile.artShift * .62,
  rotation: -direction * profile.artRotate * .52,
  skewX: -direction * profile.artSkew * .5,
  scale: 1.04,
});

const profileNodeFrom = (profile: MotionProfile, direction: -1 | 1): MotionVars => setDirectionalVar({
  rotation: direction * profile.nodeRotate,
  skewX: direction * profile.nodeSkew,
  scale: profile.nodeScale,
  filter: 'blur(12px)',
  transformOrigin: direction > 0 ? '42% 54%' : '58% 46%',
}, profile.nodeAxis, direction * profile.nodeShift);

const profileNodeOut = (profile: MotionProfile, direction: -1 | 1): MotionVars => setDirectionalVar({
  rotation: -direction * profile.nodeRotate * .65,
  skewX: -direction * profile.nodeSkew * .5,
  scale: .985,
  filter: 'blur(8px)',
}, profile.nodeAxis, -direction * profile.nodeShift * .55);

const profileTextFrom = (profile: MotionProfile, direction: -1 | 1): MotionVars => setDirectionalVar({
  rotation: direction * profile.textRotate,
  skewX: direction * profile.textSkew,
}, profile.textAxis, direction * profile.textShift);

const profileTextOut = (profile: MotionProfile, direction: -1 | 1): MotionVars => setDirectionalVar({
  rotation: -direction * profile.textRotate * .5,
  skewX: -direction * profile.textSkew * .5,
}, profile.textAxis, -direction * profile.textShift * .45);

const profileDetailFrom = (profile: MotionProfile, direction: -1 | 1): MotionVars => setDirectionalVar({
  rotation: direction * profile.detailRotate,
  skewX: direction * profile.detailSkew,
  filter: 'blur(6px)',
}, profile.detailAxis, direction * profile.detailShift);

CustomEase.create('pageClose66', '0.72,0,0.22,1');
CustomEase.create('pageOpen66', '0.18,0.74,0.22,1');
CustomEase.create('numberRead66', '0.22,0.02,0.34,1');
CustomEase.create('nodeOut66', '0.55,0.02,0.72,0.42');
CustomEase.create('nodeIn66', '0.12,0.82,0.18,1');
CustomEase.create('reveal66', '0.18,0.02,0.16,1');
/** v8 电影缓动 token：转场主曲线统一为 cubic-bezier(.2,.6,0,1)（装饰性微动沿用既有 ease）。 */
CustomEase.create('cineCam', '0.2,0.6,0,1');

export class MotionExperience {
  private readonly experience = select<HTMLElement>('#experience');
  private readonly scenes = selectAll<HTMLElement>('[data-scene]');
  private readonly strips = selectAll<HTMLElement>('#transitionStrips i');
  private readonly transitionCode = select<HTMLElement>('#transitionCode');
  private readonly transitionNumber = select<HTMLElement>('#transitionCode b');
  private readonly transitionName = select<HTMLElement>('#transitionName');
  private readonly transitionAct = select<HTMLElement>('#transitionCode span');
  private readonly stripsRoot = select<HTMLElement>('#transitionStrips');
  private readonly fxRoot = MotionExperience.buildTransitionFx(this.stripsRoot);
  private readonly pixelCells = selectAll<HTMLElement>('u', this.fxRoot);
  private readonly ringDiscs = selectAll<HTMLElement>('.tf-ring', this.fxRoot);
  /** v8 共享元素层双根（buildTransitionFx 内创建）：低根给金框遮挡，高根给其余匹配层。 */
  private readonly matchRoot = select<HTMLElement>('.tf-match-root', this.fxRoot);
  private readonly matchRootHigh = select<HTMLElement>('.tf-match-root--high', this.fxRoot);
  /** v8 入场镜头长尾（非阻塞回落 tween），转场启动/清场时收回。 */
  private settleTail: gsap.core.Tween | null = null;
  private odoReels: { reel: HTMLElement; fromY: number; toY: number }[] = [];
  private readonly railProgress = select<HTMLElement>('#railProgress');
  private readonly ambient: AmbientController;
  private readonly observer: Observer;

  private currentFlatIndex = 0;
  private desiredFlatIndex = 0;
  private started = false;
  private transitioning = false;
  private reducedMotion = false;
  private destroyed = false;
  private directJumpRequested = false;
  private pendingReason: NodeChangeReason = 'initial';
  private stateHandler: StateHandler | null = null;
  private readonly nodeHandlers: NodeHandler[] = [];

  private pageTimeline: gsap.core.Timeline | null = null;
  private nodeTimeline: gsap.core.Timeline | null = null;
  private primaryTimeline: gsap.core.Timeline | null = null;
  private detailTimeline: gsap.core.Timeline | null = null;
  private detailTimer: number | null = null;

  private lastWheelAt = 0;
  private wheelDirection: -1 | 1 | null = null;
  private wheelEnergy = 0;
  private wheelThreshold = 92;
  private wheelLastInputAt = 0;
  private wheelReleasedAt = 0;
  private wheelVelocity = 0;
  private wheelHasContinuation = false;
  private touchGestureSerial = 0;
  private lastTriggeredTouchGesture = -1;

  /** One adjacent node is the maximum visual prefetch for a wheel gesture. */
  private static readonly MAX_WHEEL_BACKLOG = 1;
  private static readonly WHEEL_BURST_GAP = 220;
  private static readonly WHEEL_RELEASE_GRACE = 760;
  private static readonly WHEEL_ENERGY_CAP = 1.55;

  /**
   * Runtime overlay stack for the non-strip transition styles. Built once so
   * index.html keeps its v6.8 contract; every layer is styled in
   * style-transition.css and stays hidden until a choreography claims it.
   */
  private static buildTransitionFx(anchor: HTMLElement): HTMLElement {
    const root = document.createElement('div');
    root.id = 'transitionFx';
    root.className = 'transition-fx';
    root.setAttribute('aria-hidden', 'true');
    const make = (className: string, parent: HTMLElement = root): HTMLElement => {
      const element = document.createElement('div');
      element.className = className;
      parent.appendChild(element);
      return element;
    };
    make('tf-veil');
    make('tf-iris-edge');
    make('tf-iris');
    make('tf-iris-hole');
    make('tf-ink');
    make('tf-ink-hole');
    make('tf-crack tf-crack--l');
    make('tf-crack tf-crack--r');
    make('tf-crack-seam');
    make('tf-slash');
    const pixels = make('tf-pixels');
    for (let index = 0; index < 84; index += 1) pixels.appendChild(document.createElement('u'));
    const rings = make('tf-rings');
    for (let index = 0; index < 6; index += 1) make('tf-ring', rings);
    make('tf-scan');
    make('tf-scan-line');
    // v8：图形匹配/遮挡共享元素层（低根在扫描场之下，高根在全部遮盖之上、巨号之下）
    make('tf-match-root');
    make('tf-match-root--high');
    anchor.insertAdjacentElement('afterend', root);
    return root;
  }

  private readonly handleKeydown = (event: KeyboardEvent): void => {
    if (event.metaKey || event.ctrlKey || event.altKey) return;
    const target = event.target as HTMLElement | null;
    if (target?.matches('input, textarea, select, button, a, [contenteditable="true"]')) return;
    // B1: Home/End（goToFlat）此前绕过导航锁——boot/菜单/抽屉期间一律拒绝键盘导航。
    if (!this.canNavigate()) return;

    if (['ArrowDown', 'PageDown', ' '].includes(event.key)) {
      event.preventDefault();
      this.enqueueNode(1, 'keyboard');
    } else if (['ArrowUp', 'PageUp'].includes(event.key)) {
      event.preventDefault();
      this.enqueueNode(-1, 'keyboard');
    } else if (event.key === 'Home') {
      event.preventDefault();
      this.goToFlat(0);
    } else if (event.key === 'End') {
      event.preventDefault();
      this.goToFlat(TOTAL_NODES - 1);
    }
  };

  constructor(ambient: AmbientController) {
    this.ambient = ambient;
    this.prepareScenes();
    this.observer = this.createInputObserver();
    window.addEventListener('keydown', this.handleKeydown);
    this.setNodeVisualImmediate(FLAT_NODES[0]);
    this.applyNodeState(FLAT_NODES[0], 'initial', false);
    this.syncSceneUI(0, 'primary');
  }

  start(): void {
    if (this.started || this.destroyed) return;
    this.started = true;
    this.animatePrimary(0, false, () => this.scheduleDetail(0));
    // B1: 冲刷 start 之前经 goToFlat 登记的目标（boot 期间按 End 不再卡死 flow）。
    this.pumpNavigation();
  }

  private createInputObserver(): Observer {
    return Observer.create({
      id: 'v68-bounded-forty-node-input',
      target: window,
      type: 'wheel,touch',
      preventDefault: true,
      capture: true,
      debounce: true,
      lockAxis: true,
      dragMinimum: 22,
      tolerance: 10,
      wheelSpeed: -1,
      ignore: '.menu, .sources, input, textarea, select, [contenteditable="true"], [data-gesture-ignore]',
      ignoreCheck: (event: Event, isPointerOrTouch: boolean) => {
        const target = event.target instanceof Element ? event.target : null;
        return Boolean(isPointerOrTouch && target?.closest('button, a'));
      },
      onPress: (self) => {
        if (this.isTouchEvent(self.event)) this.touchGestureSerial += 1;
      },
      onUp: (self) => this.handleDirectionalInput(1, self),
      onDown: (self) => this.handleDirectionalInput(-1, self),
      onStop: () => {
        // Do not erase momentum the instant the wheel stream goes quiet. A
        // high-resolution trackpad often emits a short tail after the last
        // physical finger movement; keeping one bounded carry lets the
        // authored phrase finish naturally without building a page queue.
        this.wheelReleasedAt = this.wheelHasContinuation && this.wheelEnergy > 0
          ? performance.now()
          : 0;
        this.experience.dataset.flow = this.transitioning && this.desiredFlatIndex !== this.currentFlatIndex ? 'cruise' : 'settled';
      },
      onStopDelay: 0.22,
    });
  }

  private handleDirectionalInput(direction: -1 | 1, observer: Observer): void {
    if (!this.canNavigate()) return;
    const source: InputSource = this.isTouchEvent(observer.event) || observer.isPressed ? 'touch' : 'wheel';

    if (source === 'touch') {
      if (this.lastTriggeredTouchGesture === this.touchGestureSerial) return;
      this.lastTriggeredTouchGesture = this.touchGestureSerial;
      this.enqueueNode(direction, 'touch');
      return;
    }

    const wheelEvent = observer.event instanceof WheelEvent ? observer.event : null;
    const mode = wheelEvent?.deltaMode ?? WheelEvent.DOM_DELTA_PIXEL;
    const magnitude = wheelEvent
      ? this.normalizeWheelDelta(wheelEvent.deltaY, mode)
      : Math.abs(observer.deltaY);
    this.integrateWheel(direction, Math.max(1, magnitude), mode);
  }

  /**
   * First impulse = one exact node. Subsequent deltas form a bounded energy
   * envelope. We never turn one physical gesture into an invisible backlog of
   * pages; one adjacent node can be preloaded and the rest waits for the
   * current phrase to settle.
   */
  private integrateWheel(direction: -1 | 1, magnitude: number, deltaMode: number): void {
    const now = performance.now();
    const newBurst = this.wheelDirection !== direction || now - this.lastWheelAt > MotionExperience.WHEEL_BURST_GAP;
    const elapsed = this.lastWheelAt ? Math.max(16, now - this.lastWheelAt) : 16;
    this.lastWheelAt = now;
    this.wheelLastInputAt = now;
    this.wheelReleasedAt = 0;
    const instantaneousVelocity = magnitude / elapsed;
    this.wheelVelocity = gsap.utils.interpolate(
      this.wheelVelocity,
      gsap.utils.clamp(0, 2.5, instantaneousVelocity),
      .22,
    );
    this.wheelThreshold = deltaMode === WheelEvent.DOM_DELTA_PIXEL ? 92 : 58;

    if (newBurst) {
      this.wheelDirection = direction;
      this.wheelEnergy = 0;
      this.wheelVelocity *= .6;
      this.wheelHasContinuation = false;
      this.enqueueNode(direction, 'wheel');
      return;
    }

    this.wheelHasContinuation = true;
    this.wheelEnergy = Math.min(
      this.wheelThreshold * MotionExperience.WHEEL_ENERGY_CAP,
      this.wheelEnergy + magnitude,
    );

    if (this.wheelEnergy < this.wheelThreshold) return;
    const backlog = Math.abs(this.desiredFlatIndex - this.currentFlatIndex);
    if (backlog >= MotionExperience.MAX_WHEEL_BACKLOG) return;

    this.wheelEnergy -= this.wheelThreshold;
    this.enqueueNode(direction, 'wheel');
  }

  /** Consume one stored wheel intent only after the current phrase completed. */
  private consumeWheelCarry(): boolean {
    if (!this.wheelDirection || !this.wheelLastInputAt) return false;
    const now = performance.now();
    const releasedGrace = this.wheelReleasedAt > 0
      && now - this.wheelReleasedAt <= MotionExperience.WHEEL_RELEASE_GRACE;
    if (now - this.wheelLastInputAt > MotionExperience.WHEEL_BURST_GAP && !releasedGrace) return false;
    if (this.wheelEnergy < this.wheelThreshold) return false;
    const next = clampFlat(this.currentFlatIndex + this.wheelDirection);
    if (next === this.currentFlatIndex) return false;
    this.wheelEnergy -= this.wheelThreshold;
    this.desiredFlatIndex = next;
    this.pendingReason = 'wheel';
    this.directJumpRequested = false;
    this.cancelAutoDetail();
    this.updateFlowState();
    return true;
  }

  private decayWheelCarry(): void {
    if (!this.wheelDirection || !this.wheelLastInputAt) return;
    const idle = performance.now() - this.wheelLastInputAt;
    const releaseExpired = this.wheelReleasedAt > 0
      && performance.now() - this.wheelReleasedAt > MotionExperience.WHEEL_RELEASE_GRACE;
    if (releaseExpired || (this.wheelReleasedAt === 0 && idle > MotionExperience.WHEEL_BURST_GAP)) {
      this.wheelEnergy = 0;
      this.wheelDirection = null;
      this.wheelLastInputAt = 0;
      this.wheelReleasedAt = 0;
      this.wheelVelocity = 0;
      this.wheelHasContinuation = false;
    }
  }

  private enqueueNode(direction: -1 | 1, source: InputSource): void {
    if (!this.canNavigate()) return;
    const nextDesired = clampFlat(this.desiredFlatIndex + direction);
    if (nextDesired === this.desiredFlatIndex) return;
    if (source === 'wheel'
      && Math.abs(nextDesired - this.currentFlatIndex) > MotionExperience.MAX_WHEEL_BACKLOG) {
      return;
    }

    this.desiredFlatIndex = nextDesired;
    this.pendingReason = source;
    this.directJumpRequested = false;
    this.cancelAutoDetail();
    this.updateFlowState();
    this.accelerateActivePhrase();
    this.pumpNavigation();
  }

  private updateFlowState(): void {
    const backlog = Math.abs(this.desiredFlatIndex - this.currentFlatIndex);
    this.experience.dataset.desiredNode = String(this.desiredFlatIndex + 1);
    this.experience.dataset.flow = backlog > 1 ? 'cruise' : backlog === 1 ? 'discrete' : 'settled';
  }

  /** Backlog changes only timeScale, never the geometry of the animation. */
  private accelerateActivePhrase(): void {
    if (this.reducedMotion) return;
    const backlog = Math.abs(this.desiredFlatIndex - this.currentFlatIndex);
    // Wheel travel uses a narrow, velocity-aware band. This removes the
    // sudden fast-forward that makes a long gesture feel like skipped slides,
    // while still letting a sustained trackpad stream move a little more
    // briskly than a single impulse. Keyboard/menu jumps retain a small cap.
    const scale = this.pendingReason === 'wheel'
      ? this.wheelHasContinuation
        ? gsap.utils.clamp(.92, 1, .92 + this.wheelVelocity * .045)
        : 1
      : gsap.utils.clamp(1, 1.24, 1 + backlog * .04);
    this.pageTimeline?.timeScale(scale);
    this.nodeTimeline?.timeScale(scale);
  }

  private pumpNavigation(): void {
    if (!this.started || this.transitioning || this.destroyed) return;
    if (this.desiredFlatIndex === this.currentFlatIndex) {
      this.experience.dataset.flow = 'settled';
      delete this.experience.dataset.desiredNode;
      this.scheduleDetail(FLAT_NODES[this.currentFlatIndex].sceneIndex);
      return;
    }

    const direction = Math.sign(this.desiredFlatIndex - this.currentFlatIndex) as -1 | 1;
    const targetFlat = this.directJumpRequested
      ? this.desiredFlatIndex
      : this.currentFlatIndex + direction;
    const direct = this.directJumpRequested;
    this.directJumpRequested = false;

    const currentNode = FLAT_NODES[this.currentFlatIndex];
    const targetNode = FLAT_NODES[targetFlat];
    if (currentNode.sceneIndex === targetNode.sceneIndex) {
      this.transitionNode(targetNode, direction, direct);
    } else {
      this.transitionPage(targetNode, direction, direct);
    }
  }

  private transitionNode(target: FlatNode, direction: -1 | 1, direct: boolean): void {
    this.transitioning = true;
    this.cancelSceneAnimations();
    const scene = this.scenes[target.sceneIndex];
    const profile = profileFor(target.sceneIndex);
    const current = FLAT_NODES[this.currentFlatIndex];
    const outgoing = scene.querySelector<HTMLElement>(`[data-node-visual="${current.key}"]`);
    const incoming = scene.querySelector<HTMLElement>(`[data-node-visual="${target.key}"]`);
    const incomingArt = incoming ? selectAll<HTMLElement>('.node-art', incoming) : [];
    const heritageArt = !incoming ? selectAll<HTMLElement>('.art-asset, .heritage-accent', scene) : [];
    const backlog = Math.abs(this.desiredFlatIndex - this.currentFlatIndex);
    const sustainedWheel = this.pendingReason === 'wheel' && this.wheelHasContinuation;
    const cruise = !direct && (backlog > 1 || sustainedWheel);
    const total = this.reducedMotion ? .18 : cruise ? .98 : 1.08;
    const swapAt = total * .31;
    const artInAt = total * .25;
    const textTargets = this.primaryTargets(scene).filter((element) => !element.closest('.scene__eyebrow'));
    const textOut = profileTextOut(profile, direction);
    const textFrom = profileTextFrom(profile, direction);

    scene.dataset.nodeTransitioning = 'true';
    scene.dataset.motionProfile = profile.id;
    this.experience.dataset.flow = cruise ? 'cruise' : 'discrete';
    this.pulseAmbient(.42);
    if (incoming) gsap.set(incoming, { autoAlpha: 0, visibility: 'visible', ...profileNodeFrom(profile, direction) });

    const timeline = gsap.timeline({
      defaults: { overwrite: 'auto' },
      onComplete: () => {
        this.nodeTimeline = null;
        this.transitioning = false;
        this.currentFlatIndex = target.flatIndex;
        delete scene.dataset.nodeTransitioning;
        this.finishPhrase();
      },
    });

    if (outgoing) {
      timeline.to(outgoing, {
        autoAlpha: 0,
        ...profileNodeOut(profile, direction),
        duration: total * .42,
        ease: 'nodeOut66',
      }, 0);
    } else if (heritageArt.length) {
      timeline.to(heritageArt, {
        autoAlpha: (index: number) => index === 0 ? .6 : .34,
        duration: total * .28,
        stagger: this.reducedMotion ? 0 : total * .012,
        ease: 'power2.in',
      }, 0);
    }

    timeline
      .to(textTargets, {
        autoAlpha: .2,
        ...textOut,
        duration: total * .24,
        ease: 'power2.in',
      }, 0)
      .call(() => {
        if (outgoing) {
          outgoing.classList.remove('is-active');
          gsap.set(outgoing, { clearProps: 'all' });
        }
        if (incoming) incoming.classList.add('is-active');
        this.applyNodeState(target, this.pendingReason, true);
      }, undefined, swapAt)
      .set(textTargets, textFrom, swapAt)
      .to(textTargets, {
        autoAlpha: 1,
        y: 0,
        x: 0,
        rotation: 0,
        skewX: 0,
        duration: total * .52,
        stagger: this.reducedMotion ? 0 : .025,
        ease: 'nodeIn66',
        clearProps: 'x,y,rotation,skewX',
      }, swapAt);

    if (incoming) {
      timeline.to(incoming, {
        autoAlpha: 1,
        x: 0,
        y: 0,
        rotation: 0,
        skewX: 0,
        scale: 1,
        filter: 'blur(0px)',
        duration: total * .68,
        ease: 'nodeIn66',
        clearProps: 'x,y,rotation,skewX,scale,filter,opacity,visibility,transformOrigin',
      }, artInAt);
      if (incomingArt.length > 1) {
        timeline.fromTo(incomingArt, {
          y: (index: number) => (direction > 0 ? 1 : -1) * (9 + index * 5),
          rotation: (index: number) => (index - (incomingArt.length - 1) / 2) * .7,
          filter: 'brightness(.68) blur(4px)',
        }, {
          y: 0,
          rotation: 0,
          filter: 'brightness(1) blur(0px)',
          duration: total * .62,
          stagger: this.reducedMotion ? 0 : total * .045,
          ease: 'nodeIn66',
          clearProps: 'y,rotation,filter',
        }, swapAt);
      }
    } else if (heritageArt.length) {
      timeline.to(heritageArt, {
        autoAlpha: 1,
        duration: total * .62,
        stagger: this.reducedMotion ? 0 : total * .018,
        ease: 'nodeIn66',
        clearProps: 'opacity,visibility',
      }, artInAt);
    } else {
      const selectedArt = scene.querySelector<HTMLElement>(`[data-node-art-key="${target.key}"]`);
      if (selectedArt) {
        timeline.fromTo(selectedArt,
          { y: direction > 0 ? 14 : -14, filter: 'brightness(.72) blur(5px)' },
          { y: 0, filter: 'brightness(1) blur(0px)', duration: total * .68, ease: 'nodeIn66', clearProps: 'y,filter' },
          artInAt);
      }
    }

    this.nodeTimeline = timeline;
    this.accelerateActivePhrase();
  }

  private transitionPage(target: FlatNode, direction: -1 | 1, direct: boolean): void {
    this.transitioning = true;
    this.cancelSceneAnimations();
    this.settleTail?.kill();
    this.settleTail = null;
    const outgoing = FLAT_NODES[this.currentFlatIndex];
    const incomingScene = this.scenes[target.sceneIndex];
    const profile = profileFor(target.sceneIndex);
    const style = transitionStyleFor(target.sceneIndex);
    const backlog = Math.abs(this.desiredFlatIndex - this.currentFlatIndex);
    const sustainedWheel = this.pendingReason === 'wheel' && this.wheelHasContinuation;
    const cruise = !direct && (backlog > 1 || sustainedWheel);
    const total = this.reducedMotion ? .28 : cruise ? 1.26 : 1.38;
    const closeDuration = total * style.close;
    const numberDuration = total * style.number;
    const openDuration = total * style.open;
    const swapAt = closeDuration;
    const openAt = closeDuration + numberDuration;
    const primaryAt = closeDuration + numberDuration * .48;
    const stripOrder = direction > 0 ? this.strips : [...this.strips].reverse();
    const incomingArtTargets = this.artTargets(incomingScene);
    const incomingTextTargets = this.primaryTargets(incomingScene);
    const reduced = this.reducedMotion;
    // v8 运动匹配：目标幕镜头向量 + 移动端降级收敛
    const vector = CAMERA_VECTORS[target.sceneIndex] ?? CAMERA_VECTORS[0];
    const mobile = this.isMobileLike();

    this.setTransitionCopy(target, style);
    this.experience.dataset.flow = cruise ? 'cruise' : 'discrete';
    this.experience.dataset.motionProfile = profile.id;
    document.body.classList.add('is-page-transitioning');
    this.pulseAmbient(1);
    // v8.0 镜头穿越：首幕金器驻守，离/回首幕时推镜充满画面作天然遮挡。
    if (outgoing.sceneIndex === 0 && target.sceneIndex !== 0) this.ambient.pushThrough?.();
    else if (outgoing.sceneIndex !== 0 && target.sceneIndex === 0) this.ambient.resetCamera?.();
    this.fxRoot.classList.remove(...TRANSITION_CLASSES);
    this.fxRoot.classList.add(style.className);
    this.stripsRoot.classList.remove(...TRANSITION_CLASSES);
    if (style.usesStrips) this.stripsRoot.classList.add(style.className);
    // v7.2：crack 转场按幕索引生成定制缝形（墨板尚未滑入，写入不可见）。
    if (style.id === 'crack') this.applyCrackSeam(target.sceneIndex);

    this.resetScene(incomingScene);
    this.setNodeVisualImmediate(target);
    gsap.set(incomingArtTargets, {
      autoAlpha: .2,
      ...(reduced ? profileArtFrom(profile, direction) : this.vectorArtFrom(vector, direction, mobile)),
    });
    gsap.set(incomingTextTargets, profileTextFrom(profile, direction));
    if (style.usesStrips) {
      gsap.set(stripOrder, style.id === 'curtain'
        ? { scaleY: 0, transformOrigin: direction > 0 ? 'bottom' : 'top' }
        : { scaleY: 0 });
    }

    const timeline = gsap.timeline({
      defaults: { overwrite: 'auto' },
      onComplete: () => {
        this.pageTimeline = null;
        this.transitioning = false;
        this.currentFlatIndex = target.flatIndex;
        document.body.classList.remove('is-page-transitioning');
        gsap.set(this.transitionCode, { autoAlpha: 0, visibility: 'hidden' });
        this.resetTransitionFx();
        // v8：转场状态解锁后，主体镜头继续非阻塞缓速回落到 1.0（电影化停稳）
        if (!reduced) this.startCameraSettle(incomingArtTargets, vector, mobile);
        this.finishPhrase();
      },
    });

    timeline
      .to(this.artTargets(this.scenes[outgoing.sceneIndex]), {
        autoAlpha: .2,
        ...(reduced ? profileArtOut(profile, direction) : this.vectorArtOut(vector, direction, mobile)),
        duration: closeDuration,
        ease: reduced ? 'pageClose66' : 'cineCam',
      }, 0)
      .call(() => {
        this.swapScenes(outgoing.sceneIndex, target.sceneIndex);
        this.applyNodeState(target, this.pendingReason, true);
      }, undefined, swapAt)
      .to(this.artTargets(incomingScene), reduced ? {
        autoAlpha: 1,
        scale: 1,
        xPercent: 0,
        yPercent: 0,
        rotation: 0,
        skewX: 0,
        duration: openDuration * 1.05,
        ease: 'pageOpen66',
        clearProps: 'xPercent,yPercent,rotation,skewX,transformOrigin,filter,opacity,visibility',
      } : {
        // v8：open 段只走到余势点（缩放 ≈1+Δ·.3、pan 余 8%），余势交长尾缓速回落
        autoAlpha: 1,
        ...this.vectorArtSettle(vector, direction, mobile),
        skewX: 0,
        duration: openDuration * 1.05,
        ease: 'cineCam',
      }, primaryAt - openDuration * .14)
      .to(this.primaryTargets(incomingScene), {
        autoAlpha: 1,
        x: 0,
        y: 0,
        rotation: 0,
        skewX: 0,
        filter: 'blur(0px)',
        duration: reduced ? .12 : openDuration * .9,
        stagger: reduced ? 0 : .045,
        ease: 'reveal66',
        clearProps: 'x,y,rotation,skewX',
      }, primaryAt)
      .to(this.transitionCode, {
        autoAlpha: 0,
        scale: 1.035,
        duration: Math.min(.2, openDuration * .48),
        ease: 'power2.in',
      }, openAt - numberDuration * .1);

    this.buildCoverClose(timeline, style, profile, stripOrder, direction, closeDuration, reduced);
    this.introTransitionCode(timeline, style, profile, direction, closeDuration, numberDuration, reduced);
    this.buildCoverOpen(timeline, style, profile, stripOrder, direction, openAt, openDuration, reduced);
    // v8：图形匹配/遮挡共享元素编舞（reduced-motion 走简洁切换，不建共享层）
    if (!reduced) {
      this.buildMatchClose(timeline, outgoing, target, closeDuration, numberDuration, openAt, openDuration);
    }

    this.pageTimeline = timeline;
    this.accelerateActivePhrase();
  }

  /** Bilingual catalog copy: `ACT 02 · INSTITUTION` over the giant number, CN act name below. */
  private setTransitionCopy(target: FlatNode, style: TransitionStyle): void {
    const chapter = CHAPTERS[target.sceneIndex];
    const code = String(target.sceneIndex + 1).padStart(2, '0');
    this.transitionAct.textContent = `${chapter.act} · ${chapter.english}`;
    this.transitionName.textContent = chapter.name;
    if (style.id === 'odo') {
      const prevCode = String(FLAT_NODES[this.currentFlatIndex].sceneIndex + 1).padStart(2, '0');
      this.buildOdometer(code, prevCode);
    } else {
      this.transitionNumber.textContent = code;
    }
  }

  /**
   * Split the giant number into per-digit odometer reels (runtime DOM only).
   * v7.2 环形里程表：数字格是一个 0-9 的环，9 与 0 相邻。跨 9|0 边界时
   * 取最短路径滚动——如 09→10 个位从 9 正向滚过 0（卷轴尾部补 0 格），
   * 反向 10→09 个位从 0 倒退一格到 9（卷轴头部补 9 格），绝不直滚中间数字。
   */
  private buildOdometer(code: string, prevCode: string): void {
    this.transitionNumber.textContent = '';
    this.odoReels = [];
    for (let index = 0; index < code.length; index += 1) {
      const from = Number(prevCode[index] ?? 0);
      const to = Number(code[index]);
      // 目标格以环上最短路径表示：落在 from±5 之外时改走环绕副本（±10）。
      const delta = to - from;
      const target = delta > 5 ? to - 10 : delta < -5 ? to + 10 : to;
      const lo = Math.min(from, target, 0);
      const hi = Math.max(from, target, 9);
      const count = hi - lo + 1;
      const column = document.createElement('span');
      column.className = 'ts-odo-col';
      const reel = document.createElement('span');
      reel.className = 'ts-odo-reel';
      for (let cellIndex = lo; cellIndex <= hi; cellIndex += 1) {
        const cell = document.createElement('i');
        cell.textContent = String(((cellIndex % 10) + 10) % 10);
        reel.appendChild(cell);
      }
      column.appendChild(reel);
      this.transitionNumber.appendChild(column);
      // 卷轴高 count 格：显示第 i 格 ⇒ yPercent = -(i - lo) / count * 100
      const positionFor = (cellIndex: number): number => -((cellIndex - lo) / count) * 100;
      const fromY = positionFor(from);
      this.odoReels.push({ reel, fromY, toY: positionFor(target) });
      gsap.set(reel, { yPercent: fromY });
    }
  }

  private fxLayer(name: string): HTMLElement {
    return select<HTMLElement>(`.tf-${name}`, this.fxRoot);
  }

  /** v7.2：按幕索引写入定制裂缝（clip-path 互为镜像）+ 锔缝辉光线位置/倾角。 */
  private applyCrackSeam(sceneIndex: number): void {
    const seam = buildCrackSeam(CRACK_SPECS[sceneIndex] ?? CRACK_SPECS[2]);
    gsap.set(this.fxLayer('crack--l'), { clipPath: seam.left });
    gsap.set(this.fxLayer('crack--r'), { clipPath: seam.right });
    gsap.set(this.fxLayer('crack-seam'), { left: `${seam.seamX}%`, rotation: seam.seamTilt });
  }

  /**
   * v7.2 转场-金尘联动：聚散脉冲。main.ts 适配层转发 pulse 时走类型化调用；
   * 尚未转发时改走 AmbientScene 自监听的 DOM 事件桥（事件名常量见
   * webgl/AmbientScene.ts，两处字面量保持一致），适配层补齐后自动回到主路径。
   */
  private pulseAmbient(intensity: number): void {
    if (typeof this.ambient.pulse === 'function') {
      this.ambient.pulse(intensity);
    } else {
      window.dispatchEvent(new CustomEvent('gilt:ambient-pulse', { detail: intensity }));
    }
  }

  /** Cover choreography: screen must be fully covered by closeDuration (the swap beat). */
  private buildCoverClose(
    timeline: gsap.core.Timeline,
    style: TransitionStyle,
    profile: MotionProfile,
    stripOrder: HTMLElement[],
    direction: -1 | 1,
    closeDuration: number,
    reduced: boolean,
  ): void {
    const fx = this.fxRoot;
    switch (style.id) {
      case 'blinds':
        timeline.to(stripOrder, {
          scaleY: 1,
          duration: closeDuration * .8,
          stagger: reduced ? 0 : { each: closeDuration * .014, from: 'edges' },
          ease: 'cineCam',
        }, 0);
        break;
      case 'iris':
        timeline
          .set([this.fxLayer('iris'), this.fxLayer('iris-edge')], { autoAlpha: 1 }, 0)
          .fromTo(fx, { '--tf-iris-r': '0%' }, {
            '--tf-iris-r': '118%', duration: closeDuration, ease: 'cineCam',
          }, 0);
        break;
      case 'crack': {
        const seam = this.fxLayer('crack-seam');
        timeline
          .set([this.fxLayer('crack--l'), this.fxLayer('crack--r')], { autoAlpha: 1 }, 0)
          .set(seam, { autoAlpha: 0 }, 0)
          .fromTo(this.fxLayer('crack--l'), { xPercent: -106 }, {
            xPercent: 0, duration: closeDuration * .78, ease: 'cineCam',
          }, 0)
          .fromTo(this.fxLayer('crack--r'), { xPercent: 106 }, {
            xPercent: 0, duration: closeDuration * .78, ease: 'cineCam',
          }, 0)
          .to(seam, { autoAlpha: .95, duration: reduced ? .05 : closeDuration * .1, ease: 'power2.out' }, closeDuration * .78)
          .to(seam, { autoAlpha: .3, duration: closeDuration * .12, ease: 'power2.inOut' }, closeDuration * .88);
        break;
      }
      case 'ink':
        timeline
          .set(this.fxLayer('ink'), { autoAlpha: 1 }, 0)
          .fromTo(fx, { '--tf-ink-r': '0%' }, {
            '--tf-ink-r': '126%', duration: closeDuration, ease: 'cineCam',
          }, 0);
        break;
      case 'odo':
        timeline.fromTo(this.fxLayer('veil'), { autoAlpha: 0 }, {
          autoAlpha: 1, duration: closeDuration, ease: 'cineCam',
        }, 0);
        break;
      case 'slash':
        timeline.fromTo(this.fxLayer('slash'), {
          autoAlpha: 1, xPercent: direction > 0 ? -118 : 118,
        }, {
          xPercent: 0, duration: closeDuration, ease: 'cineCam',
        }, 0);
        break;
      case 'pixels':
        timeline
          .set(this.fxLayer('pixels'), { autoAlpha: 1 }, 0)
          .fromTo(this.pixelCells, { autoAlpha: 0, scale: .55 }, {
            autoAlpha: 1,
            scale: 1,
            duration: closeDuration * .42,
            stagger: reduced ? 0 : { each: (closeDuration * .5) / this.pixelCells.length, from: 'random' },
            ease: 'cineCam',
          }, 0);
        break;
      case 'rings':
        timeline
          .set(this.fxLayer('rings'), { autoAlpha: 1 }, 0)
          .fromTo(this.ringDiscs, { scale: 0 }, {
            scale: 1,
            duration: closeDuration * .68,
            stagger: reduced ? 0 : closeDuration * .052,
            ease: 'cineCam',
          }, 0);
        break;
      case 'scan':
        timeline
          .set(this.fxLayer('scan'), { autoAlpha: 1 }, 0)
          .fromTo(fx, { '--tf-scan-p': '50%' }, {
            '--tf-scan-p': '0%', duration: closeDuration, ease: 'cineCam',
          }, 0);
        break;
      default: // curtain — 金边帷幕，沿用 12 strips 契约结构；v8 主曲线统一 cineCam，差异化留在 stagger/origin/几何
        timeline.to(stripOrder, {
          scaleY: 1,
          duration: closeDuration * .82,
          stagger: reduced ? 0 : closeDuration * profile.stripStagger,
          ease: 'cineCam',
        }, 0);
    }
  }

  /** Giant act number + bilingual catalog line, staged per transition style. */
  private introTransitionCode(
    timeline: gsap.core.Timeline,
    style: TransitionStyle,
    profile: MotionProfile,
    direction: -1 | 1,
    closeDuration: number,
    numberDuration: number,
    reduced: boolean,
  ): void {
    const codeEl = this.transitionCode;
    const numberEl = this.transitionNumber;
    const at = closeDuration * .55;
    const numberAt = style.id === 'odo' ? closeDuration * .5 : closeDuration * .64;
    const codeInDuration = Math.min(.22, closeDuration * .68);

    if (style.id === 'odo') {
      timeline
        .set(codeEl, { autoAlpha: 0, visibility: 'visible', yPercent: 6, scale: 1, clipPath: 'none' }, 0)
        .set(numberEl, { scale: 1, xPercent: 0, yPercent: 0, rotation: 0, skewX: 0, filter: 'blur(0px)' }, 0)
        .to(codeEl, { autoAlpha: 1, yPercent: 0, duration: codeInDuration, ease: 'power2.out' }, at)
        .fromTo(this.odoReels.map((digit) => digit.reel), {
          yPercent: (index: number) => this.odoReels[index].fromY,
        }, {
          yPercent: (index: number) => this.odoReels[index].toY,
          duration: numberDuration * .95,
          stagger: reduced ? 0 : .07,
          ease: 'numberRead66',
        }, numberAt);
      return;
    }

    if (style.id === 'scan') {
      const hiddenClip = direction > 0 ? 'inset(-8% -3% 108% -3%)' : 'inset(108% -3% -8% -3%)';
      const shownClip = 'inset(-8% -3% -8% -3%)';
      const line = this.fxLayer('scan-line');
      timeline
        .set(numberEl, { scale: 1, xPercent: 0, yPercent: 0, rotation: 0, skewX: 0, filter: 'blur(0px)' }, 0)
        .fromTo(codeEl, { autoAlpha: 1, visibility: 'visible', clipPath: hiddenClip }, {
          clipPath: shownClip, duration: numberDuration * .9, ease: 'power1.inOut',
        }, numberAt)
        .fromTo(line, { autoAlpha: .95, y: direction > 0 ? '-4vh' : '104vh' }, {
          y: direction > 0 ? '104vh' : '-4vh', duration: numberDuration * .9, ease: 'power1.inOut',
        }, numberAt)
        .to(line, { autoAlpha: 0, duration: numberDuration * .12, ease: 'power1.in' }, numberAt + numberDuration * .82);
      return;
    }

    const containerFrom: MotionVars = { autoAlpha: 0, visibility: 'visible', clipPath: 'none' };
    const numberFrom: MotionVars = { filter: 'blur(14px)' };
    switch (style.id) {
      case 'iris':
        Object.assign(containerFrom, { scale: .62 });
        Object.assign(numberFrom, { scale: .82, filter: 'blur(22px)' });
        break;
      case 'crack':
        Object.assign(containerFrom, { scaleX: 1.16 });
        Object.assign(numberFrom, { scale: .95, filter: 'blur(14px)' });
        break;
      case 'ink':
        Object.assign(containerFrom, { scale: 1.22 });
        Object.assign(numberFrom, { scale: 1.06, filter: 'blur(24px)' });
        break;
      case 'blinds':
        Object.assign(containerFrom, { yPercent: direction > 0 ? 16 : -16 });
        Object.assign(numberFrom, { yPercent: direction > 0 ? 12 : -12, filter: 'blur(12px)' });
        break;
      case 'slash':
        Object.assign(containerFrom, { xPercent: direction > 0 ? -10 : 10, skewX: direction > 0 ? -7 : 7 });
        break;
      case 'pixels':
        Object.assign(numberFrom, { scale: 1.04, filter: 'blur(6px)' });
        break;
      case 'rings':
        Object.assign(containerFrom, { scale: .74, rotation: direction > 0 ? 2 : -2 });
        Object.assign(numberFrom, { scale: .9, filter: 'blur(16px)' });
        break;
      default: // curtain
        Object.assign(containerFrom, { yPercent: direction > 0 ? 10 : -10, scale: .97 });
        Object.assign(numberFrom, {
          scale: .92,
          yPercent: direction > 0 ? 10 : -10,
          rotation: -direction * profile.numberRotate,
          skewX: direction * profile.numberRotate * .22,
          filter: 'blur(18px)',
        });
    }

    timeline
      .set(codeEl, containerFrom, 0)
      .to(codeEl, {
        autoAlpha: 1,
        xPercent: 0,
        yPercent: 0,
        scale: 1,
        scaleX: 1,
        rotation: 0,
        skewX: 0,
        duration: codeInDuration,
        ease: style.id === 'pixels' ? 'steps(6)' : 'power2.out',
      }, at)
      .fromTo(numberEl, numberFrom, {
        xPercent: 0,
        yPercent: 0,
        scale: style.id === 'curtain' ? 1.045 : 1,
        rotation: 0,
        skewX: 0,
        filter: 'blur(0px)',
        duration: numberDuration,
        ease: 'numberRead66',
      }, numberAt);
  }

  /** Reveal choreography: the cover exits with the same signature it entered. */
  private buildCoverOpen(
    timeline: gsap.core.Timeline,
    style: TransitionStyle,
    profile: MotionProfile,
    stripOrder: HTMLElement[],
    direction: -1 | 1,
    openAt: number,
    openDuration: number,
    reduced: boolean,
  ): void {
    const fx = this.fxRoot;
    switch (style.id) {
      case 'blinds':
        timeline.to(stripOrder, {
          scaleY: 0,
          duration: openDuration * .74,
          stagger: reduced ? 0 : { each: openDuration * .013, from: 'center' },
          ease: 'cineCam',
        }, openAt + openDuration * .04);
        break;
      case 'iris':
        timeline
          .set(fx, { '--tf-iris-r': '0%', '--tf-iris-h': '0%' }, openAt)
          .set(this.fxLayer('iris'), { autoAlpha: 0 }, openAt)
          .set(this.fxLayer('iris-hole'), { autoAlpha: 1 }, openAt)
          .to(fx, { '--tf-iris-h': '118%', duration: openDuration * .88, ease: 'cineCam' }, openAt)
          .to(this.fxLayer('iris-edge'), {
            autoAlpha: 0, duration: openDuration * .2, ease: 'power1.in',
          }, openAt + openDuration * .7)
          .set(this.fxLayer('iris-hole'), { autoAlpha: 0 }, openAt + openDuration * .92);
        break;
      case 'crack':
        timeline
          .to(this.fxLayer('crack-seam'), {
            autoAlpha: .9, duration: openDuration * .14, ease: 'power2.out',
          }, openAt)
          .to(this.fxLayer('crack--l'), {
            xPercent: -106, rotation: -1.2, transformOrigin: '0% 50%',
            duration: openDuration * .86, ease: 'cineCam',
          }, openAt + openDuration * .06)
          .to(this.fxLayer('crack--r'), {
            xPercent: 106, rotation: 1.2, transformOrigin: '100% 50%',
            duration: openDuration * .86, ease: 'cineCam',
          }, openAt + openDuration * .06)
          .to(this.fxLayer('crack-seam'), {
            // v8：本体早让位 —— 锔缝形状由 buildLineMatch 克隆接管摆转，避免双线分叉
            autoAlpha: 0, duration: openDuration * .18, ease: 'power2.in',
          }, openAt + openDuration * .14);
        break;
      case 'ink':
        timeline
          .set(fx, { '--tf-ink-r': '0%', '--tf-ink-h': '0%' }, openAt)
          .set(this.fxLayer('ink'), { autoAlpha: 0 }, openAt)
          .set(this.fxLayer('ink-hole'), { autoAlpha: 1 }, openAt)
          .to(fx, { '--tf-ink-h': '136%', duration: openDuration * .92, ease: 'cineCam' }, openAt)
          .set(this.fxLayer('ink-hole'), { autoAlpha: 0 }, openAt + openDuration * .96);
        break;
      case 'odo':
        timeline.to(this.fxLayer('veil'), {
          autoAlpha: 0, duration: openDuration * .82, ease: 'cineCam',
        }, openAt + openDuration * .06);
        break;
      case 'slash':
        timeline.to(this.fxLayer('slash'), {
          xPercent: direction > 0 ? 118 : -118, duration: openDuration * .94, ease: 'cineCam',
        }, openAt);
        break;
      case 'pixels':
        timeline.to(this.pixelCells, {
          autoAlpha: 0,
          scale: .55,
          duration: openDuration * .38,
          stagger: reduced ? 0 : { each: (openDuration * .5) / this.pixelCells.length, from: 'random' },
          ease: 'cineCam',
        }, openAt + openDuration * .05);
        break;
      case 'rings':
        timeline.to(this.ringDiscs, {
          scale: 1.85,
          autoAlpha: 0,
          duration: openDuration * .72,
          stagger: reduced ? 0 : { each: openDuration * .05, from: 'end' },
          ease: 'cineCam',
        }, openAt + openDuration * .05);
        break;
      case 'scan':
        timeline.to(fx, {
          '--tf-scan-p': '50%', duration: openDuration * .82, ease: 'cineCam',
        }, openAt + openDuration * .06);
        break;
      default: // curtain
        timeline
          .set(stripOrder, { transformOrigin: direction > 0 ? 'top' : 'bottom' }, openAt)
          .to([...stripOrder].reverse(), {
            scaleY: 0,
            duration: openDuration * .78,
            stagger: reduced ? 0 : openDuration * profile.stripStagger,
            ease: 'cineCam',
          }, openAt);
    }
  }

  /* ----------------------------------------------------- v8 镜头语言体系 */

  /** 移动端降级路径判定（与 CSS 760px 断点一致）。 */
  private isMobileLike(): boolean {
    return window.matchMedia('(max-width: 760px)').matches;
  }

  /** 入场镜头向量：从向量来向接入（与出场同向同势 = 运动匹配）。 */
  private vectorArtFrom(vector: CameraVector, direction: -1 | 1, mobile: boolean): MotionVars {
    const pan = mobile ? .62 : 1;
    const zoom = mobile ? .7 : 1;
    return {
      xPercent: -direction * vector.panX * pan,
      yPercent: -direction * vector.panY * pan,
      rotation: direction * vector.rotate * (mobile ? .5 : 1),
      skewX: 0,
      scale: 1 + (vector.scaleFrom - 1) * zoom,
      transformOrigin: direction > 0 ? '42% 54%' : '58% 46%',
    };
  }

  /** 出场镜头向量：沿向量继续出离（推势延续，绝不反打）。 */
  private vectorArtOut(vector: CameraVector, direction: -1 | 1, mobile: boolean): MotionVars {
    const pan = mobile ? .62 : 1;
    const zoom = mobile ? .7 : 1;
    return {
      xPercent: direction * vector.panX * pan,
      yPercent: direction * vector.panY * pan,
      rotation: -direction * vector.rotate * (mobile ? .3 : .6),
      scale: 1 + (vector.scaleOut - 1) * zoom,
    };
  }

  /** open 段终点余势：镜头未停稳（缩放残 30%、pan 残 8%），残量交非阻塞长尾。 */
  private vectorArtSettle(vector: CameraVector, direction: -1 | 1, mobile: boolean): MotionVars {
    const pan = mobile ? .62 : 1;
    const zoom = mobile ? .7 : 1;
    return {
      xPercent: -direction * vector.panX * pan * .08,
      yPercent: -direction * vector.panY * pan * .08,
      rotation: direction * vector.rotate * (mobile ? .5 : 1) * .15,
      scale: 1 + (vector.scaleFrom - 1) * zoom * .3,
    };
  }

  /**
   * v8 非阻塞长尾：转场状态在 onComplete 已解锁，主体镜头继续以 cineCam
   * 渐近回落到 1.0（桌面 2.4–3.4s / 移动端 ≤2.5s 量级 = 慢速镜头运动）。
   * 冲突兜住：下一次 transitionPage 顶部 kill、resetScene 的 killTweensOf、
   * 以及出入场 tween 的 overwrite:'auto'。
   */
  private startCameraSettle(targets: HTMLElement[], vector: CameraVector, mobile: boolean): void {
    this.settleTail?.kill();
    this.settleTail = gsap.to(targets, {
      xPercent: 0,
      yPercent: 0,
      rotation: 0,
      scale: 1,
      duration: mobile ? Math.min(vector.settle, 2.5) : vector.settle,
      ease: 'cineCam',
      overwrite: 'auto',
      clearProps: 'xPercent,yPercent,rotation,skewX,scale,transformOrigin,filter,opacity,visibility',
      onComplete: () => { this.settleTail = null; },
    });
  }

  /** 以匹配根为基准记录元素边界盒（FLIP First；根静态无变换，视口坐标直接换算）。 */
  private matchRectOf(element: Element | null, root: HTMLElement): MatchRect | null {
    if (!element) return null;
    const rect = element.getBoundingClientRect();
    if (rect.width < 1 || rect.height < 1) return null;
    const origin = root.getBoundingClientRect();
    return { left: rect.left - origin.left, top: rect.top - origin.top, width: rect.width, height: rect.height };
  }

  /** 建共享元素层：left/top/width/height 仅初始化一次，此后只动 transform/opacity。 */
  private makeMatchLayer(root: HTMLElement, className: string, rect: MatchRect, origin: '0 0' | '50% 50%'): HTMLElement {
    const layer = document.createElement('div');
    layer.className = `tf-match ${className}`;
    root.appendChild(layer);
    gsap.set(layer, {
      left: rect.left,
      top: rect.top,
      width: rect.width,
      height: rect.height,
      autoAlpha: 0,
      transformOrigin: origin,
    });
    return layer;
  }

  /**
   * v8 图形匹配/遮挡编舞。close 段在此内联；swap 帧（遮盖最充分帧 = 底层
   * 切换帧）以 .call 测量目标盒 —— 此刻版式变体与巨号文本已在 swap 回调中
   * 同步完毕 —— open 段把共享层送抵目标并溶出（遮挡物在下一幕转化为装饰）。
   * 正向/逆向皆可：目标幕元素恒定，源元素缺失时各编舞自带中性出生点。
   */
  private buildMatchClose(
    timeline: gsap.core.Timeline,
    outgoing: FlatNode,
    target: FlatNode,
    closeDuration: number,
    numberDuration: number,
    openAt: number,
    openDuration: number,
  ): void {
    const outgoingScene = this.scenes[outgoing.sceneIndex];
    const incomingScene = this.scenes[target.sceneIndex];
    this.buildGiantMatch(timeline, outgoingScene, incomingScene, closeDuration, numberDuration, openAt, openDuration);
    const spec = GRAPHIC_MATCHES[target.sceneIndex];
    if (!spec) return;
    switch (spec.kind) {
      case 'line':
        this.buildLineMatch(timeline, incomingScene, spec, closeDuration, openAt, openDuration);
        break;
      case 'medal':
        this.buildMedalMatch(timeline, outgoingScene, incomingScene, spec, closeDuration, openAt, openDuration);
        break;
      case 'disc':
        this.buildDiscMatch(timeline, incomingScene, spec, closeDuration, openAt, openDuration);
        break;
      case 'frame':
        this.buildFrameMatch(timeline, outgoingScene, incomingScene, spec, closeDuration, openAt, openDuration);
        break;
    }
  }

  /** 基座匹配（全幕间）：巨号年代字同位置形变 —— 提出遮盖层、swap 帧换字、open 段 FLIP 落回溶出。 */
  private buildGiantMatch(
    timeline: gsap.core.Timeline,
    outgoingScene: HTMLElement,
    incomingScene: HTMLElement,
    closeDuration: number,
    numberDuration: number,
    openAt: number,
    openDuration: number,
  ): void {
    const source = outgoingScene.querySelector<HTMLElement>('.scene__giant span');
    const rect = this.matchRectOf(source, this.matchRootHigh);
    if (!source || !rect) return;
    const layer = this.makeMatchLayer(this.matchRootHigh, 'tf-match--giant', rect, '0 0');
    const computed = window.getComputedStyle(source);
    const outSpan = document.createElement('span');
    outSpan.textContent = source.textContent;
    const inSpan = document.createElement('span');
    layer.append(outSpan, inSpan);
    gsap.set([outSpan, inSpan], {
      fontFamily: computed.fontFamily,
      fontSize: computed.fontSize,
      fontWeight: computed.fontWeight,
      letterSpacing: computed.letterSpacing,
      lineHeight: computed.lineHeight,
    });
    gsap.set(inSpan, { autoAlpha: 0 });
    // close：随遮盖升起淡入 —— 巨号被“提”到遮盖之上，镜头参照不丢
    timeline.to(layer, { autoAlpha: .5, duration: closeDuration * .9, ease: 'cineCam' }, 0);
    timeline.call(() => {
      const targetSpan = incomingScene.querySelector<HTMLElement>('.scene__giant span');
      const targetRect = this.matchRectOf(targetSpan, this.matchRootHigh);
      if (!targetSpan || !targetRect) {
        gsap.set(layer, { autoAlpha: 0 });
        return;
      }
      const nextText = targetSpan.textContent ?? '';
      if (nextText && nextText !== outSpan.textContent) {
        inSpan.textContent = nextText;
        timeline.to(outSpan, { autoAlpha: 0, duration: numberDuration * .6, ease: 'power1.inOut' }, closeDuration + numberDuration * .2)
          .to(inSpan, { autoAlpha: 1, duration: numberDuration * .6, ease: 'power1.inOut' }, closeDuration + numberDuration * .2);
      }
      // number 段压暗为 whisper，不与 z-210 编目巨号争焦
      timeline.to(layer, { autoAlpha: .3, duration: numberDuration * .5, ease: 'power1.inOut' }, closeDuration + numberDuration * .18);
      // open：FLIP 漂移至目标盒（同位置时近似静止），随后溶入真实巨号
      timeline.to(layer, {
        x: targetRect.left - rect.left,
        y: targetRect.top - rect.top,
        scaleX: targetRect.width / rect.width,
        scaleY: targetRect.height / rect.height,
        autoAlpha: .58,
        duration: openDuration * .8,
        ease: 'cineCam',
      }, openAt + openDuration * .04);
      timeline.to(layer, { autoAlpha: 0, duration: openDuration * .16, ease: 'power1.in' }, openAt + openDuration * .84);
    }, undefined, closeDuration + .001);
  }

  /** ③ crack：锔缝金线摆转 90°，落为下一幕展签的金色顶线（金线 → 边框/时间轴）。 */
  private buildLineMatch(
    timeline: gsap.core.Timeline,
    incomingScene: HTMLElement,
    spec: GraphicMatchSpec,
    closeDuration: number,
    openAt: number,
    openDuration: number,
  ): void {
    timeline.call(() => {
      const rect = this.matchRectOf(this.fxLayer('crack-seam'), this.matchRootHigh);
      const targetRect = this.matchRectOf(incomingScene.querySelector(spec.inn), this.matchRootHigh);
      if (!rect || !targetRect) return;
      const layer = this.makeMatchLayer(this.matchRootHigh, 'tf-match--line', rect, '50% 50%');
      timeline.to(layer, { autoAlpha: .9, duration: openDuration * .1, ease: 'power2.out' }, openAt);
      timeline.to(layer, {
        x: (targetRect.left + targetRect.width / 2) - (rect.left + rect.width / 2),
        y: targetRect.top - (rect.top + rect.height / 2),
        rotation: -90,
        scaleY: gsap.utils.clamp(.12, 1.6, targetRect.width / rect.height),
        duration: openDuration * .68,
        ease: 'cineCam',
      }, openAt + openDuration * .06);
      timeline.to(layer, { autoAlpha: 0, duration: openDuration * .18, ease: 'power1.in' }, openAt + openDuration * .72);
    }, undefined, closeDuration + .001);
  }

  /** ⑥ odo 遮挡转场：奖盘掠过镜头，满屏帧完成底层切换，随后收拢为产业仪表环（圆形 → 仪表盘）。 */
  private buildMedalMatch(
    timeline: gsap.core.Timeline,
    outgoingScene: HTMLElement,
    incomingScene: HTMLElement,
    spec: GraphicMatchSpec,
    closeDuration: number,
    openAt: number,
    openDuration: number,
  ): void {
    const source = spec.out ? outgoingScene.querySelector(spec.out) : null;
    let rect = this.matchRectOf(source, this.matchRootHigh);
    if (!rect) {
      // 逆向（⑦→⑥）无奖盘源：中性出生点（视口中心 34vmin）
      const origin = this.matchRootHigh.getBoundingClientRect();
      const size = Math.min(origin.width, origin.height) * .34;
      rect = { left: (origin.width - size) / 2, top: (origin.height - size) / 2, width: size, height: size };
    }
    const diameter = Math.min(rect.width, rect.height);
    const discRect: MatchRect = {
      left: rect.left + (rect.width - diameter) / 2,
      top: rect.top + (rect.height - diameter) / 2,
      width: diameter,
      height: diameter,
    };
    const layer = this.makeMatchLayer(this.matchRootHigh, 'tf-match--medal', discRect, '50% 50%');
    const rootBox = this.matchRootHigh.getBoundingClientRect();
    const coverScale = (Math.hypot(rootBox.width, rootBox.height) * 1.12) / diameter;
    // close：奖盘放大至满屏，最充分遮挡帧恰为 swapAt
    timeline.to(layer, { autoAlpha: 1, duration: closeDuration * .5, ease: 'cineCam' }, 0)
      .to(layer, { scale: coverScale, duration: closeDuration, ease: 'cineCam' }, 0);
    timeline.call(() => {
      const targetRect = this.matchRectOf(incomingScene.querySelector(spec.inn), this.matchRootHigh);
      if (!targetRect) {
        gsap.to(layer, { autoAlpha: 0, duration: openDuration * .4, ease: 'power1.in' });
        return;
      }
      // open：金环收拢为下一幕仪表盘光环（遮挡物转化为装饰）
      timeline.to(layer, {
        x: (targetRect.left + targetRect.width / 2) - (discRect.left + diameter / 2),
        y: (targetRect.top + targetRect.height / 2) - (discRect.top + diameter / 2),
        scale: (Math.min(targetRect.width, targetRect.height) * .92) / diameter,
        duration: openDuration * .72,
        ease: 'cineCam',
      }, openAt + openDuration * .05);
      timeline.to(layer, { autoAlpha: 0, duration: openDuration * .2, ease: 'power1.in' }, openAt + openDuration * .76);
    }, undefined, closeDuration + .001);
  }

  /** ⑨ rings：年轮最内一环脱轨悬留，open 段收拢为出海信号弧的光环（年轮 → 光环）。 */
  private buildDiscMatch(
    timeline: gsap.core.Timeline,
    incomingScene: HTMLElement,
    spec: GraphicMatchSpec,
    closeDuration: number,
    openAt: number,
    openDuration: number,
  ): void {
    const rootBox = this.matchRootHigh.getBoundingClientRect();
    const diameter = Math.min(rootBox.width, rootBox.height) * .3;
    const rect: MatchRect = {
      left: (rootBox.width - diameter) / 2,
      top: (rootBox.height - diameter) / 2,
      width: diameter,
      height: diameter,
    };
    const layer = this.makeMatchLayer(this.matchRootHigh, 'tf-match--disc', rect, '50% 50%');
    timeline.to(layer, { autoAlpha: .5, duration: closeDuration * .6, ease: 'cineCam' }, closeDuration * .3)
      .fromTo(layer, { scale: .3 }, { scale: 1, duration: closeDuration * .7, ease: 'cineCam' }, closeDuration * .3);
    timeline.call(() => {
      const targetRect = this.matchRectOf(incomingScene.querySelector(spec.inn), this.matchRootHigh);
      if (!targetRect) {
        gsap.to(layer, { autoAlpha: 0, duration: openDuration * .3, ease: 'power1.in' });
        return;
      }
      timeline.to(layer, {
        x: (targetRect.left + targetRect.width / 2) - (rect.left + diameter / 2),
        y: (targetRect.top + targetRect.height / 2) - (rect.top + diameter / 2),
        scale: (Math.min(targetRect.width, targetRect.height) * .8) / diameter,
        duration: openDuration * .68,
        ease: 'cineCam',
      }, openAt + openDuration * .06);
      timeline.to(layer, { autoAlpha: 0, duration: openDuration * .2, ease: 'power1.in' }, openAt + openDuration * .7);
    }, undefined, closeDuration + .001);
  }

  /** ⑩ scan 遮挡转场：展签金框扫过遮满全屏（低根，位于扫描场之下），落为下一幕窗口（展签矩形 → 窗口）。 */
  private buildFrameMatch(
    timeline: gsap.core.Timeline,
    outgoingScene: HTMLElement,
    incomingScene: HTMLElement,
    spec: GraphicMatchSpec,
    closeDuration: number,
    openAt: number,
    openDuration: number,
  ): void {
    const source = spec.out ? outgoingScene.querySelector(spec.out) : null;
    const rect = this.matchRectOf(source, this.matchRoot);
    if (!rect) return;
    const layer = this.makeMatchLayer(this.matchRoot, 'tf-match--frame', rect, '0 0');
    const rootBox = this.matchRoot.getBoundingClientRect();
    // close：金框扩张至满屏恰在 swapAt（transformOrigin 0 0：x/y 把源盒顶点送到根原点）
    timeline.to(layer, { autoAlpha: 1, duration: closeDuration * .32, ease: 'cineCam' }, 0)
      .to(layer, {
        x: -rect.left,
        y: -rect.top,
        scaleX: rootBox.width / rect.width,
        scaleY: rootBox.height / rect.height,
        duration: closeDuration,
        ease: 'cineCam',
      }, 0);
    timeline.call(() => {
      const targetRect = this.matchRectOf(incomingScene.querySelector(spec.inn), this.matchRoot);
      if (!targetRect) {
        gsap.to(layer, { autoAlpha: 0, duration: openDuration * .3, ease: 'power1.in' });
        return;
      }
      timeline.to(layer, {
        x: targetRect.left - rect.left,
        y: targetRect.top - rect.top,
        scaleX: targetRect.width / rect.width,
        scaleY: targetRect.height / rect.height,
        duration: openDuration * .7,
        ease: 'cineCam',
      }, openAt + openDuration * .04);
      timeline.to(layer, { autoAlpha: 0, duration: openDuration * .2, ease: 'power1.in' }, openAt + openDuration * .74);
    }, undefined, closeDuration + .001);
  }

  /** Back to a clean slate: no half-drawn cover may survive a killed timeline. */
  private resetTransitionFx(): void {
    const layers = selectAll<HTMLElement>('*', this.fxRoot);
    gsap.killTweensOf([this.fxRoot, ...layers, ...this.strips, this.transitionCode, this.transitionNumber]);
    this.fxRoot.classList.remove(...TRANSITION_CLASSES);
    this.stripsRoot.classList.remove(...TRANSITION_CLASSES);
    gsap.set([this.fxRoot, ...layers], { clearProps: 'all' });
    gsap.set(this.strips, { scaleY: 0, clearProps: 'transformOrigin' });
    gsap.set([this.transitionCode, this.transitionNumber], { clearProps: 'transform,filter,clipPath' });
    // v8：共享元素层清场（匹配层 tween 已随 killTweensOf 终止），并收回镜头长尾
    this.matchRoot.replaceChildren();
    this.matchRootHigh.replaceChildren();
    this.settleTail?.kill();
    this.settleTail = null;
  }

  private finishPhrase(): void {
    this.decayWheelCarry();
    if (this.desiredFlatIndex !== this.currentFlatIndex) {
      this.pumpNavigation();
    } else if (this.consumeWheelCarry()) {
      // Sustained input may continue, but only one authored phrase at a time.
      this.pumpNavigation();
    } else {
      this.experience.dataset.flow = 'settled';
      delete this.experience.dataset.desiredNode;
      this.scheduleDetail(FLAT_NODES[this.currentFlatIndex].sceneIndex);
    }
  }

  private prepareScenes(): void {
    gsap.set(this.scenes, { autoAlpha: 0, visibility: 'hidden', pointerEvents: 'none' });
    this.scenes.forEach((scene) => {
      scene.classList.remove('is-active');
      scene.setAttribute('aria-hidden', 'true');
      this.resetScene(scene);
    });
    const first = this.scenes[0];
    first.classList.add('is-active');
    first.setAttribute('aria-hidden', 'false');
    gsap.set(first, { autoAlpha: 1, visibility: 'visible', pointerEvents: 'auto', zIndex: 12 });
    gsap.set(this.strips, { scaleY: 0 });
    gsap.set(this.transitionCode, { autoAlpha: 0, visibility: 'hidden' });
    this.resetTransitionFx();
  }

  private primaryTargets(scene: HTMLElement): HTMLElement[] {
    return selectAll<HTMLElement>('[data-primary] [data-reveal]', scene);
  }

  private detailTargets(scene: HTMLElement): HTMLElement[] {
    return selectAll<HTMLElement>('[data-detail] [data-reveal]', scene);
  }

  private artTargets(scene: HTMLElement): HTMLElement[] {
    return selectAll<HTMLElement>('.scene-art-code', scene);
  }

  private resetScene(scene: HTMLElement): void {
    const targets = [...this.primaryTargets(scene), ...this.detailTargets(scene), ...this.artTargets(scene)];
    gsap.killTweensOf(targets);
    gsap.set(this.primaryTargets(scene), { autoAlpha: 0, x: 0, y: 44, rotation: 0, skewX: 0, filter: 'blur(14px)' });
    gsap.set(this.detailTargets(scene), { autoAlpha: 0, x: 0, y: 22, rotation: 0, skewX: 0, filter: 'blur(8px)' });
    gsap.set(this.artTargets(scene), {
      autoAlpha: .2,
      scale: 1.055,
      xPercent: 0,
      rotation: 0,
      skewX: 0,
      yPercent: Number(scene.dataset.visualHeight ?? 100) > 110 ? 1.2 : 0,
    });
    scene.dataset.phase = 'idle';
  }

  private swapScenes(outgoingIndex: number, incomingIndex: number): void {
    const outgoing = this.scenes[outgoingIndex];
    const incoming = this.scenes[incomingIndex];
    // A11y：记录焦点，避免切幕后焦点随隐藏场景一起丢失到 body。
    const activeElement = document.activeElement;
    outgoing.classList.remove('is-active');
    outgoing.setAttribute('aria-hidden', 'true');
    gsap.set(outgoing, { autoAlpha: 0, visibility: 'hidden', pointerEvents: 'none', zIndex: 10 });

    incoming.classList.add('is-active');
    incoming.setAttribute('aria-hidden', 'false');
    incoming.dataset.phase = 'primary';
    gsap.set(incoming, { autoAlpha: 1, visibility: 'visible', pointerEvents: 'auto', zIndex: 12 });
    this.syncSceneUI(incomingIndex, 'primary');

    if (activeElement instanceof HTMLElement && outgoing.contains(activeElement)) {
      incoming.querySelector<HTMLElement>('[data-node-button].is-active, button:not([tabindex="-1"]), input, [tabindex]:not([tabindex="-1"])')
        ?.focus({ preventScroll: true });
    }
  }

  private animatePrimary(index: number, quick: boolean, onComplete?: () => void): void {
    this.cancelSceneAnimations();
    const scene = this.scenes[index];
    const profile = profileFor(index);
    const direction: -1 | 1 = 1;
    scene.dataset.phase = 'primary';
    scene.dataset.motionProfile = profile.id;
    this.syncSceneUI(index, 'primary');
    gsap.set(this.artTargets(scene), profileArtFrom(profile, direction));
    gsap.set(this.primaryTargets(scene), profileTextFrom(profile, direction));
    this.primaryTimeline = gsap.timeline({
      onComplete: () => {
        this.primaryTimeline = null;
        onComplete?.();
      },
    })
      .to(this.artTargets(scene), {
        autoAlpha: 1,
        scale: 1,
        xPercent: 0,
        yPercent: 0,
        rotation: 0,
        skewX: 0,
        duration: this.reducedMotion ? .12 : quick ? .42 : .82,
        ease: 'pageOpen66',
        clearProps: 'xPercent,yPercent,rotation,skewX,transformOrigin',
      }, 0)
      .to(this.primaryTargets(scene), {
        autoAlpha: 1,
        x: 0,
        y: 0,
        rotation: 0,
        skewX: 0,
        filter: 'blur(0px)',
        duration: this.reducedMotion ? .12 : quick ? .44 : .78,
        stagger: this.reducedMotion ? 0 : .09,
        ease: 'reveal66',
        clearProps: 'x,y,rotation,skewX',
      }, .03);
  }

  private scheduleDetail(index: number): void {
    this.cancelAutoDetail();
    const current = FLAT_NODES[this.currentFlatIndex];
    if (!this.started || this.transitioning || current.sceneIndex !== index || this.desiredFlatIndex !== this.currentFlatIndex) return;
    const delay = this.reducedMotion ? 70 : 500;
    this.detailTimer = window.setTimeout(() => {
      this.detailTimer = null;
      const latest = FLAT_NODES[this.currentFlatIndex];
      if (this.transitioning || latest.sceneIndex !== index || this.desiredFlatIndex !== this.currentFlatIndex) return;
      this.animateDetail(index);
    }, delay);
  }

  private animateDetail(index: number): void {
    const scene = this.scenes[index];
    const profile = profileFor(index);
    const direction: -1 | 1 = 1;
    scene.dataset.phase = 'detail';
    scene.dataset.motionProfile = profile.id;
    this.syncSceneUI(index, 'detail');
    this.detailTimeline?.kill();
    const details = this.detailTargets(scene);
    gsap.set(details, profileDetailFrom(profile, direction));
    this.detailTimeline = gsap.timeline({ onComplete: () => { this.detailTimeline = null; } })
      .to(details, {
        autoAlpha: 1,
        x: 0,
        y: 0,
        rotation: 0,
        skewX: 0,
        filter: 'blur(0px)',
        duration: this.reducedMotion ? .12 : .82,
        stagger: this.reducedMotion ? 0 : .06,
        ease: 'reveal66',
        clearProps: 'x,y,rotation,skewX',
      });
  }

  private cancelAutoDetail(): void {
    if (this.detailTimer !== null) window.clearTimeout(this.detailTimer);
    this.detailTimer = null;
    this.detailTimeline?.kill();
    this.detailTimeline = null;
  }

  private cancelSceneAnimations(): void {
    this.cancelAutoDetail();
    this.primaryTimeline?.kill();
    this.primaryTimeline = null;
  }

  private setNodeVisualImmediate(node: FlatNode): void {
    const scene = this.scenes[node.sceneIndex];
    scene.dataset.node = node.key;
    selectAll<HTMLElement>('[data-node-visual]', scene).forEach((visual) => {
      const active = visual.dataset.nodeVisual === node.key;
      visual.classList.toggle('is-active', active);
      gsap.set(visual, active
        ? { autoAlpha: 1, visibility: 'visible', x: 0, y: 0, scale: 1, rotation: 0, skewX: 0, filter: 'none' }
        : { autoAlpha: 0, visibility: 'hidden', x: 0, y: 0, scale: 1, rotation: 0, skewX: 0, filter: 'none' });
    });
  }

  private applyNodeState(node: FlatNode, reason: NodeChangeReason, notify: boolean): void {
    const scene = this.scenes[node.sceneIndex];
    scene.dataset.node = node.key;
    scene.dataset.nodeIndex = String(node.localIndex + 1);
    scene.dataset.motionProfile = profileFor(node.sceneIndex).id;
    this.experience.dataset.scene = String(node.sceneIndex + 1);
    this.experience.dataset.node = node.key;
    this.experience.dataset.nodeIndex = String(node.flatIndex + 1);
    this.experience.dataset.nodeCount = String(TOTAL_NODES);

    selectAll<HTMLButtonElement>('[data-node-button]', scene).forEach((button) => {
      const active = button.dataset.nodeKey === node.key;
      button.classList.toggle('is-active', active);
      button.setAttribute('aria-selected', String(active));
      button.tabIndex = active ? 0 : -1;
    });
    const range = scene.querySelector<HTMLInputElement>('#eraRange');
    if (range) range.value = String(node.localIndex);
    if (notify) this.nodeHandlers.forEach((handler) => handler(node.sceneIndex, node.key, node.localIndex, node.flatIndex, reason));
    this.syncProgress(node);
  }

  private syncProgress(node: FlatNode): void {
    const nodeProgress = node.flatIndex / (TOTAL_NODES - 1);
    const sceneProgress = node.sceneIndex / (CHAPTERS.length - 1);
    this.ambient.setProgress(nodeProgress);
    gsap.to(this.railProgress, {
      scaleY: sceneProgress,
      duration: this.reducedMotion ? .08 : .48,
      ease: 'power2.out',
      overwrite: true,
    });
  }

  private syncSceneUI(index: number, phase: ScenePhase): void {
    this.experience.dataset.scene = String(index + 1);
    this.experience.dataset.phase = phase;
    this.stateHandler?.(index, phase);
  }

  private normalizeWheelDelta(delta: number, mode: number): number {
    if (mode === WheelEvent.DOM_DELTA_LINE) return Math.abs(delta) * 24;
    if (mode === WheelEvent.DOM_DELTA_PAGE) return Math.abs(delta) * window.innerHeight;
    return Math.abs(delta);
  }

  private isTouchEvent(event: Event): boolean {
    if (event.type.startsWith('touch')) return true;
    return 'pointerType' in event && (event as PointerEvent).pointerType === 'touch';
  }

  private canNavigate(): boolean {
    return this.started
      && !this.destroyed
      && !document.body.classList.contains('is-loading')
      && !document.body.classList.contains('menu-open')
      && !document.body.classList.contains('sources-open');
  }

  /** Menu/rail navigation lands on the first node of a chapter. */
  goTo(sceneIndex: number): void {
    const targetScene = clampScene(Math.round(sceneIndex));
    const targetFlat = FLAT_NODES.find((node) => node.sceneIndex === targetScene)?.flatIndex ?? 0;
    this.goToFlat(targetFlat);
  }

  goToNode(sceneIndex: number, nodeKey: string): void {
    const target = FLAT_NODES.find((node) => node.sceneIndex === sceneIndex && node.key === nodeKey);
    if (!target) return;
    this.pendingReason = 'control';
    this.goToFlat(target.flatIndex);
  }

  goToFlat(index: number, instant = false): void {
    const target = clampFlat(Math.round(index));
    if (instant) {
      this.jumpImmediately(target, 'qa');
      return;
    }
    if (target === this.desiredFlatIndex && target === this.currentFlatIndex) return;
    this.desiredFlatIndex = target;
    this.pendingReason = this.pendingReason === 'control' ? 'control' : 'keyboard';
    this.directJumpRequested = Math.abs(target - this.currentFlatIndex) > 1;
    this.cancelAutoDetail();
    this.updateFlowState();
    this.accelerateActivePhrase();
    this.pumpNavigation();
  }

  private jumpImmediately(flatIndex: number, reason: NodeChangeReason): void {
    const target = FLAT_NODES[flatIndex];
    const current = FLAT_NODES[this.currentFlatIndex];
    this.pageTimeline?.kill();
    this.nodeTimeline?.kill();
    this.cancelSceneAnimations();
    this.transitioning = false;
    document.body.classList.remove('is-page-transitioning');
    gsap.set(this.strips, { scaleY: 0 });
    gsap.set(this.transitionCode, { autoAlpha: 0, visibility: 'hidden' });
    this.resetTransitionFx();
    if (current.sceneIndex !== target.sceneIndex) this.swapScenes(current.sceneIndex, target.sceneIndex);
    this.currentFlatIndex = flatIndex;
    this.desiredFlatIndex = flatIndex;
    this.setNodeVisualImmediate(target);
    this.applyNodeState(target, reason, true);
    const scene = this.scenes[target.sceneIndex];
    scene.dataset.phase = 'detail';
    gsap.set(this.artTargets(scene), { autoAlpha: 1, scale: 1, xPercent: 0, yPercent: 0, rotation: 0, skewX: 0, filter: 'none' });
    gsap.set([...this.primaryTargets(scene), ...this.detailTargets(scene)], { autoAlpha: 1, x: 0, y: 0, rotation: 0, skewX: 0, filter: 'none' });
    this.syncSceneUI(target.sceneIndex, 'detail');
    this.experience.dataset.flow = 'settled';
    delete this.experience.dataset.desiredNode;
  }

  onActiveChapter(handler: StateHandler): void {
    this.stateHandler = handler;
    const node = FLAT_NODES[this.currentFlatIndex];
    const phase = this.scenes[node.sceneIndex].dataset.phase === 'detail' ? 'detail' : 'primary';
    handler(node.sceneIndex, phase);
  }

  onActiveNode(handler: NodeHandler): void {
    this.nodeHandlers.push(handler);
    const node = FLAT_NODES[this.currentFlatIndex];
    handler(node.sceneIndex, node.key, node.localIndex, node.flatIndex, 'initial');
  }

  setReducedMotion(reduced: boolean): void {
    this.reducedMotion = reduced;
    this.ambient.setReducedMotion(reduced);
    this.experience.dataset.reducedMotion = String(reduced);
  }

  refresh(): void {
    const node = FLAT_NODES[this.currentFlatIndex];
    this.applyNodeState(node, 'initial', false);
    this.syncSceneUI(node.sceneIndex, this.scenes[node.sceneIndex].dataset.phase === 'detail' ? 'detail' : 'primary');
  }

  destroy(): void {
    this.destroyed = true;
    this.observer.kill();
    this.pageTimeline?.kill();
    this.nodeTimeline?.kill();
    this.primaryTimeline?.kill();
    this.detailTimeline?.kill();
    if (this.detailTimer !== null) window.clearTimeout(this.detailTimer);
    window.removeEventListener('keydown', this.handleKeydown);
    this.fxRoot.remove();
  }
}
