/**
 * cine-core / ParallaxField — v8.0 阻尼视差场
 * ------------------------------------------
 * 双源：指针（hover + fine pointer 设备）+ 叙事进度（全局节点进度
 * 作为慢速纵向漂移源）。前 / 中 / 后景三档速度 0.09 / 0.05 / 0.02，
 * lerp 阻尼 0.08（移动端 0.1），帧率无关换算：
 * k = 1 - (1 - damping)^(dt·60)。
 *
 * 视差只写进直播幕 rig 的 CSS 变量（--pf-bg-* / --pf-mid-* / --pf-fg-*），
 * 由 .cine-depth 三层消费；正文 .scene__inner、顶栏、rail 零视差。
 * （main.ts 既有的指针编排有它自己的展签/巨字/文本微移，本系统
 * 不接管也不冲突——嵌套 transform 自然叠加。）
 *
 * 移动端：不挂指针源，叙事漂移幅度减半；reduced-motion：全部归零静止。
 */

import type { CineEnvironment, CineSceneRig } from './CameraDirector';

/** 三档速度（后 / 中 / 前）。 */
const TIER_SPEED = { bg: 0.02, mid: 0.05, fg: 0.09 } as const;
type Tier = keyof typeof TIER_SPEED;

/** 桌面端主幅度（px）：指针横轴 / 指针纵轴 / 叙事纵轴。 */
const POINTER_MASTER_X = 560;
const POINTER_MASTER_Y = 336;
const SCROLL_MASTER_Y = 240;

interface Channel {
  x: number;
  y: number;
}

const zeroChannel = (): Channel => ({ x: 0, y: 0 });

export class ParallaxField {
  private readonly rigs: CineSceneRig[];
  private env: CineEnvironment;
  private liveScene = -1;
  private readonly current: Record<Tier, Channel> = { bg: zeroChannel(), mid: zeroChannel(), fg: zeroChannel() };
  private readonly target: Record<Tier, Channel> = { bg: zeroChannel(), mid: zeroChannel(), fg: zeroChannel() };
  private pointer = { x: 0, y: 0 }; // -1..1
  private scroll = 0;               // -1..1（全局叙事进度映射）
  private readonly hasPointer: boolean;
  private settled = true;

  private readonly handlePointerMove = (event: PointerEvent): void => {
    this.pointer = {
      x: (event.clientX / window.innerWidth) * 2 - 1,
      y: (event.clientY / window.innerHeight) * 2 - 1,
    };
    this.settled = false;
  };

  constructor(rigs: CineSceneRig[], env: CineEnvironment) {
    this.rigs = rigs;
    this.env = env;
    this.hasPointer = !env.mobile
      && typeof window !== 'undefined'
      && window.matchMedia('(hover: hover) and (pointer: fine)').matches;
    if (this.hasPointer) {
      window.addEventListener('pointermove', this.handlePointerMove, { passive: true });
    }
  }

  /** 全局叙事进度 0..1 → -1..1 的慢速纵向漂移。 */
  setScrollProgress(progress: number): void {
    const clamped = Math.min(1, Math.max(0, progress));
    const next = clamped * 2 - 1;
    if (next === this.scroll) return;
    this.scroll = next;
    this.settled = false;
  }

  setActiveScene(scene: number): void {
    const previous = this.rigs[this.liveScene];
    if (previous && this.liveScene !== scene) this.writeVars(previous, true);
    this.liveScene = scene;
    // 视差通道值不清零：跨幕保持连续，新幕从当前视差姿态接棒。
    this.settled = false;
  }

  private computeTargets(): void {
    const mobileScale = this.env.mobile ? 0.5 : 1;
    const px = this.hasPointer && !this.env.reducedMotion ? this.pointer.x : 0;
    const py = this.hasPointer && !this.env.reducedMotion ? this.pointer.y : 0;
    const sy = this.env.reducedMotion ? 0 : this.scroll;
    (Object.keys(TIER_SPEED) as Tier[]).forEach((tier) => {
      const speed = TIER_SPEED[tier];
      this.target[tier] = {
        x: px * speed * POINTER_MASTER_X * mobileScale,
        y: (py * speed * POINTER_MASTER_Y + sy * speed * SCROLL_MASTER_Y * mobileScale),
      };
    });
  }

  private writeVars(rig: CineSceneRig, forceZero = false): void {
    const channels = forceZero
      ? { bg: zeroChannel(), mid: zeroChannel(), fg: zeroChannel() }
      : this.current;
    rig.rig.style.setProperty('--pf-bg-x', `${channels.bg.x.toFixed(2)}px`);
    rig.rig.style.setProperty('--pf-bg-y', `${channels.bg.y.toFixed(2)}px`);
    rig.rig.style.setProperty('--pf-mid-x', `${channels.mid.x.toFixed(2)}px`);
    rig.rig.style.setProperty('--pf-mid-y', `${channels.mid.y.toFixed(2)}px`);
    rig.rig.style.setProperty('--pf-fg-x', `${channels.fg.x.toFixed(2)}px`);
    rig.rig.style.setProperty('--pf-fg-y', `${channels.fg.y.toFixed(2)}px`);
  }

  setReducedMotion(reduced: boolean): void {
    this.env = { ...this.env, reducedMotion: reduced };
    if (reduced) {
      (Object.keys(TIER_SPEED) as Tier[]).forEach((tier) => {
        this.current[tier] = zeroChannel();
        this.target[tier] = zeroChannel();
      });
      this.rigs.forEach((rig) => this.writeVars(rig, true));
      this.settled = true;
      return;
    }
    this.settled = false;
  }

  /** 共享 ticker 驱动（index.ts 挂 gsap.ticker）。dt 单位秒。 */
  update(dt: number): void {
    if (this.env.reducedMotion || this.settled) return;
    this.computeTargets();
    const damping = this.env.mobile ? 0.1 : 0.08;
    const k = 1 - Math.pow(1 - damping, dt * 60);
    let maxDelta = 0;
    (Object.keys(TIER_SPEED) as Tier[]).forEach((tier) => {
      const channel = this.current[tier];
      const goal = this.target[tier];
      channel.x += (goal.x - channel.x) * k;
      channel.y += (goal.y - channel.y) * k;
      maxDelta = Math.max(maxDelta, Math.abs(goal.x - channel.x), Math.abs(goal.y - channel.y));
    });
    const rig = this.rigs[this.liveScene];
    if (rig) this.writeVars(rig);
    if (maxDelta < 0.05) {
      (Object.keys(TIER_SPEED) as Tier[]).forEach((tier) => {
        this.current[tier] = { ...this.target[tier] };
      });
      if (rig) this.writeVars(rig);
      this.settled = true;
    }
  }

  destroy(): void {
    if (this.hasPointer) window.removeEventListener('pointermove', this.handlePointerMove);
    this.rigs.forEach((rig) => this.writeVars(rig, true));
    this.liveScene = -1;
  }
}

export { TIER_SPEED };
