/* ============================================================================
   kinetic.ts — v8.0 电影化动态文字（kinetic type）
   ----------------------------------------------------------------------------
   十幕十种专属标题入场 + 数字/年份快速替换过冲。
   · 全部运动统一电影缓动 CustomEase 'ktCine' = cubic-bezier(.2,.6,0,1)；
     数字过冲 'ktSnap' = cubic-bezier(.25,1.32,.35,1)（轻微过冲）。
   · 只在 kinetic 自建的内层包裹元素上动效；motion.ts 直接补间的
     [data-reveal] 容器一律不碰（hero-years 例外：仅 clip-path，不写 opacity/
     transform，避免与 motion 的 reveal 冲突）。
   · 正文（p / copy / thesis）永不动画；reduced-motion / ?qa 一律瞬时呈现。
   · RAF 统一：全部走 GSAP ticker，无独立 requestAnimationFrame。
   对外接口（供主代理接线）：
     initKinetic(): void
     onNodeChange(scene: number, localIndex: number): void
   ========================================================================== */

import gsap from 'gsap';
import { CustomEase } from 'gsap/CustomEase';
import './style-kinetic.css';

gsap.registerPlugin(CustomEase);
CustomEase.create('ktCine', '.2,.6,0,1');
CustomEase.create('ktSnap', '.25,1.32,.35,1');

type Technique =
  | 'mask'         // ① 遮罩切入 clip-path inset
  | 'tracking'     // ② 字距收束 .35em→.06em
  | 'chars'        // ③ 字符错位归位 translateY ±12→0 stagger
  | 'slices'       // ④ 水平切片拼合
  | 'stroke'       // ⑤ 轮廓描边转实心
  | 'blur'         // ⑥ 模糊到清晰
  | 'perspective'  // ⑦ 透视推近入焦 rotateX 8°→0
  | 'sweep'        // ⑧ 金色光扫过字面
  | 'sync'         // ⑨ 与背景巨号同步滑动
  | 'lines';       // ⑩ 逐行升起的语义块

interface SceneSpec {
  technique: Technique;
  /** 主标题元素（scene 内选择器）；多目标技术（mask/lines）用 blocks */
  title: string | null;
  /** 主显示数字/年份：入场 quiet-rise、幕内切换 180ms 轻微过冲 */
  figure: string | null;
  /** 次要语义行（kicker 等），统一 quiet-rise */
  quiet: string[];
  /** mask / lines 的多目标选择器 */
  blocks: string[];
}

/* 十幕分配表（与报告一致）：
   01 序章 mask · 02 制度 tracking · 03 冠军 chars · 04 联赛 slices ·
   05 亚运 stroke · 06 产业 blur · 07 城市 perspective · 08 职业 sweep ·
   09 出海 sync · 10 未来 lines */
const SCENE_SPECS: SceneSpec[] = [
  { technique: 'mask', title: null, figure: null, quiet: [], blocks: ['.hero-title > span', '.hero-title > em', '.hero-years'] },
  { technique: 'tracking', title: '#policyTitle', figure: '#policyYear', quiet: ['#policyKicker'], blocks: [] },
  { technique: 'chars', title: '#honorTitle', figure: '#honorYear', quiet: ['#honorMark'], blocks: [] },
  { technique: 'slices', title: '.memory-scoreboard-v66 > div:first-child > span', figure: null, quiet: ['#memoryTitle', '#memoryPlace'], blocks: [] },
  { technique: 'stroke', title: '#gamesLabel', figure: '#gamesYear', quiet: ['#gamesStatus'], blocks: [] },
  { technique: 'blur', title: '#metricLabel', figure: '#metricValue', quiet: [], blocks: [] },
  { technique: 'perspective', title: '#cityName', figure: '#cityValue', quiet: ['#cityKicker'], blocks: [] },
  { technique: 'sweep', title: '#roleTitle', figure: '#roleIndex', quiet: ['#roleEnglish'], blocks: [] },
  { technique: 'sync', title: '#reachTitle', figure: '#reachValue', quiet: ['#reachKicker'], blocks: [] },
  { technique: 'lines', title: null, figure: null, quiet: [], blocks: ['#futureIndex', '.future-answer-v66 small', '#futureTitle', '.future-stats-v66 > span'] },
];

/** 入场时长 .7–1.4s（电影缓动）；幕内节点切换统一 ×.55 快放。 */
const ENTRANCE_DUR: Record<Technique, number> = {
  mask: 1.05, tracking: 1.15, chars: 1, slices: .9, stroke: 1.2,
  blur: 1.1, perspective: 1.15, sweep: 1.2, sync: 1.2, lines: .8,
};
/** stagger 上限 .05s（硬约束）。 */
const STAGGER: Record<Technique, number> = {
  mask: .05, tracking: 0, chars: .032, slices: .05, stroke: 0,
  blur: 0, perspective: 0, sweep: 0, sync: 0, lines: .05,
};
/** 移动端仅保留 5 种低耗方案：mask / chars / blur / sync / lines；其余降级为 mask。 */
const MOBILE_OK = new Set<Technique>(['mask', 'chars', 'blur', 'sync', 'lines']);

const CLIP_HIDDEN = 'inset(-14% -4% 104% -4%)';
const CLIP_OPEN = 'inset(-14% -4% -12% -4%)';

let armed = false;
let lastScene = -1;
let activeTl: gsap.core.Timeline | null = null;
let pendingInitial: { scene: number; localIndex: number } | null = null;
let bootObserver: MutationObserver | null = null;
let motionObserver: MutationObserver | null = null;
const giantCache = new Map<number, string>();
const qaMode = new URLSearchParams(window.location.search).has('qa');

const isReduced = (): boolean => document.documentElement.classList.contains('reduced-motion');
const isMobile = (): boolean => window.matchMedia('(max-width: 760px), (pointer: coarse)').matches;
const isBooting = (): boolean => document.body.classList.contains('is-loading');

const markKt = (el: HTMLElement): void => { el.setAttribute('data-kt', '1'); };

/** 确定性 PRNG（mulberry32）：字符错位偏移可复现，QA 截图稳定。 */
const mulberry32 = (seed: number): (() => number) => {
  let state = seed >>> 0;
  return () => {
    state = (state + 0x6D2B79F5) >>> 0;
    let t = state;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
};

/** 把 host 的子内容收进一个内层 span（重复调用时先解包旧结构，不嵌套累积）。 */
const wrapInner = (el: HTMLElement, className: string): HTMLElement => {
  el.querySelectorAll(':scope > .kt-fx').forEach((node) => node.remove());
  el.querySelectorAll(':scope > .kt-base').forEach((base) => {
    while (base.firstChild) el.insertBefore(base.firstChild, base);
    base.remove();
  });
  const span = document.createElement('span');
  span.className = className;
  while (el.firstChild) span.appendChild(el.firstChild);
  el.appendChild(span);
  return span;
};

/** 克隆层剥 id：fx 副本绝不重复占用 #id（main.ts 按 id 换文案）。 */
const stripIds = (root: HTMLElement): void => {
  root.removeAttribute('id');
  root.querySelectorAll('[id]').forEach((node) => node.removeAttribute('id'));
};

const makeFxCopy = (host: HTMLElement, copyClass: string): { base: HTMLElement; fx: HTMLElement; copy: HTMLElement } => {
  host.classList.add('kt-host');
  markKt(host);
  const base = wrapInner(host, 'kt-base');
  const fx = document.createElement('span');
  fx.className = 'kt-fx';
  fx.setAttribute('aria-hidden', 'true');
  const copy = base.cloneNode(true) as HTMLElement;
  stripIds(copy);
  copy.classList.add(copyClass);
  fx.appendChild(copy);
  host.appendChild(fx);
  return { base, fx, copy };
};

/* ------------------------------------------------------------- 十种技术 */

/** ① 遮罩切入：clip-path inset 自上而下揭开 + 轻微上升。 */
const addMask = (tl: gsap.core.Timeline, targets: HTMLElement[], at: number, dur: number, stag: number): void => {
  targets.forEach((el, index) => {
    markKt(el);
    const pos = at + index * stag;
    // data-reveal 元素（.hero-years）由 motion 负责 opacity/transform，kinetic 只补 clip。
    if (el.hasAttribute('data-reveal')) {
      tl.fromTo(el, { clipPath: CLIP_HIDDEN }, { clipPath: CLIP_OPEN, duration: dur, ease: 'ktCine' }, pos);
    } else {
      tl.fromTo(el,
        { clipPath: CLIP_HIDDEN, yPercent: 16, opacity: 0 },
        { clipPath: CLIP_OPEN, yPercent: 0, opacity: 1, duration: dur, ease: 'ktCine' }, pos);
    }
  });
};

/** ② 字距收束：.35em → .06em（任务指定值；inline 终值保留，无回跳）。 */
const addTracking = (tl: gsap.core.Timeline, el: HTMLElement, at: number, dur: number, fast: boolean): void => {
  markKt(el);
  tl.fromTo(el,
    { letterSpacing: fast ? '.18em' : '.35em', opacity: 0, y: 8 },
    { letterSpacing: '.06em', opacity: 1, y: 0, duration: dur, ease: 'ktCine' }, at);
};

/** ③ 字符错位归位：逐字 translateY 随机 ±12px → 0，stagger ≤ .05。 */
const splitChars = (el: HTMLElement): HTMLElement[] => {
  const text = el.textContent ?? '';
  el.textContent = '';
  el.setAttribute('aria-label', text);
  const holder = document.createElement('span');
  holder.className = 'kt-chars';
  holder.setAttribute('aria-hidden', 'true');
  const chars: HTMLElement[] = [];
  for (const ch of text) {
    const span = document.createElement('span');
    span.className = 'kt-ch';
    span.textContent = ch === ' ' ? ' ' : ch;
    holder.appendChild(span);
    chars.push(span);
  }
  el.appendChild(holder);
  return chars;
};

const addChars = (tl: gsap.core.Timeline, el: HTMLElement, at: number, dur: number, stag: number, seed: number): void => {
  const chars = splitChars(el);
  const rand = mulberry32(seed);
  const offsets = chars.map(() => (rand() * 2 - 1) * 12);
  tl.fromTo(chars,
    { y: (index: number) => offsets[index], opacity: 0 },
    { y: 0, opacity: 1, duration: dur, stagger: stag, ease: 'ktCine', clearProps: 'transform,opacity' }, at);
};

/** ④ 水平切片拼合：三段横带 x 错位 → 归位（记分牌横排结构）。 */
const addSlices = (tl: gsap.core.Timeline, host: HTMLElement, at: number, dur: number, stag: number): void => {
  host.classList.add('kt-host', 'kt-host--slices');
  markKt(host);
  const base = wrapInner(host, 'kt-base');
  const fx = document.createElement('span');
  fx.className = 'kt-fx';
  fx.setAttribute('aria-hidden', 'true');
  const bands: [string, string][] = [['-2%', '66.4%'], ['33.2%', '33.2%'], ['66.4%', '-2%']];
  const offsets = [-16, 13, -9];
  const slices: HTMLElement[] = [];
  bands.forEach(([top, bottom]) => {
    const slice = base.cloneNode(true) as HTMLElement;
    stripIds(slice);
    slice.classList.add('kt-slice');
    slice.style.clipPath = `inset(${top} -3% ${bottom} -3%)`;
    fx.appendChild(slice);
    slices.push(slice);
  });
  host.appendChild(fx);
  tl.set(base, { opacity: 0 }, at)
    .fromTo(slices,
      { x: (index: number) => offsets[index], opacity: 0 },
      { x: 0, opacity: 1, duration: dur, stagger: stag, ease: 'ktCine' }, at)
    .add(() => { fx.remove(); base.style.opacity = ''; }, at + dur + stag * 2 + .05);
};

/** ⑤ 轮廓描边转实心：描边副本显形 → 实心浮显 → 描边退场。 */
const addStroke = (tl: gsap.core.Timeline, host: HTMLElement, at: number, dur: number): void => {
  const { base, fx, copy } = makeFxCopy(host, 'kt-stroke-copy');
  tl.set(base, { opacity: 0 }, at)
    .fromTo(copy, { opacity: 0, scale: 1.018 }, { opacity: 1, scale: 1, duration: dur * .4, ease: 'ktCine' }, at)
    .to(base, { opacity: 1, duration: dur * .5, ease: 'ktCine' }, at + dur * .36)
    .to(copy, { opacity: 0, duration: dur * .42, ease: 'ktCine' }, at + dur * .58)
    .add(() => { fx.remove(); base.style.opacity = ''; }, at + dur + .08);
};

/** ⑥ 模糊到清晰：blur(14px) → 0 + 轻微上升。 */
const addBlur = (tl: gsap.core.Timeline, el: HTMLElement, at: number, dur: number): void => {
  markKt(el);
  tl.fromTo(el,
    { opacity: 0, y: 8, filter: 'blur(14px)' },
    { opacity: 1, y: 0, filter: 'blur(0px)', duration: dur, ease: 'ktCine' }, at);
};

/** ⑦ 透视推近入焦：父级 perspective 900px，rotateX 8°→0 + 焦点 blur。 */
const ensureLens = (el: HTMLElement): void => {
  if (el.parentElement instanceof HTMLElement && el.parentElement.classList.contains('kt-lens')) return;
  const lens = document.createElement('div');
  lens.className = 'kt-lens';
  el.parentNode?.insertBefore(lens, el);
  lens.appendChild(el);
};

const addPerspective = (tl: gsap.core.Timeline, el: HTMLElement, at: number, dur: number): void => {
  ensureLens(el);
  markKt(el);
  tl.fromTo(el,
    { opacity: 0, y: 16, rotationX: 8, transformOrigin: '50% 100%', filter: 'blur(5px)' },
    { opacity: 1, y: 0, rotationX: 0, filter: 'blur(0px)', duration: dur, ease: 'ktCine' }, at);
};

/** ⑧ 金色光扫过字面：高光副本 clip 横扫 → 淡出，字面回落纸金。 */
const addSweep = (tl: gsap.core.Timeline, host: HTMLElement, at: number, dur: number): void => {
  const { base, fx, copy } = makeFxCopy(host, 'kt-sweep-copy');
  tl.fromTo(base, { opacity: 0 }, { opacity: 1, duration: dur * .36, ease: 'ktCine' }, at)
    .fromTo(copy,
      { clipPath: 'inset(-14% 104% -14% -4%)' },
      { clipPath: 'inset(-14% -4% -14% -4%)', duration: dur * .68, ease: 'ktCine' }, at + dur * .16)
    .to(copy, { opacity: 0, duration: dur * .3, ease: 'power1.out' }, at + dur * .74)
    .add(() => { fx.remove(); base.style.opacity = ''; }, at + dur + .08);
};

/** ⑨ 与背景巨号同步滑动：标题与 .scene__giant 同向同缓动滑入（巨号稍长＝阻尼回响）。 */
const addSync = (tl: gsap.core.Timeline, el: HTMLElement, giantBox: HTMLElement | null, at: number, dur: number): void => {
  markKt(el);
  tl.fromTo(el, { x: -34, opacity: 0 }, { x: 0, opacity: 1, duration: dur, ease: 'ktCine' }, at);
  if (giantBox) {
    markKt(giantBox);
    tl.fromTo(giantBox, { x: -34 }, { x: 0, duration: dur * 1.12, ease: 'ktCine' }, at);
  }
};

/** ⑩ 逐行升起的语义块：序号 → kicker → 标题 → 数据行，依次升起。 */
const addLines = (tl: gsap.core.Timeline, blocks: HTMLElement[], at: number, dur: number, stag: number): void => {
  blocks.forEach(markKt);
  tl.fromTo(blocks,
    { y: 16, opacity: 0 },
    { y: 0, opacity: 1, duration: dur, stagger: stag, ease: 'ktCine' }, at);
};

/* ------------------------------------------------------------- 清理 */

/** 终止进行中的 kinetic 时间线并还原一切 kinetic 内联痕迹（全场景扫描，代价极小）。 */
const cleanupAll = (): void => {
  activeTl?.kill();
  activeTl = null;
  document.querySelectorAll('.kt-fx').forEach((node) => node.remove());
  document.querySelectorAll<HTMLElement>('.kt-base').forEach((node) => { node.style.opacity = ''; });
  document.querySelectorAll<HTMLElement>('.kt-ch').forEach((node) => gsap.set(node, { clearProps: 'all' }));
  document.querySelectorAll<HTMLElement>('[data-kt]').forEach((node) => {
    gsap.killTweensOf(node);
    gsap.set(node, { clearProps: 'all' });
    node.removeAttribute('data-kt');
    node.classList.remove('kt-host', 'kt-host--slices');
  });
};

/* ------------------------------------------------------------- 主流程 */

const playScene = (sceneEl: HTMLElement, scene: number, localIndex: number, entrance: boolean, at: number): void => {
  cleanupAll();
  const spec = SCENE_SPECS[scene];
  if (!spec) return;

  const mobile = isMobile();
  const technique: Technique = mobile && !MOBILE_OK.has(spec.technique) ? 'mask' : spec.technique;
  const dur = ENTRANCE_DUR[technique] * (entrance ? 1 : .55);
  const stag = Math.min(.05, STAGGER[technique] * (entrance ? 1 : .6));
  const seed = scene * 131 + localIndex * 17 + 7;

  const pick = (selector: string): HTMLElement | null => sceneEl.querySelector<HTMLElement>(selector);
  const pickAll = (selectors: string[]): HTMLElement[] =>
    selectors.flatMap((selector) => Array.from(sceneEl.querySelectorAll<HTMLElement>(selector)));
  const pickOne = (selector: string | null): HTMLElement[] => {
    if (!selector) return [];
    const el = pick(selector);
    return el ? [el] : [];
  };

  const tl = gsap.timeline();
  activeTl = tl;

  switch (technique) {
    case 'mask':
      addMask(tl, scene === 0 ? pickAll(spec.blocks) : pickOne(spec.title), at, dur, stag);
      break;
    case 'tracking':
      pickOne(spec.title).forEach((el) => addTracking(tl, el, at, dur, !entrance));
      break;
    case 'chars':
      pickOne(spec.title).forEach((el) => addChars(tl, el, at, dur, stag, seed));
      break;
    case 'slices':
      pickOne(spec.title).forEach((el) => addSlices(tl, el, at, dur, stag));
      break;
    case 'stroke':
      pickOne(spec.title).forEach((el) => addStroke(tl, el, at, dur));
      break;
    case 'blur':
      pickOne(spec.title).forEach((el) => addBlur(tl, el, at, dur));
      break;
    case 'perspective':
      pickOne(spec.title).forEach((el) => addPerspective(tl, el, at, dur));
      break;
    case 'sweep':
      pickOne(spec.title).forEach((el) => addSweep(tl, el, at, dur));
      break;
    case 'sync':
      pickOne(spec.title).forEach((el) => addSync(tl, el, entrance ? pick('.scene__giant') : null, at, dur));
      break;
    case 'lines':
      addLines(tl, pickAll(spec.blocks), at, dur, stag);
      break;
  }

  /* 章节 eyebrow：仅幕入场，线生长 + 英文行淡入（统一微手势，不计入十种）。 */
  if (entrance) {
    const line = pick('.scene__eyebrow i');
    const english = pick('.scene__eyebrow span:last-child');
    if (line) {
      markKt(line);
      tl.fromTo(line, { scaleX: 0, transformOrigin: '0% 50%' }, { scaleX: 1, duration: .8, ease: 'ktCine' }, at + .1);
    }
    if (english) {
      markKt(english);
      tl.fromTo(english, { opacity: 0, x: 6 }, { opacity: 1, x: 0, duration: .6, ease: 'ktCine' }, at + .22);
    }
  }

  /* 主显示数字：入场 quiet-rise；幕内切换 180ms 轻微过冲（tabular-nums 沿用现有）。 */
  const figure = spec.figure ? pick(spec.figure) : null;
  if (figure) {
    markKt(figure);
    if (entrance) {
      tl.fromTo(figure, { opacity: 0, yPercent: 8 }, { opacity: 1, yPercent: 0, duration: .7, ease: 'ktCine' }, at + .08);
    } else {
      tl.fromTo(figure,
        { scale: 1.012, yPercent: -2, transformOrigin: '50% 100%' },
        { scale: 1, yPercent: 0, duration: .18, ease: 'ktSnap' }, 0);
    }
  }

  /* 次要语义行（kicker 等）：quiet-rise。 */
  const quietEls = pickAll(spec.quiet);
  if (quietEls.length) {
    quietEls.forEach(markKt);
    tl.fromTo(quietEls,
      { opacity: 0, y: 6 },
      { opacity: 1, y: 0, duration: entrance ? .55 : .4, stagger: .05, ease: 'ktCine' }, at + (entrance ? .22 : .06));
  }

  /* 场景巨号：幕内切换文本变化时 200ms 快速替换 + 轻微过冲。
     main.ts updateGiant 的 .55s 淡入在此被快照为瞬时替换（kinetic 注册在最后）。 */
  const giantBox = pick('.scene__giant');
  const giantText = giantBox?.querySelector<HTMLElement>('[data-giant]') ?? null;
  const currentGiant = giantText?.textContent ?? '';
  const previousGiant = giantCache.get(scene);
  giantCache.set(scene, currentGiant);
  if (!entrance && giantBox && giantText && previousGiant !== undefined && previousGiant !== currentGiant) {
    gsap.killTweensOf(giantText);
    gsap.set(giantText, { opacity: .58 });
    markKt(giantBox);
    tl.fromTo(giantBox,
      { scale: 1.03, yPercent: -1.4, transformOrigin: '0% 100%' },
      { scale: 1, yPercent: 0, duration: .2, ease: 'ktSnap' }, 0);
  }
};

/* ------------------------------------------------------------- 对外接口 */

/**
 * 初始化 kinetic type 系统。幂等。
 * 接线位置建议：main.ts init() 内、wireMotion 之前调用一次。
 */
export function initKinetic(): void {
  if (armed) return;
  armed = true;

  /* boot 期间收到的首个入场先挂起，body.is-loading 移除后与 motion.start() 同拍播放。 */
  if (isBooting()) {
    bootObserver = new MutationObserver(() => {
      if (isBooting()) return;
      bootObserver?.disconnect();
      bootObserver = null;
      const pending = pendingInitial;
      pendingInitial = null;
      if (!pending) return;
      /* ?qa / reduced-motion：boot 揭幕后同样保持瞬时静态。 */
      if (qaMode || isReduced()) { cleanupAll(); return; }
      const sceneEl = document.querySelector<HTMLElement>(`[data-scene="${pending.scene}"]`);
      if (sceneEl) playScene(sceneEl, pending.scene, pending.localIndex, true, .12);
    });
    bootObserver.observe(document.body, { attributes: true, attributeFilter: ['class'] });
  }

  /* reduced-motion 运行时翻转（顶栏「动态」开关）：立即静止并还原。 */
  motionObserver = new MutationObserver(() => {
    if (isReduced()) cleanupAll();
  });
  motionObserver.observe(document.documentElement, { attributes: true, attributeFilter: ['class'] });
}

/**
 * 节点切换钩子。主代理接线：
 *   motion.onActiveNode((scene, _key, localIndex) => onNodeChange(scene, localIndex));
 * 注意：注册顺序须放在既有 onActiveNode（ui.handleNode / applyNodeContent）之后，
 * 以保证 kinetic 读到的是切换后的新文案。
 * 场景变化 → 播放该幕专属入场；同场景 → 快放变体 + 数字过冲。
 */
export function onNodeChange(scene: number, localIndex: number): void {
  if (!armed) initKinetic();
  const sceneEl = document.querySelector<HTMLElement>(`[data-scene="${scene}"]`);
  if (!sceneEl || scene < 0 || scene >= SCENE_SPECS.length) return;

  if (isReduced() || qaMode) {
    cleanupAll();
    const giant = sceneEl.querySelector<HTMLElement>('[data-giant]');
    giantCache.set(scene, giant?.textContent ?? '');
    lastScene = scene;
    return;
  }

  const entrance = scene !== lastScene;
  if (isBooting()) {
    pendingInitial = { scene, localIndex };
    lastScene = scene;
    return;
  }

  /* 幕入场：页面转场 onNodeChange 触发于 swapAt（遮罩全覆盖），
     延迟 .26s 让标题随揭幕绽放；首幕 boot 揭幕用 .12s（由 observer 分支传入）。 */
  playScene(sceneEl, scene, localIndex, entrance, entrance ? .26 : 0);
  lastScene = scene;
}
