/**
 * v8.0 宏景层（scene vistas）
 * --------------------------------
 * 将 v8 AI 美术资产挂载为每幕的纵深背景：
 * - 十幕宏景 → .cine-depth--bg（由 cine-core 的镜头/视差系统统一驱动）；
 * - 序章加共享金环（.cine-depth--mid，慢旋，呼应 pushThrough 穿越叙事）；
 * - 未来幕加黑曜石碎裂前景片（.cine-depth--fg，缓慢漂移，深度构图）。
 *
 * 必须在 initCine() 之后调用（依赖 .cine-rig 深度层已存在）。
 * 图片走 srcset 自适应（960/1920 双版本），loading=lazy，不阻塞首屏。
 */

const VISTA_SLUGS: readonly string[] = [
  'act01-trophy-macro',
  'act02-archive-matrix',
  'act03-laurel-flag',
  'act04-cinema-beam',
  'act05-lotus-medal',
  'act06-orbital',
  'act07-contour-city',
  'act08-tactics-table',
  'act09-earth-arc',
  'act10-stone-gate',
];

const vistaUrl = (slug: string, width: 960 | 1920): string => `./assets/art/v8/${slug}-${width}.webp`;

const makeImg = (slug: string, className: string, eager: boolean): HTMLImageElement => {
  const img = document.createElement('img');
  img.className = className;
  img.alt = '';
  img.decoding = 'async';
  img.loading = eager ? 'eager' : 'lazy';
  img.setAttribute('aria-hidden', 'true');
  // 先 srcset/sizes 后 src：避免个别浏览器对裸 src 的投机性请求（始终 1920 档）。
  img.srcset = `${vistaUrl(slug, 960)} 960w, ${vistaUrl(slug, 1920)} 1920w`;
  img.sizes = '100vw';
  img.src = vistaUrl(slug, 1920);
  return img;
};

export function mountSceneVistas(root: ParentNode = document): void {
  // 清理-重挂：cine rig 重建（bfcache 恢复）时旧层可能随 rig 拆装而移位，
  // 统一先清再挂，保证每幕恰有一套宏景。
  root.querySelectorAll('.scene-vista, .scene-vista-ring, .scene-vista-shatter')
    .forEach((el) => el.remove());
  const scenes = Array.from(root.querySelectorAll<HTMLElement>('.scene[data-scene]'))
    .sort((a, b) => Number(a.dataset.scene) - Number(b.dataset.scene));

  scenes.forEach((scene, index) => {
    const slug = VISTA_SLUGS[index];
    if (!slug) return;
    const bg = scene.querySelector<HTMLElement>('.cine-depth--bg');
    const host = bg ?? scene; // cine rig 缺失时退化为场景直挂（仍在底层 z 序内）
    host.appendChild(makeImg(slug, 'scene-vista', index === 0));

    if (index === 0) {
      // 序章：金环驻守中景，慢旋——与首幕金器/推镜穿越形成图形呼应。
      const mid = scene.querySelector<HTMLElement>('.cine-depth--mid');
      const ring = makeImg('shared-ring', 'scene-vista-ring', true);
      ring.src = './assets/art/v8/shared-ring-1024.webp';
      ring.srcset = './assets/art/v8/shared-ring-512.webp 512w, ./assets/art/v8/shared-ring-1024.webp 1024w';
      ring.sizes = '46vw';
      (mid ?? host).appendChild(ring);
    }
    if (index === 9) {
      // 未来幕：碎裂前景片，前景遮挡构成深度三层。
      const fg = scene.querySelector<HTMLElement>('.cine-depth--fg');
      (fg ?? host).appendChild(makeImg('shared-obsidian-shatter', 'scene-vista-shatter', false));
    }
  });
}
